import asyncio
from archive_service import ArchiveService


class SidebarBroker:
    """侧边栏 SSE 推送总线:按 session_id 维护订阅队列。

    新消息钩子在企微同步的工作线程中触发,通过 call_soon_threadsafe 把事件
    安全投递到各订阅者的 asyncio 队列,再由 SSE 生成器异步下发到侧边栏。
    """

    def __init__(self) -> None:
        self._subscribers: dict[str, set[asyncio.Queue]] = {}
        self._lock = threading.Lock()
        self._loop: asyncio.AbstractEventLoop | None = None

    def bind_loop(self, loop: asyncio.AbstractEventLoop) -> None:
        self._loop = loop

    def subscribe(self, session_id: str) -> asyncio.Queue:
        queue: asyncio.Queue = asyncio.Queue(maxsize=100)
        with self._lock:
            self._subscribers.setdefault(session_id, set()).add(queue)
        return queue

    def unsubscribe(self, session_id: str, queue: asyncio.Queue) -> None:
        with self._lock:
            subs = self._subscribers.get(session_id)
            if subs:
                subs.discard(queue)
                if not subs:
                    self._subscribers.pop(session_id, None)

    def on_new_messages(self, messages: list[dict]) -> None:
        """ArchiveService 新消息钩子(在工作线程调用)。"""
        if not self._loop:
            return
        try:
            self._loop.call_soon_threadsafe(_schedule_auto_sidebar_assist_for_messages, list(messages or []))
        except Exception as exc:
            logger.warning("客户新消息自动触发调度失败: %s", exc)
        for msg in messages:
            session_id = msg.get("session_id")
            if not session_id:
                continue
            with self._lock:
                queues = list(self._subscribers.get(session_id, ()))
            if not queues:
                continue
            for queue in queues:
                self._loop.call_soon_threadsafe(self._safe_put, queue, msg)


    @staticmethod
    def _safe_put(queue: asyncio.Queue, item: dict) -> None:
        try:
            queue.put_nowait(item)
        except asyncio.QueueFull:
            # 慢消费者:丢弃最旧一条再放,保证侧边栏拿到最新消息
            try:
                queue.get_nowait()
                queue.put_nowait(item)
            except Exception:
                pass


SIDEBAR_BROKER = SidebarBroker()


@app.on_event("shutdown")
async def shutdown_event():
    stop_scheduler()


@app.on_event("startup")
async def startup_event():
    archive_status = ArchiveService.config_status()

    # SSE 推送总线:绑定主事件循环并注册新消息钩子。
    # 不受 ENABLE_ARCHIVE_POLLING 限制——无论消息由回调还是常驻 worker 拉到,
    # 只要落库就能推给订阅当前会话的侧边栏。
    SIDEBAR_BROKER.bind_loop(asyncio.get_running_loop())
    ArchiveService.register_new_message_hook(SIDEBAR_BROKER.on_new_messages)
    logger.info("侧边栏 SSE 推送总线已就绪。")

    # 加载用户自定义套装到策略注册表; 并注入惰性 DB 加载器(多进程按需同步, 避免 unsupported scenario)
    try:
        import mail_sequence_strategy as _mss
        _mss.set_dynamic_scenario_loader(_load_single_custom_suite_from_db)
        _apply_mail_scenario_label_overrides()
        _startup_db = SessionLocal()
        _load_custom_suites_into_registry(_startup_db)
        _startup_db.close()
    except Exception as _e:
        logger.warning("加载自定义套装注册失败: %s", _e)

    if not settings.ENABLE_ARCHIVE_POLLING:
        logger.info("企微会话存档自动轮询未启用；知识库后台正常启动。")
        return
    if not archive_status["ready"]:
        logger.warning("企微会话存档自动轮询已请求但配置不完整，跳过启动: %s", archive_status["missing"])
        return

    # 2026-05-27：暂停知识库评分后台守护线程(kb_evaluation_worker)。
    # 它每 60 秒扫未打分记录并调 LLM-1(qwen14b) 打分，会与线上 API 的评分抢同一端点占资源。
    # 恢复请取消下面两行注释。
    # from kb_evaluation_worker import start_kb_evaluation_thread
    # start_kb_evaluation_thread()

    # 2026-06-16: 重新启用常驻增量拉取 worker 作为主力取数链路。
    # 背景:企微单应用只能配一个接收消息 URL,该 URL 被老 C# CRM(.ashx)占用,
    # 回调(callback.py)实际未必生效;只靠回调会出现"两头落空、消息没人拉"。
    # 常驻 worker 不依赖企微回调配置,是最稳的兜底;回调若生效则作为加速补充。
    # 二者都调用同一个 sync_today_data,内部有进程锁/线程锁,并发重入安全。
    poll_interval = max(1.0, float(settings.ARCHIVE_POLL_INTERVAL_SECONDS))
    logger.info("启动企微会话存档常驻增量拉取 worker,间隔 %.1fs", poll_interval)

    async def background_poll_worker():
        consecutive_errors = 0
        while True:
            try:
                # 使用 to_thread 将底层 C-SDK 同步阻塞推到独立线程,避免卡住事件循环
                result = await asyncio.to_thread(ArchiveService.sync_today_data)
                status = result.get("status")
                if status == "success":
                    consecutive_errors = 0
                    if result.get("inserted_count"):
                        logger.info(
                            "常驻 worker 拉取新增 %s 条 (seq=%s)",
                            result.get("inserted_count"), result.get("current_seq"),
                        )
                elif status == "skipped":
                    consecutive_errors = 0  # 被回调触发的同步占用,属正常
                else:
                    consecutive_errors += 1
                    logger.warning("常驻 worker 拉取未成功: %s", result.get("msg"))
            except Exception as e:
                consecutive_errors += 1
                logger.error("常驻 worker 拉取异常: %s", e)
            # 连续失败时指数退避,最长 60s,避免在限频/网络故障时打爆腾讯接口
            sleep_seconds = poll_interval
            if consecutive_errors:
                sleep_seconds = min(60.0, poll_interval * (2 ** min(consecutive_errors, 5)))
            await asyncio.sleep(sleep_seconds)

    asyncio.create_task(background_poll_worker())


# === 30 分钟后台补算 API 调用的"原始回复分 + 相似分" ===
# 背景:实时验证详情页里这两列默认空,因为 _refresh_api_invocation_quality 只在两个时机被触发:
#   (a) 调用创建时——此时销售通常还没回复,actual_sales_replies=[],跳过原始回复分/相似分;
#   (b) 分析详情页打开时——手动行为。
# 实时验证是批量看一整天,不会逐条点开分析页,所以这两列绝大多数停留在 pending_no_sales_reply。
# 这里加一个 30 分钟周期 worker,只补算"北京 2026-05-28 00:00 之后"创建的调用;之前历史数据不动。
# 不重复算的两道防线:
#   1) SQL 层只取 quality_status IS NULL / pending_no_sales_reply / quality_similarity 缺失的;
#   2) _refresh_api_invocation_quality 内部 reply_hash 守卫:hash 未变就早 return,不调 LLM。
API_RESCORE_BACKFILL_FROM_UTC = datetime(2026, 5, 28, 0, 0, 0) - timedelta(hours=8)  # = 北京 2026-05-28 00:00
API_RESCORE_BACKFILL_INTERVAL_SECONDS = 1800   # 30 分钟
API_RESCORE_BACKFILL_BATCH_LIMIT = 50          # 单轮最多处理 50 条,防一次跑太久把事件循环空闲时间吃光

def _wecom_followup_scoring_window_status(now_utc: datetime | None = None) -> dict:
    """Return whether follow-up WeCom scoring may run in the Beijing daily window."""
    enabled = bool(getattr(settings, "WECOM_FOLLOWUP_SCORING_WINDOW_ENABLED", True))
    start_hour = int(getattr(settings, "WECOM_FOLLOWUP_SCORING_WINDOW_START_HOUR_BJ", 20))
    end_hour = int(getattr(settings, "WECOM_FOLLOWUP_SCORING_WINDOW_END_HOUR_BJ", 24))
    start_hour = max(0, min(start_hour, 24))
    end_hour = max(0, min(end_hour, 24))
    start_minute = start_hour * 60
    end_minute = end_hour * 60
    now_bj = (now_utc or datetime.utcnow()) + timedelta(hours=8)
    current_minute = now_bj.hour * 60 + now_bj.minute

    if not enabled or start_minute == end_minute:
        allowed = True
    elif start_minute < end_minute:
        allowed = start_minute <= current_minute < end_minute
    else:
        allowed = current_minute >= start_minute or current_minute < end_minute

    next_start_bj = now_bj.replace(hour=min(start_hour, 23), minute=0, second=0, microsecond=0)
    if enabled and not allowed:
        if start_minute < end_minute:
            if current_minute >= start_minute:
                next_start_bj += timedelta(days=1)
        elif not (end_minute <= current_minute < start_minute):
            next_start_bj += timedelta(days=1)
    seconds_until_start = max(60, int((next_start_bj - now_bj).total_seconds())) if enabled and not allowed else 0
    return {
        "allowed": allowed,
        "enabled": enabled,
        "beijing_time": now_bj.isoformat(timespec="seconds"),
        "window": f"{start_hour:02d}:00-{end_hour:02d}:00",
        "seconds_until_start": seconds_until_start,
    }


def _run_api_invocation_rescore_backfill() -> dict:
    """单次扫描:取 5.28 起未完成评分的调用,按 session 分组共享 _load_session_messages,逐条调 refresh。"""
    from sqlalchemy import or_, exists
    window = _wecom_followup_scoring_window_status()
    if not window["allowed"]:
        logger.info(
            "API原始/相似分后台补算跳过: 当前北京时间=%s 不在配置窗口 %s",
            window["beijing_time"],
            window["window"],
        )
        return {"scanned": 0, "refreshed": 0, "failed": 0, "skipped_by_window": True, "window": window}
    db = SessionLocal()
    scanned = 0
    refreshed = 0
    failed = 0
    try:
        # 只选取“目前已经有我方销售人员回复”的调用进入队列，确保能打分
        has_reply = exists().where(
            MessageLog.user_id == ApiAssistInvocation.session_id,
            MessageLog.sender_type == "sales",
            MessageLog.id > ApiAssistInvocation.anchor_message_id,
            MessageLog.is_mock.is_(False),
        )

        items = db.query(ApiAssistInvocation).filter(
            ApiAssistInvocation.triggered_at >= API_RESCORE_BACKFILL_FROM_UTC,
            ApiAssistInvocation.anchor_message_id.isnot(None),
            has_reply,
            or_(
                ApiAssistInvocation.quality_status.is_(None),
                ApiAssistInvocation.quality_status == "pending_no_sales_reply",
                ApiAssistInvocation.quality_similarity.is_(None),
            ),
        ).order_by(ApiAssistInvocation.triggered_at.desc()).limit(API_RESCORE_BACKFILL_BATCH_LIMIT).all()
        # 按 session 分组,一个 session 只查一次 _load_session_messages,避免 N+1。
        by_session: dict = {}
        for it in items:
            by_session.setdefault(it.session_id, []).append(it)
        for session_id, session_items in by_session.items():
            try:
                messages = _load_session_messages(db, session_id) if session_id else []
            except Exception as msg_exc:
                logger.warning("API原始/相似分补算: 加载会话消息失败 session=%s err=%s", session_id, msg_exc)
                continue
            for it in session_items:
                scanned += 1
                old_ts = it.quality_scored_at
                try:
                    _refresh_api_invocation_quality(db, it, all_messages=messages)
                    if it.quality_scored_at != old_ts:
                        refreshed += 1
                        # 每次打分刷新成功，立即 commit 释放事务行锁，然后再进行睡眠，避免持有锁睡眠
                        try:
                            db.commit()
                        except Exception as commit_exc:
                            logger.warning("API原始/相似分补算: 单条提交失败 inv=%s err=%s", it.invocation_id, commit_exc)
                            try: db.rollback()
                            except Exception: pass
                        import time
                        time.sleep(3.0)  # 给 LLM 留出喘息间隔，防过载
                    else:
                        # 若无实质变化，也即时 commit 结束该事务释放锁
                        db.commit()
                except Exception as item_exc:
                    failed += 1
                    logger.warning("API原始/相似分补算: 单条失败 inv=%s err=%s", it.invocation_id, item_exc)
                    try: db.rollback()
                    except Exception: pass
                    continue
    finally:
        db.close()
    return {"scanned": scanned, "refreshed": refreshed, "failed": failed}

async def _api_invocation_rescore_backfill_worker():
    """30 分钟周期循环;启动后立刻先跑一次,之后每 30 分钟再跑。"""
    while True:
        sleep_seconds = API_RESCORE_BACKFILL_INTERVAL_SECONDS
        try:
            stats = await asyncio.to_thread(_run_api_invocation_rescore_backfill)
            logger.info(f"API原始/相似分后台补算 一轮完成: {stats}")
            if isinstance(stats, dict) and stats.get("skipped_by_window"):
                window = stats.get("window") if isinstance(stats.get("window"), dict) else {}
                sleep_seconds = max(
                    60,
                    min(API_RESCORE_BACKFILL_INTERVAL_SECONDS, int(window.get("seconds_until_start") or API_RESCORE_BACKFILL_INTERVAL_SECONDS)),
                )
        except Exception as e:
            logger.error("API原始/相似分后台补算 异常: %s", e)
        await asyncio.sleep(sleep_seconds)

@app.on_event("startup")
async def _start_api_rescore_backfill_worker():
    logger.info("启动 API 调用原始回复分/相似分 30 分钟后台补算任务(从北京 2026-05-28 00:00 起)")
    asyncio.create_task(_api_invocation_rescore_backfill_worker())


@app.get("/cb/qywx")
async def qywx_verify(
    msg_signature: str = Query(...),
    timestamp: str = Query(...),
    nonce: str = Query(...),
    echostr: str = Query(...)
):
    """企微回调开启时的 URL 验证接口"""
    logger.info(f"收到企微验证请求")
    res = QYWXUtils.decrypt_message(msg_signature, timestamp, nonce, echostr, is_verify=True)
    return res

@app.post("/cb/qywx")
async def qywx_receive_message(
    request: Request,
    background_tasks: BackgroundTasks,
    msg_signature: str = Query(...),
    timestamp: str = Query(...),
    nonce: str = Query(...)
):
    """企微回调消息接收接口"""
    body = await request.body()
    xml_content = QYWXUtils.decrypt_message(msg_signature, timestamp, nonce, body, is_verify=False)
    if not xml_content:
        raise HTTPException(status_code=400, detail="Decrypt failed")

    try:
        root = ET.fromstring(xml_content)
        from_user = (root.findtext("FromUserName") or "").strip()
        content = (
            root.findtext("Content")
            or root.findtext("Recognition")
            or root.findtext("Title")
            or ""
        ).strip()
    except Exception as exc:
        raise HTTPException(status_code=400, detail=f"企微消息 XML 解析失败: {exc}") from exc

    if not from_user or not content:
        raise HTTPException(status_code=400, detail="企微回调缺少 FromUserName 或文本内容")

    # 1. 实时旁路扫描 (主线程)
    IntentEngine.fast_track_scan(from_user, content)

    # 2. 异步深度分析 (改用原生 BackgroundTasks 以适配 Windows)
    background_tasks.add_task(process_deep_analyze_task, from_user, content, "customer")

    return "success"

def process_deep_analyze_task(user_id, content, sender_type):
    """后台长对话分析任务"""
    db = SessionLocal()
    try:
        # 消息持久化
        log = MessageLog(user_id=user_id, content=content, sender_type=sender_type)
        db.add(log)
        db.commit()

        # 获取上下文
        context_logs = db.query(MessageLog).filter(MessageLog.user_id == user_id).order_by(MessageLog.id.desc()).limit(10).all()
        context = [{"content": l.content, "sender_type": l.sender_type} for l in reversed(context_logs)]

        # 执行 AI 分析链路
        IntentEngine.slow_track_analyze(user_id, context)
    finally:
        db.close()

# --- 知识库管理 API ---

@app.post("/api/knowledge")
async def add_knowledge(title: str, content: str, category: str = "通用"):
    embedding = IntentEngine.get_embedding(content)

    db = SessionLocal()
    try:
        new_item = KnowledgeBase(title=title, content=content, category=category, embedding=embedding)
        db.add(new_item)
        db.commit()
        return {"status": "success", "id": new_item.id}
    finally:
        db.close()

@app.get("/api/knowledge")
async def list_knowledge():
    db = SessionLocal()
    try:
        items = db.query(KnowledgeBase.id, KnowledgeBase.title, KnowledgeBase.category).all()
        return [{"id": i.id, "title": i.title, "category": i.category} for i in items]
    finally:
        db.close()

