def _redact_value(value):
    if isinstance(value, str):
        return sanitize_text(value)
    if isinstance(value, list):
        return [_redact_value(item) for item in value]
    if isinstance(value, dict):
        return {key: _redact_value(item) for key, item in value.items()}
    return value

def _hit_log_to_dict(log: KnowledgeHitLog, redact: bool = False) -> dict:
    query_text = log.query_text
    final_response = log.final_response
    manual_feedback = log.manual_feedback
    if redact:
        query_text = _redact_value(query_text)
        final_response = _redact_value(final_response)
        manual_feedback = _redact_value(manual_feedback)
    return {
        "log_id": str(log.log_id),
        "request_id": log.request_id,
        "session_id": log.session_id,
        "query_text": query_text,
        "query_features": log.query_features,
        "filters_used": log.filters_used,
        "hit_chunk_ids": log.hit_chunk_ids,
        "scores": log.scores,
        "hit_snapshot_available": bool(getattr(log, "hit_chunks_snapshot", None)),
        "hit_detail_source": "recorded_retrieval_snapshot" if getattr(log, "hit_chunks_snapshot", None) else "not_loaded",
        "hit_detail_warning": None,
        "no_hit_reason": log.no_hit_reason,
        "status": log.status,
        "retrieval_quality": log.retrieval_quality,
        "confidence_score": float(log.confidence_score) if log.confidence_score is not None else None,
        "insufficient_info": log.insufficient_info,
        "manual_review_required": log.manual_review_required,
        "final_response": final_response,
        "manual_feedback": manual_feedback,
        "feedback_status": log.feedback_status,
        "latency_ms": log.latency_ms,
        "created_at": log.created_at,
    }

def _normalize_hit_chunk_ids(hit_chunk_ids) -> list[str]:
    normalized: list[str] = []
    if not isinstance(hit_chunk_ids, list):
        return normalized
    for item in hit_chunk_ids:
        chunk_id = None
        if isinstance(item, dict):
            chunk_id = item.get("chunk_id") or item.get("id")
        else:
            chunk_id = item
        if chunk_id:
            normalized.append(str(chunk_id))
    return normalized

def _score_for_hit(scores, chunk_id: str, index: int):
    if isinstance(scores, dict):
        value = scores.get(chunk_id) or scores.get(str(index + 1)) or scores.get(index)
    elif isinstance(scores, list) and index < len(scores):
        item = scores[index]
        if isinstance(item, dict):
            value = item.get("score") or item.get("similarity") or item.get("final_score")
        else:
            value = item
    else:
        value = None
    try:
        return float(value) if value is not None else None
    except (TypeError, ValueError):
        return None

def _chunk_to_hit_dict(chunk: KnowledgeChunk, *, score=None, hit_rank: int | None = None, document: KnowledgeDocument | None = None, redact: bool = False) -> dict:
    content = chunk.content
    title = chunk.title
    if redact:
        content = _redact_value(content)
        title = _redact_value(title)
    return {
        "chunk_id": str(chunk.chunk_id),
        "document_id": str(chunk.document_id) if chunk.document_id else None,
        "document_title": document.title if document else None,
        "source_ref": document.source_ref if document else None,
        "hit_rank": hit_rank,
        "score": score,
        "title": title,
        "content": content,
        "chunk_type": chunk.chunk_type,
        "chunk_type_label": label_for("chunk_type", chunk.chunk_type),
        "knowledge_type": chunk.knowledge_type,
        "knowledge_type_label": label_for("knowledge_type", chunk.knowledge_type),
        "business_line": chunk.business_line,
        "business_line_label": label_for("business_line", chunk.business_line),
        "service_scope": chunk.service_scope,
        "service_scope_label": label_for("service_scope", chunk.service_scope),
        "status": chunk.status,
    }

def _snapshot_hit_to_dict(hit: dict, *, index: int, redact: bool = False, source: str = "recorded_retrieval_snapshot") -> dict:
    row = dict(hit or {})
    if redact:
        row["title"] = _redact_value(row.get("title"))
        row["content"] = _redact_value(row.get("content"))
    row["hit_rank"] = row.get("hit_rank") or index + 1
    row["snapshot_source"] = source
    row["snapshot_available"] = True
    row["is_original_retrieval_snapshot"] = True
    row["knowledge_type_label"] = row.get("knowledge_type_label") or label_for("knowledge_type", row.get("knowledge_type"))
    row["chunk_type_label"] = row.get("chunk_type_label") or label_for("chunk_type", row.get("chunk_type"))
    row["business_line_label"] = row.get("business_line_label") or label_for("business_line", row.get("business_line"))
    row["service_scope_label"] = row.get("service_scope_label") or label_for("service_scope", row.get("service_scope"))
    return row

def _knowledge_hits_from_payload(payload, *, expected_log_id: str | None = None) -> tuple[list[dict], dict | None]:
    if not isinstance(payload, dict):
        return [], None
    knowledge = payload.get("knowledge_v2")
    if not isinstance(knowledge, dict) and isinstance(payload.get("step4_knowledge"), dict):
        knowledge = payload["step4_knowledge"].get("knowledge_v2")
    if not isinstance(knowledge, dict):
        return [], None
    if expected_log_id:
        payload_log_id = knowledge.get("log_id") or knowledge.get("knowledge_log_id")
        if payload_log_id and str(payload_log_id) != str(expected_log_id):
            return [], None
    hits = knowledge.get("hits")
    return (hits if isinstance(hits, list) else []), knowledge

def _hit_log_chain_snapshot_hits(db: Session, log: KnowledgeHitLog) -> tuple[list[dict], str | None]:
    log_id = str(log.log_id)
    snapshot = db.query(ReplyChainSnapshot).filter(
        ReplyChainSnapshot.knowledge_log_id == log_id
    ).order_by(ReplyChainSnapshot.updated_at.desc()).first()
    hits, _knowledge = _knowledge_hits_from_payload(
        {"knowledge_v2": snapshot.knowledge_v2} if snapshot else None,
        expected_log_id=log_id,
    )
    if hits:
        return hits, "reply_chain_snapshot"

    summary = db.query(IntentSummary).filter(
        IntentSummary.knowledge_log_id == log_id
    ).order_by(IntentSummary.summarized_at.desc(), IntentSummary.id.desc()).first()
    hits, _knowledge = _knowledge_hits_from_payload(
        {"knowledge_v2": summary.knowledge_v2} if summary else None,
        expected_log_id=log_id,
    )
    if hits:
        return hits, "intent_summary_snapshot"

    inv_query = db.query(ApiAssistInvocation)
    if log.request_id:
        inv_query = inv_query.filter(ApiAssistInvocation.request_id == log.request_id)
    elif log.session_id:
        inv_query = inv_query.filter(ApiAssistInvocation.session_id == log.session_id)
    else:
        return [], None
    for inv in inv_query.order_by(ApiAssistInvocation.triggered_at.desc()).limit(80).all():
        hits, _knowledge = _knowledge_hits_from_payload(inv.result_payload, expected_log_id=log_id)
        if hits:
            return hits, "api_assist_invocation_snapshot"
    return [], None

def _hit_log_snapshot_hits(log: KnowledgeHitLog) -> list[dict]:
    snapshot = getattr(log, "hit_chunks_snapshot", None)
    if isinstance(snapshot, dict):
        hits = snapshot.get("hits")
        return hits if isinstance(hits, list) else []
    if isinstance(snapshot, list):
        return snapshot
    return []

def _hit_log_hit_chunks(db: Session, log: KnowledgeHitLog, *, redact: bool = False) -> list[dict]:
    snapshot_hits = _hit_log_snapshot_hits(log)
    if snapshot_hits:
        return [_snapshot_hit_to_dict(hit, index=index, redact=redact, source="recorded_retrieval_snapshot") for index, hit in enumerate(snapshot_hits)]

    chain_hits, chain_source = _hit_log_chain_snapshot_hits(db, log)
    if chain_hits:
        return [_snapshot_hit_to_dict(hit, index=index, redact=redact, source=chain_source or "chain_snapshot") for index, hit in enumerate(chain_hits)]

    hit_chunk_ids = _normalize_hit_chunk_ids(log.hit_chunk_ids)
    if not hit_chunk_ids:
        return []
    chunks = db.query(KnowledgeChunk).filter(KnowledgeChunk.chunk_id.in_(hit_chunk_ids)).all()
    chunk_map = {str(chunk.chunk_id): chunk for chunk in chunks}
    doc_ids = [str(chunk.document_id) for chunk in chunks if chunk.document_id]
    docs = db.query(KnowledgeDocument).filter(KnowledgeDocument.document_id.in_(doc_ids)).all() if doc_ids else []
    doc_map = {str(doc.document_id): doc for doc in docs}
    result = []
    for index, chunk_id in enumerate(hit_chunk_ids):
        chunk = chunk_map.get(chunk_id)
        if not chunk:
            result.append({
                "chunk_id": chunk_id,
                "hit_rank": index + 1,
                "missing": True,
                "snapshot_source": "current_lookup_by_recorded_id",
                "snapshot_available": False,
                "is_original_retrieval_snapshot": False,
            })
            continue
        row = _chunk_to_hit_dict(
            chunk,
            score=_score_for_hit(log.scores, chunk_id, index),
            hit_rank=index + 1,
            document=doc_map.get(str(chunk.document_id)),
            redact=redact,
        )
        row.update({
            "snapshot_source": "current_lookup_by_recorded_id",
            "snapshot_available": False,
            "is_original_retrieval_snapshot": False,
            "audit_warning": "历史日志未记录命中正文快照；这是按历史 chunk_id 查询到的当前切片内容，不保证等同当时传给后续流程的原文。",
        })
        result.append(row)
    return result
def _parse_kb_stats_datetime(value: str | None, *, end_of_day: bool = False) -> datetime | None:
    if not value:
        return None
    text_value = str(value).strip()
    try:
        if len(text_value) == 10:
            parsed = datetime.strptime(text_value, "%Y-%m-%d")
            if end_of_day:
                parsed = parsed + timedelta(days=1)
            return parsed
        return datetime.fromisoformat(text_value.replace("Z", "+00:00")).replace(tzinfo=None)
    except ValueError:
        raise HTTPException(status_code=400, detail=f"Invalid datetime: {value}")

