            r"(?:个人|私人)[^。；;\n]{0,30}(?:银行卡|银行账号|收款账号|支付宝|微信收款|账户|账号)",
            r"(?:银行卡|银行账号|收款账号|支付宝|微信收款|账户|账号)[^。；;\n]{0,30}(?:个人|私人)",
