# 用户自建套装的中文标签和步骤标签，运行时动态填充（重启后从 DB 重新加载）
_DYNAMIC_SCENARIO_CHINESE: dict[str, str] = {}
_DYNAMIC_STEP_LABELS: dict[tuple[str, int], str] = {}


def _mail_runtime_settings_path() -> str:
    import os
    return os.path.join(os.path.dirname(__file__), "runtime_llm_settings.json")


def _load_mail_scenario_label_overrides() -> dict[str, str]:
    """读取内置场景的中文名覆盖(用户对老的 3 个场景改的名字), 存在 runtime_llm_settings.json。"""
    import os, json
    path = _mail_runtime_settings_path()
    if not os.path.exists(path):
        return {}
    try:
        with open(path, "r", encoding="utf-8") as f:
            data = json.load(f)
        ov = data.get("scenario_label_overrides") if isinstance(data, dict) else None
        return {str(k): str(v) for k, v in ov.items()} if isinstance(ov, dict) else {}
    except Exception:
        return {}


def _save_mail_scenario_label_override(scenario: str, label: str) -> None:
    """持久化内置场景改名(scenario 代码不变, 仅显示名), 重启后由 _apply 重新载入。"""
    import os, json
    path = _mail_runtime_settings_path()
    data: dict[str, Any] = {}
    if os.path.exists(path):
        try:
            with open(path, "r", encoding="utf-8") as f:
                loaded = json.load(f)
            if isinstance(loaded, dict):
                data = loaded
        except Exception:
            data = {}
    ov = data.get("scenario_label_overrides")
    if not isinstance(ov, dict):
        ov = {}
    ov[scenario] = label
    data["scenario_label_overrides"] = ov
    with open(path, "w", encoding="utf-8") as f:
        json.dump(data, f, ensure_ascii=False, indent=2)


def _apply_mail_scenario_label_overrides() -> None:
    """启动时把改名覆盖应用到内置场景中文名(只覆盖已知内置场景, 不新增)。"""
    for scenario, label in _load_mail_scenario_label_overrides().items():
        if scenario in _MAIL_SCENARIO_CHINESE and str(label).strip():
            _MAIL_SCENARIO_CHINESE[scenario] = str(label).strip()


def _get_scenario_label_cn(scenario: str) -> str | None:
    """返回场景中文标签，内置场景优先，否则查用户自建。"""
    return _MAIL_SCENARIO_CHINESE.get(scenario) or _DYNAMIC_SCENARIO_CHINESE.get(scenario)


def _is_supported_scenario(scenario: str) -> bool:
    scenario = (scenario or "").strip()
    if scenario in _MAIL_SCENARIO_CHINESE or scenario in _DYNAMIC_SCENARIO_CHINESE:
        return True
    # 自建套装(custom_*): 本 worker 进程可能尚未注册, 按需从 DB 惰性加载再判定,
    # 避免"创建套装的进程注册了、当前请求落在另一进程"导致误报 unsupported scenario。
    if scenario.startswith("custom_"):
        try:
            return _load_single_custom_suite_from_db(scenario)
        except Exception:
            return False
    return False


def _is_valid_suite_step(scenario: str, suite_step: int) -> bool:
    """固定场景限 1..4; 自建套装(custom_*)允许 1..8(与编辑接口一致)。"""
    try:
        step = int(suite_step)
    except Exception:
        return False
    if (scenario or "").startswith("custom_"):
        return 1 <= step <= 8
    return step in ALL_MAIL_SEQUENCE_STEPS


def _load_custom_suites_into_registry(db) -> None:
    """启动时/创建后将自建套装注册到运行时缓存。"""
    from mail_sequence_strategy import register_dynamic_scenario
    try:
        rows = db.query(MailCustomSuite).all()
    except Exception:
        return
    for row in rows:
        _DYNAMIC_SCENARIO_CHINESE[row.scenario] = row.label_cn
        # 从 MailSequenceTemplate 加载各步骤标签
        step_labels: dict[int, str] = {}
        try:
            tmpl_rows = db.query(MailSequenceTemplate).filter(
                MailSequenceTemplate.scenario == row.scenario,
            ).all()
            for t in tmpl_rows:
                lbl = (t.step_label_cn or "").strip()
                if lbl:
                    step_labels[int(t.suite_step)] = lbl
                    _DYNAMIC_STEP_LABELS[(row.scenario, int(t.suite_step))] = lbl
        except Exception:
            pass
        register_dynamic_scenario(row.scenario, row.label_cn, row.step_count, step_labels)


def _load_single_custom_suite_from_db(scenario: str) -> bool:
    """按需把单个自建套装从 DB 注册进本进程运行时缓存。

    供 mail_sequence_strategy 的惰性加载钩子调用: 任何 worker 进程解析到没见过的 custom_* 场景时,
    直接从 DB 读取注册, 解决"创建套装的进程注册了、生成草稿的进程没注册"的多进程不同步问题。
    """
    scenario = (scenario or "").strip()
    if not scenario.startswith("custom_"):
        return False
    from mail_sequence_strategy import register_dynamic_scenario
    db = SessionLocal()
    try:
        row = db.query(MailCustomSuite).filter(MailCustomSuite.scenario == scenario).first()
        if row is None:
            return False
        step_labels: dict[int, str] = {}
        for t in db.query(MailSequenceTemplate).filter(
            MailSequenceTemplate.scenario == scenario,
        ).all():
            lbl = (t.step_label_cn or "").strip()
            if lbl:
                step_labels[int(t.suite_step)] = lbl
                _DYNAMIC_STEP_LABELS[(scenario, int(t.suite_step))] = lbl
        _DYNAMIC_SCENARIO_CHINESE[scenario] = row.label_cn
        register_dynamic_scenario(scenario, row.label_cn, row.step_count, step_labels)
        return True
    except Exception:
        logger.warning("MAIL_CUSTOM_SUITE_LAZYLOAD_FAILED scenario=%s", scenario, exc_info=True)
        return False
    finally:
        db.close()

# "印刷报价后跟进"独立模板: 不绑定案例联系人, 用固定 customer_key 单独成组, 内容人工填写。
_MAIL_PRINT_QUOTE_FOLLOWUP_SCENARIO = "print_quote_followup"
_MAIL_PRINT_QUOTE_FOLLOWUP_CUSTOMER_KEY = "PRINT-QUOTE-FOLLOWUP"

# CRM 生命周期阶段(crm_profile._get_customer_lifecycle_stage 的 3 个取值, 按联系人维度)→ 套装场景映射:
#   熟联系人(该联系人近1年≥3销售合同) → 老客户其他业务介绍
#   老联系人(该联系人历史有销售合同)   → 老客户激活
#   新联系人(该联系人无销售合同)       → 新客户开发介绍
_MAIL_LIFECYCLE_STAGE_TO_SCENARIO = {
    "熟联系人": "new_business_promotion",
    "老联系人": "re_activation",
    "新联系人": "new_contact_intro",
}


def _mail_scenario_from_lifecycle_stage(lifecycle_stage: str | None) -> tuple[str, str]:
    """按 CRM 生命周期阶段真实判断套装场景, 返回 (scenario, 判断依据文案)。

    阶段无法识别(CRM 查询失败/为空/未知值)时回退默认 new_business_promotion。
    """
    stage = sanitize_text(lifecycle_stage or "").strip()
    scenario = _MAIL_LIFECYCLE_STAGE_TO_SCENARIO.get(stage)
    if scenario:
        return scenario, f"CRM 生命周期阶段={stage}"
    if stage:
        return "new_business_promotion", f"未知生命周期阶段({stage})，回退默认"
    return "new_business_promotion", "CRM 生命周期阶段未识别，回退默认"

