def _load_runtime_settings_with_defaults() -> dict[str, Any]:
    import os, json
    from intent_engine import IntentEngine

    # Get defaults
    try:
        default_wecom_prompt = IntentEngine.get_ai_settings().get("SYSTEM_PROMPT_LLM2") or ""
    except Exception:
        default_wecom_prompt = ""

    default_wecom_temp = 0.7
    default_mail_prompt = _MAIL_DRAFT_LLM_SYSTEM_PROMPT
    default_mail_temp = 0.3

    path = os.path.join(os.path.dirname(__file__), "runtime_llm_settings.json")
    data = {}
    if os.path.exists(path):
        try:
            with open(path, "r", encoding="utf-8") as f:
                data = json.load(f)
        except Exception:
            pass
    if not isinstance(data, dict):
        data = {}

    return {
        "wecom_system_prompt": data.get("wecom_system_prompt") or default_wecom_prompt,
        "wecom_temperature": data.get("wecom_temperature") if data.get("wecom_temperature") is not None else default_wecom_temp,
        "mail_system_prompt": data.get("mail_system_prompt") or default_mail_prompt,
        "mail_temperature": data.get("mail_temperature") if data.get("mail_temperature") is not None else default_mail_temp,
        "mail_generation_model": _normalize_mail_generation_model(data.get("mail_generation_model")),
    }


_MAIL_DRAFT_LLM_SYSTEM_PROMPT = (
    "你是事必达的资深销售。写给客户的邮件要像真人发出的轻商务邮件：自然、具体、克制。\n"
    "不要写成营销文、服务清单、合规摘要或 AI 总结。\n"
    "只输出 JSON，不要 Markdown：{\"subject\":\"\",\"paragraphs\":[\"称呼段\",\"正文段1\",\"正文段2\"]}"
)

_MAIL_GENERATION_MODEL_OPTIONS: dict[str, dict[str, str]] = {
    "deepseek-v4-flash": {
        "provider": "deepseek",
        "label": "deepseek-v4-flash（默认）",
        "model": "deepseek-v4-flash",
    },
    "deepseek-v4-pro": {
        "provider": "deepseek",
        "label": "deepseek-v4-pro",
        "model": "deepseek-v4-pro",
    },
    "chatgpt": {
        "provider": "openai",
        "label": "ChatGPT",
        "model": "",
    },
}


def _normalize_mail_generation_model(value: str | None) -> str:
    key = sanitize_text(value or "").strip().lower()
    aliases = {
        "": "deepseek-v4-flash",
        "deepseek": "deepseek-v4-flash",
        "deepseek-chat": "deepseek-v4-flash",
        "deepseek-v4-flash": "deepseek-v4-flash",
        "deepseek-v4-pro": "deepseek-v4-pro",
        "openai": "chatgpt",
        "gpt": "chatgpt",
        "chatgpt": "chatgpt",
    }
    return aliases.get(key, "deepseek-v4-flash")


def _save_mail_generation_model(model_key: str) -> None:
    import os, json

    path = os.path.join(os.path.dirname(__file__), "runtime_llm_settings.json")
    data: dict[str, Any] = {}
    if os.path.exists(path):
        try:
            with open(path, "r", encoding="utf-8") as f:
                loaded = json.load(f)
            if isinstance(loaded, dict):
                data = loaded
        except Exception:
            data = {}
    data["mail_generation_model"] = _normalize_mail_generation_model(model_key)
    try:
        with open(path, "w", encoding="utf-8") as f:
            json.dump(data, f, ensure_ascii=False, indent=2)
    except Exception as exc:
        raise HTTPException(status_code=500, detail=f"保存邮件生成模型配置失败: {exc}")


def _mail_draft_chat_url(api_url: str) -> str:
    base = (api_url or "").rstrip("/")
    if not base:
        return ""
    if base.endswith("/chat/completions") or base.endswith("/v1/messages"):
        return base
    return base + "/chat/completions"


def _mail_draft_llm_provider() -> str:
    model_key = _normalize_mail_generation_model(_load_runtime_settings_with_defaults().get("mail_generation_model"))
    return _MAIL_GENERATION_MODEL_OPTIONS[model_key]["provider"]


def _mail_draft_llm_config(provider: str | None = None) -> dict[str, Any]:
    requested = sanitize_text(provider or "").strip().lower()
    model_key = _normalize_mail_generation_model(requested) if requested else _normalize_mail_generation_model(_load_runtime_settings_with_defaults().get("mail_generation_model"))
    option = _MAIL_GENERATION_MODEL_OPTIONS[model_key]
    provider_key = option["provider"]
    if provider_key == "openai":
        api_url = (
            getattr(settings, "MAIL_DRAFT_OPENAI_API_URL", "")
            or getattr(settings, "RECORDING_PARSE_OPENAI_VISION_API_URL", "")
            or "https://api.openai.com/v1/chat/completions"
        )
        api_key = getattr(settings, "MAIL_DRAFT_OPENAI_API_KEY", "") or getattr(settings, "RECORDING_PARSE_OPENAI_VISION_API_KEY", "")
        model = getattr(settings, "MAIL_DRAFT_OPENAI_MODEL", "") or "gpt-4o-mini"
        timeout = int(getattr(settings, "MAIL_DRAFT_OPENAI_TIMEOUT_SECONDS", 60) or 60)
    else:
        provider_key = "deepseek"
        api_url = getattr(settings, "LLM2_API_URL", "")
        api_key = getattr(settings, "LLM2_API_KEY", "")
        model = option["model"] or getattr(settings, "LLM2_MODEL", "")
        timeout = int(getattr(settings, "LLM2_TIMEOUT_SECONDS", 100) or 100)
    runtime_settings = _load_runtime_settings_with_defaults()
    dyn_temp = runtime_settings.get("mail_temperature")
    if dyn_temp is not None:
        try:
            temperature = float(dyn_temp)
        except ValueError:
            temperature = float(getattr(settings, "MAIL_DRAFT_LLM_TEMPERATURE", 0.7) or 0.7)
    else:
        temperature = float(getattr(settings, "MAIL_DRAFT_LLM_TEMPERATURE", 0.7) or 0.7)

    return {
        "provider": provider_key,
        "model_key": model_key,
        "api_url": _mail_draft_chat_url(api_url),
        "api_key": api_key or "",
        "model": model or "",
        "timeout_seconds": timeout,
        "temperature": temperature,
        "max_tokens": int(getattr(settings, "MAIL_DRAFT_LLM_MAX_TOKENS", 1800) or 1800),
    }


def _mail_draft_llm_public_config() -> dict[str, Any]:
    active_model = _normalize_mail_generation_model(_load_runtime_settings_with_defaults().get("mail_generation_model"))
    active_provider = _MAIL_GENERATION_MODEL_OPTIONS[active_model]["provider"]
    model_options = []
    for model_key, option in _MAIL_GENERATION_MODEL_OPTIONS.items():
        cfg = _mail_draft_llm_config(model_key)
        model_options.append({
            "value": model_key,
            "provider": cfg["provider"],
            "label": option["label"],
            "configured": bool(cfg["api_url"] and cfg["api_key"] and cfg["model"]),
            "api_url": cfg["api_url"],
            "model": cfg["model"],
            "active": model_key == active_model,
        })
    return {
        "version": "mail_draft_llm_config.v2",
        "active_model": active_model,
        "active_provider": active_provider,
        "providers": model_options,
        "model_options": model_options,
        "real_sending_enabled": False,
        "wecom_impact": "none",
    }


class MailDraftLlmConfigUpdateRequest(BaseModel):
    model: str | None = None
    provider: str | None = None


@app.get("/api/v1/mail/draft-llm-config")
def get_mail_draft_llm_config():
    return _mail_draft_llm_public_config()


@app.put("/api/v1/mail/draft-llm-config")
def update_mail_draft_llm_config(payload: MailDraftLlmConfigUpdateRequest):
    model_key = _normalize_mail_generation_model(payload.model or payload.provider)
    cfg = _mail_draft_llm_config(model_key)
    if not (cfg["api_url"] and cfg["api_key"] and cfg["model"]):
        raise HTTPException(status_code=422, detail=f"{model_key} 邮件草稿 LLM 未配置完整，不能切换")
    _save_mail_generation_model(model_key)
    return _mail_draft_llm_public_config()


@app.post("/api/v1/mail/draft-llm-config/test")
def test_mail_draft_llm_config(payload: MailDraftLlmConfigUpdateRequest):
    model_key = _normalize_mail_generation_model(payload.model or payload.provider)
    cfg = _mail_draft_llm_config(model_key)
    provider = cfg["provider"]
    if not (cfg["api_url"] and cfg["api_key"] and cfg["model"]):
        return {
            "status": "not_configured",
            "provider": provider,
            "model_key": model_key,
            "model": cfg["model"],
            "configured": False,
            "message": f"{model_key} 邮件草稿 LLM 未配置完整",
        }
    test_prompt = (
        "只输出JSON，不要markdown。"
        '{"subject":"测试邮件主题","paragraphs":["测试您好，","这是一条邮件模型连通性测试。"]}'
    )
    result = _call_llm2_json_for_mail_draft(test_prompt, timeout_seconds=min(cfg["timeout_seconds"], 30), model_key=model_key)
    return {
        "status": "success" if result.get("parsed") else "error",
        "provider": provider,
        "model_key": model_key,
        "model": result.get("model") or cfg["model"],
        "configured": True,
        "error": result.get("error"),
        "parsed_keys": sorted((result.get("parsed") or {}).keys()),
    }

def _call_llm2_json_for_mail_draft(prompt: str, timeout_seconds: int = 35, force_json: bool = True, model_key: str | None = None) -> dict:
    """Call mail draft LLM provider (default DeepSeek, can switch to OpenAI/ChatGPT/Claude) for JSON response.

    Returns {parsed: dict | None, raw_text: str, error: str | None, model: str}.
    """
    import requests as _rq

    cfg = _mail_draft_llm_config(model_key)
    api_url = cfg["api_url"]
    api_key = cfg["api_key"]
    model = cfg["model"]
    provider = cfg["provider"]
    if not api_url or not api_key or not model:
        return {"parsed": None, "raw_text": "", "error": f"{provider} 邮件草稿 LLM 环境变量未配置完整", "model": model}

    # If it is Anthropic native API:
    if provider == "anthropic" and ("api.anthropic.com" in api_url or "/v1/messages" in api_url):
        headers = {
            "x-api-key": api_key,
            "anthropic-version": "2023-06-01",
            "content-type": "application/json",
        }
        payload = {
            "model": model,
            "messages": [{"role": "user", "content": prompt}],
            "temperature": cfg["temperature"],
            "max_tokens": cfg["max_tokens"],
        }
    else:
        # Standard OpenAI API call
        headers = {
            "Authorization": f"Bearer {api_key}",
            "Content-Type": "application/json",
        }
        payload = {
            "model": model,
            "messages": [{"role": "user", "content": prompt}],
            "temperature": cfg["temperature"],
            "max_tokens": cfg["max_tokens"],
        }
        # Do not force response_format JSON if it's Claude model or Anthropic provider,
        # as standard proxy APIs might fail or reject JSON schema formatting parameters
        if force_json and not ("claude" in model.lower() or "anthropic" in provider):
            payload["response_format"] = {"type": "json_object"}

    raw_text = ""
    try:
        session = _rq.Session()
        session.trust_env = False
        resp = session.post(api_url, json=payload, headers=headers, timeout=timeout_seconds or cfg["timeout_seconds"])
        if resp.status_code != 200:
            return {"parsed": None, "raw_text": "", "error": f"{provider} HTTP {resp.status_code}: {resp.text[:200]}", "model": f"{provider}:{model}"}
        data = resp.json()

        # Parse text field depending on response structure
        if provider == "anthropic" and "content" in data:
            raw_text = data["content"][0]["text"] if data["content"] else ""
        elif "choices" in data:
            raw_text = data["choices"][0]["message"]["content"] if "choices" in data else ""
        else:
            # Fallback if proxy behaves differently
            raw_text = data.get("content") or ""

        # Safely strip potential markdown blocks from raw response text
        cleaned = raw_text.strip()
        if cleaned.startswith("```json"):
            cleaned = cleaned[7:]
        if cleaned.startswith("```"):
            cleaned = cleaned[3:]
        if cleaned.endswith("```"):
            cleaned = cleaned[:-3]
        cleaned = cleaned.strip()

        if not force_json:
            return {"parsed": None, "raw_text": raw_text, "error": None, "model": f"{provider}:{model}"}

        parsed = json.loads(cleaned)
        return {"parsed": parsed, "raw_text": raw_text, "error": None, "model": f"{provider}:{model}"}
    except json.JSONDecodeError as exc:
        return {"parsed": None, "raw_text": raw_text, "error": f"JSON 解析失败: {exc}. 原始输出: {raw_text[:200]}", "model": f"{provider}:{model}"}
    except Exception as exc:
        return {"parsed": None, "raw_text": "", "error": f"{provider} 调用异常: {sanitize_text(str(exc))[:200]}", "model": f"{provider}:{model}"}


def _call_llm2_text_for_mail_draft(prompt: str, timeout_seconds: int = 35) -> dict:
    """Call mail draft LLM with the exact user script only; do not force JSON response."""
    return _call_llm2_json_for_mail_draft(prompt, timeout_seconds=timeout_seconds, force_json=False)


def _mail_generation_industry_for_prompt(profile: MailDraftIntentProfile) -> str:
    company_raw = sanitize_text(profile.company_name or "")
    company = company_raw.lower()
    raw_industry = sanitize_text(profile.company_industry or "")
    medical_company_tokens = ("爱德华", "edwards", "医疗", "medical", "医药", "生物", "生命科学", "器械")
    if any(token in company_raw for token in medical_company_tokens) or any(token in company for token in medical_company_tokens):
        return "医疗器械/生命科学客户（法律/合同仅作资料类型线索）"
    industrial_company_tokens = ("设备", "空气处理", "制造", "工业", "机械", "工程", "电气", "半导体", "材料", "化工")
    if any(token in company_raw for token in industrial_company_tokens) or any(token in company for token in industrial_company_tokens):
        return "工业设备/制造客户（法律/合同仅作资料类型线索）"
    if raw_industry in {"legal", "法律服务", "法律资料"}:
        return "客户行业未确认；法律/合同仅作资料类型线索"
    return raw_industry or "客户行业未明确，按客户公司名和历史合作保守判断"


def _mail_prompt_template_text(value: str | None, limit: int = 1200) -> str:
    text_value = sanitize_text(value or "")
    if not text_value:
        return "无前台模板内容。"
    return text_value[:limit]


def _mail_prompt_multiline_fact(value: str | None, limit: int = 900) -> str:
    text_value = sanitize_text(value or "")
    if not text_value:
        return "无明确记录。"
    text_value = re.sub(r"\n{3,}", "\n\n", text_value).strip()
    return text_value[: max(int(limit), 1)]


def _mail_prompt_variable_value(value: str | None, limit: int = 240) -> str:
    text_value = _mail_prompt_fact(value, limit)
    if text_value in {"无明确记录", "unknown", "None"}:
        return "无明确记录"
    return text_value


def _mail_prompt_template_variable_map(
    profile: MailDraftIntentProfile,
    *,
    industry: str,
    crm_history: str,
    fewshot_title: str,
    fewshot_content: str,
    service_focus: str,
) -> list[str]:
    return [
        f"{{customer_name}} = {_mail_prompt_variable_value(profile.recipient_name, 60)}",
        f"{{company_name}} = {_mail_prompt_variable_value(profile.company_name, 100)}",
        f"{{industry}} = {_mail_prompt_variable_value(industry, 80)}",
        f"{{history}} = {_mail_prompt_variable_value(crm_history, 120)}",
        f"{{peer_case}} = {fewshot_title or '无命中'}",
        f"{{business_lines}} = {service_focus.rstrip('。')}",
        f"{{seller_name}} = {_mail_prompt_variable_value(profile.seller_name, 40)}",
        "{referral_request} = 请对方判断是否转给相关团队，不直接索要电话或邮箱",
    ]


def _mail_prompt_full_email_examples(profile: MailDraftIntentProfile, limit: int = 5) -> list[str]:
    examples = []
    for item in (profile.prompt_full_email_examples or [])[:max(int(limit), 1)]:
        function_fragment = sanitize_text(item.get("function_fragment") if isinstance(item, dict) else "")
        review_status = sanitize_text(item.get("review_status") if isinstance(item, dict) else "")
        title = _mail_prompt_fact(sanitize_text(item.get("title") if isinstance(item, dict) else ""), 90)
        content = _mail_sanitize_fewshot_reference_for_draft(item.get("content") if isinstance(item, dict) else "") or ""
        content = _mail_prompt_fact(content, 520)
        score = item.get("useful_score") if isinstance(item, dict) else None
        label = title if title != "无明确记录" else "未命名完整邮件"
        body = content if content != "无明确记录" else "无可用内容"
        score_text = f"；分数：{score}" if score is not None else ""
        approved_text = "；人工认可" if review_status == "approved" else "；未评审/候选"
        fragment_text = f"；切片类型：{function_fragment or 'unknown'}"
        examples.append(f"{len(examples) + 1}）{label}{score_text}{approved_text}{fragment_text}\n{body}")
    return examples


def _mail_prompt_contract_case_examples(profile: MailDraftIntentProfile, limit: int = 5) -> list[str]:
    examples = []
    for item in (profile.prompt_contract_case_examples or [])[:max(int(limit), 1)]:
        contract_id = sanitize_text(item.get("contract_id") if isinstance(item, dict) else "")
        business_type = sanitize_text(item.get("business_type") if isinstance(item, dict) else "")
        product_name = sanitize_text(item.get("product_name_all") if isinstance(item, dict) else "")
        business_line = sanitize_text(item.get("business_line_inferred") if isinstance(item, dict) else "")
        case_text = sanitize_text(item.get("mail_case_text") if isinstance(item, dict) else "")
        raw_text = sanitize_text(item.get("case_text_raw") if isinstance(item, dict) else "")
        main_text = case_text or raw_text or "无案例摘要"
        examples.append(
            f"{len(examples) + 1}）合同案例 {contract_id or '未编号'}｜{business_type or '业务类型未标注'}｜{product_name or '产品未标注'}｜{business_line or '业务线未标注'}\n"
            f"{_mail_prompt_fact(main_text, 320)}"
        )
    return examples


def _mail_prompt_approved_gold_style_standard(profile: MailDraftIntentProfile) -> str:
    full_email_titles = [
        sanitize_text(item.get("title") or "")
        for item in (profile.prompt_full_email_examples or profile.admitted_fewshot_examples or [])
        if isinstance(item, dict)
        and sanitize_text(item.get("function_fragment") or "") == "full_email"
        and sanitize_text(item.get("review_status") or "") == "approved"
    ]
    title_hint = "；".join(title for title in full_email_titles[:2] if title)
    return (
        "人工认可黄金邮件标准：像销售本人写给熟客户或潜在联系人，不像规则摘要。"
        "写法要有自然称呼、一个具体业务场景、少量可信经验、轻商务语气和低压力下一步；"
        "可以借鉴 approved full_email 的亲和、具体、可转发感，但不要照抄夸张数字、客户原话、微信/领礼品等不适合本次客户的内容。"
        f"{' 当前参考主题：' + title_hint if title_hint else ''}"
    )


def _mail_generation_stage_brief(profile: MailDraftIntentProfile) -> str:
    scenario = sanitize_text(profile.scenario)
    step_no = int(profile.suite_step)
    if scenario == "new_business_promotion":
        return {
            1: "第1封：破冰。承接已有合作，只提出一个自然的非笔译业务切口。",
            2: "第2封：补一个同类型参考，不写成当前客户自己的历史。",
            3: "第3封：说明如果要推进，可以从什么资料/场景开始。",
            4: "第4封：低压力收口，请对方判断是否需要服务清单或转给相关团队。",
        }.get(step_no, "按当前阶段写。")
    if scenario == "re_activation":
        return {
            1: "第1封：像老朋友一样重新保持联系，不催单。",
            2: "第2封：用相近行业经验唤醒需求。",
            3: "第3封：给一个很轻的协作路径。",
            4: "第4封：礼貌收口，确认是否需要资料评估或转给相关同事。",
        }.get(step_no, "按当前阶段写。")
    if scenario == "new_contact_intro":
        return {
            1: "第1封：说明身份和来意，确认是否找对负责人。",
            2: "第2封：补充可信经验。",
            3: "第3封：说明项目怎么开始。",
            4: "第4封：低压力确认负责人或转介绍。",
        }.get(step_no, "按当前阶段写。")
    return "按当前阶段写。"


def _mail_generation_opening_hint(profile: MailDraftIntentProfile) -> str:
    scenario = sanitize_text(profile.scenario)
    step_no = int(profile.suite_step)
    if scenario == "new_business_promotion":
        return {
            1: "从真实历史合作事实开头，顺势提出一个非笔译业务切口。",
            2: "从同类型优秀段落或可迁移场景切入，但不要写成当前客户自己的历史。",
            3: "从一个很小的资料、会议、活动或内容场景开始梳理。",
            4: "低压力同步服务范围，请对方判断是否需要清单、资料评估或转给相关团队。",
        }.get(step_no, "")
    return ""


def _mail_prompt_short_purpose(profile: MailDraftIntentProfile) -> str:
    purpose = sanitize_text(profile.sequence_template_purpose)
    default_markers = ("4 封套装", "必须服务于总目标", "商用邮件标准")
    if not purpose or any(marker in purpose for marker in default_markers):
        return _mail_generation_stage_brief(profile)
    return _mail_prompt_fact(purpose, 70)


def _mail_prompt_short_timing(profile: MailDraftIntentProfile) -> str:
    timing = sanitize_text(profile.sequence_template_send_timing)
    if not timing:
        return ""
    match = re.search(r"第\s*\d+\s*天发送(?:：[^。；;]*)?", timing)
    if match:
        return match.group(0).strip()
    return _mail_prompt_fact(timing, 55)


def _mail_prompt_customer_salutation(profile: MailDraftIntentProfile) -> str:
    """问候语称呼:有英文名优先用英文名;否则"姓+称谓",称谓按真实性别(男->先生,女->女士)。

    性别未知时不强加称谓(避免叫错),退回原名。称呼为空则返回"您好"。
    """
    # 1) 英文名优先(来自 CRM 联系人 EnglishName)
    english = sanitize_text(getattr(profile, "recipient_english_name", "") or "").strip()
    if english:
        return english.split()[0].strip(" ,;，；") or english
    name = sanitize_text(profile.recipient_name or "").strip()
    if not name:
        return "您好"
    # recipient_name 本身就是英文(如来自邮箱前缀)时也按英文名用
    if re.search(r"[A-Za-z]", name):
        return name.split()[0].strip(" ,;，；") or name
    # 名字本身已带称谓/职务则原样保留
    if name.endswith(("小姐", "先生", "女士", "总", "经理")):
        return name
    chinese = re.sub(r"[^\u4e00-\u9fff]", "", name)
    gender = sanitize_text(getattr(profile, "recipient_gender", "") or "").strip()
    if chinese:
        surname = chinese[:1]
        if gender == "男":
            return f"{surname}先生"
        if gender == "女":
            return f"{surname}女士"
        # 性别未知:不猜称谓,直接用原中文名
        return name
    return name


def _mail_prompt_company_short_name(profile: MailDraftIntentProfile) -> str:
    company = sanitize_text(profile.company_name or "").strip()
    if not company:
        return "贵司"
    company = re.sub(r"[（(].*?[）)]", "", company)
    company = re.sub(r"(股份)?有限公司|有限责任公司|集团|中国|上海|北京|广州|深圳|科技|技术|贸易|实业", "", company)
    company = company.strip(" -_，,；;")
    short = company or sanitize_text(profile.company_name or "").strip() or "贵司"
    # 公司名最多保留 4 个字符（含 4），避免邮件抬头过长
    return short[:4]


def _mail_prompt_history_summary(profile: MailDraftIntentProfile, crm_history: str) -> str:
    source = "；".join(
        item for item in [
            sanitize_text(profile.recent_opportunities or ""),
            sanitize_text(profile.ongoing_contracts or ""),
            sanitize_text(profile.contact_recent_followup or ""),
            sanitize_text(crm_history or ""),
        ]
        if item
    )
    service_terms: list[str] = []
    term_map = [
        ("笔译", ("笔译", "翻译", "英译中", "中译英", "资料")),
        ("同传", ("同传", "口译", "会议")),
        ("多媒体译制", ("多媒体", "视频", "字幕", "配音")),
        ("排版印刷", ("排版", "印刷", "画册", "手册")),
        ("活动物料", ("展会", "活动", "物料", "礼品")),
    ]
    for label, keywords in term_map:
        if any(keyword in source for keyword in keywords) and label not in service_terms:
            service_terms.append(label)
    if service_terms:
        return f"为客户提供{'，'.join(service_terms)}服务"
    cleaned = _mail_prompt_variable_value(crm_history, 240)
    return cleaned if cleaned != "无明确记录" else "为客户提供过相关服务"


def _mail_prompt_template_variable_values(profile: MailDraftIntentProfile, *, industry: str, crm_history: str) -> dict[str, str]:
    return {
        "customer_name": _mail_prompt_customer_salutation(profile),
        "company_name": _mail_prompt_company_short_name(profile),
        "industry": _mail_prompt_variable_value(industry, 120),
        "history": _mail_prompt_history_summary(profile, crm_history),
        "business_lines": "笔译/本地化、会议同传/设备、多媒体译制、排版印刷、展会活动物料、商务礼品",
        "seller_name": _mail_prompt_variable_value(profile.seller_name, 40),
        "referral_request": "请对方判断是否转给相关团队",
        "peer_case": "",
    }


def _mail_apply_prompt_template_variables(template: str, values: dict[str, str]) -> str:
    rendered = template or ""
    for key, value in values.items():
        rendered = rendered.replace("{" + key + "}", sanitize_text(value))
    return _mail_brand_display_text(rendered)


def _build_mail_draft_llm_full_prompt(profile: MailDraftIntentProfile) -> str:
    crm_history = "；".join(
        part
        for part in [
            f"商机：{_mail_prompt_fact(profile.recent_opportunities, 70)}",
            f"历史：{_mail_prompt_fact(profile.ongoing_contracts, 70)}",
            f"跟进：{_mail_prompt_fact(profile.contact_recent_followup, 70)}",
        ]
        if "无明确记录" not in part
    ) or "无明确历史记录。"
    crm_history = re.sub(r"负责人：[^｜；;，,。]+[｜；;，,]?", "", crm_history)
    crm_history = re.sub(r"销售：[^，,；;。]+[，,；;]?", "", crm_history)
    crm_history = re.sub(r"(?:QQ|微信|企微|电话)[，,；;]?", "", crm_history, flags=re.IGNORECASE)
    crm_history = re.sub(r"销售询问[^；;。]*负责人信息", "有相关部门协作线索", crm_history)
    crm_history = re.sub(r"[；;]?\s*跟进：.*$", "", crm_history)
    crm_history = re.sub(r"-{3,}", "", crm_history).strip("；; ，,")
    crm_history = crm_history.replace("近期商机记录", "已有商机记录")
    crm_history = crm_history.replace("近期时间", "历史时间")
    industry = _mail_generation_industry_for_prompt(profile)
    template = sanitize_text(profile.sequence_template_ai_instruction or "").strip()
    if not template:
        template = sanitize_text(profile.sequence_template_script or "").strip()
    values = _mail_prompt_template_variable_values(profile, industry=industry, crm_history=crm_history)
    return _mail_apply_prompt_template_variables(template, values)


def _mail_normalize_llm_text(value: str | None) -> str:
    text_value = (value or "").replace("\r\n", "\n").replace("\r", "\n")
    text_value = re.sub(r"[ \t]+\n", "\n", text_value)
    text_value = re.sub(r"\n{3,}", "\n\n", text_value)
    return text_value.strip()


def _mail_strip_markdown_label(value: str | None) -> str:
    text_value = re.sub(r"^\s*[-*#]+\s*", "", value or "")
    text_value = text_value.replace("**", "").replace("__", "")
    return text_value.strip()


def _mail_text_to_body_html(value: str | None) -> str:
    text_value = _mail_normalize_llm_text(value)
    if not text_value:
        return ""
    paragraphs = [part.strip() for part in re.split(r"\n{2,}", text_value) if part.strip()]
    return "".join(f"<p>{html.escape(part).replace(chr(10), '<br>')}</p>" for part in paragraphs)


def _mail_generated_body_html_from_value(value: str | None) -> str:
    text_value = _mail_normalize_llm_text(value)
    if not text_value:
        return ""
    text_value = re.sub(r"(?is)<\s*(script|style)\b.*?>.*?<\s*/\s*\1\s*>", "", text_value)
    if re.search(r"<\s*(p|div|br|table|ul|ol|li)\b", text_value, flags=re.IGNORECASE):
        return text_value
    return _mail_text_to_body_html(text_value)


def _mail_extract_json_object_from_text(value: str | None) -> dict[str, Any] | None:
    raw = _mail_normalize_llm_text(value)
    fence = re.search(r"```(?:json)?\s*(\{.*?\})\s*```", raw, flags=re.S | re.I)
    if fence:
        raw = fence.group(1)
    else:
        start = raw.find("{")
        end = raw.rfind("}")
        if start >= 0 and end > start:
            raw = raw[start : end + 1]
    try:
        data = json.loads(raw)
    except Exception:
        return None
    return data if isinstance(data, dict) else None


def _mail_subject_body_from_json_payload(data: dict[str, Any]) -> tuple[str, str, list[str]]:
    subject = sanitize_text(data.get("subject") or data.get("title") or "").strip()[:200]
    body_html = _mail_generated_body_html_from_value(data.get("body_html") or data.get("html") or "")
    if body_html:
        return subject, body_html, []
    body = sanitize_text(data.get("body") or data.get("content") or "").strip()
    if body:
        return subject, _mail_text_to_body_html(body), []
    paragraphs_raw = data.get("paragraphs")
    if isinstance(paragraphs_raw, list):
        paragraphs = [
            _mail_sanitize_generated_mail_paragraph(str(item or "").strip())
            for item in paragraphs_raw
            if str(item or "").strip()
        ]
        return subject, "", paragraphs
    return subject, "", []


def _mail_extract_subject_body_from_raw_llm_output(raw_text: str) -> tuple[str, str, list[str], dict[str, Any]]:
    parsed = _mail_extract_json_object_from_text(raw_text)
    if parsed:
        subject, body_html, paragraphs = _mail_subject_body_from_json_payload(parsed)
        return subject, body_html, paragraphs, {"source": "json"}

    text_value = _mail_normalize_llm_text(raw_text)
    subject = ""
    body = text_value
    subject_match = None
    for pattern in [
        r"(?m)^\s*(?:\*\*)?邮件主题(?:\*\*)?\s*[：:]\s*(.+)$",
        r"(?m)^\s*(?:\*\*)?主题(?:\*\*)?\s*[：:]\s*(.+)$",
        r"(?m)^\s*Subject\s*[：:]\s*(.+)$",
        r"(?m)^\s*邮件标题\s*[：:]\s*(.+)$",
    ]:
        subject_match = re.search(pattern, text_value, flags=re.I)
        if subject_match:
            subject = _mail_strip_markdown_label(subject_match.group(1)).strip(" ：:")[:200]
            break
    if subject_match:
        body = text_value[: subject_match.start()] + text_value[subject_match.end() :]
    body_match = re.search(r"(?is)(?:\*\*)?正文(?:\*\*)?\s*[：:]\s*(.+)$", body)
    if body_match:
        body = body_match.group(1)
    body = re.sub(r"(?m)^\s*(?:\*\*)?(?:邮件主题|主题|邮件标题|Subject)(?:\*\*)?\s*[：:].*$", "", body, flags=re.I)
    body = re.sub(r"(?m)^\s*(?:\*\*)?正文(?:\*\*)?\s*[：:]\s*", "", body)
    body_html = _mail_text_to_body_html(body)
    return subject, body_html, [], {"source": "raw_text", "subject_detected": bool(subject)}


def _llm_generate_mail_intro_paragraphs(profile: MailDraftIntentProfile) -> dict:
    """调用 LLM-2 (DeepSeek) 起草中文邮件的"人际沟通"段（自我介绍 / 价值 / 行动呼吁）。

    v1.7.208 行为变更（按用户要求注释掉所有 fallback_template 返回）：
    - LLM-2 报错 / 返空 / 返缺字段 → 直接 raise HTTPException 503, 不再返 status='fallback_template'
      让上层 _assemble_mail_draft_from_intent_profile 假装"已识别为兜底"。
    - 成功路径返 {status: 'success', model, subject, paragraphs, error: None, prompt}。
    """
    full_prompt = _build_mail_draft_llm_full_prompt(profile)

    llm_resp = _call_llm2_text_for_mail_draft(full_prompt, timeout_seconds=35)
    model_name = llm_resp.get("model") or "llm2"
    # v1.7.208 旧的 fallback_template 返回逻辑（已注释 — 用户禁止假装成功）:
    #   if llm_resp.get("error") or not llm_resp.get("parsed"):
    #       err = llm_resp.get("error") or "LLM-2 返回空"
    #       logger.warning("MAIL_DRAFT_LLM2_FALLBACK reason=%s", err)
    #       return {"status": "fallback_template", "model": model_name, "subject": "", "paragraphs": [], "error": ..., "prompt": full_prompt}
    if llm_resp.get("error") or not llm_resp.get("parsed"):
        if llm_resp.get("error"):
            err = llm_resp.get("error") or "LLM-2 返回空"
            logger.warning("MAIL_DRAFT_LLM2_FAILED reason=%s", err)
            raise HTTPException(
                status_code=503,
                detail=f"LLM-2 (DeepSeek) 调用失败（v1.7.208 不再返 fallback_template 兜底）: {sanitize_text(str(err))[:240]}",
            )
    raw_text = llm_resp.get("raw_text") or ""
    subject, body_html, paragraphs, parse_meta = _mail_extract_subject_body_from_raw_llm_output(raw_text)
    # v1.7.208 旧的"缺 subject/paragraphs 返 fallback_template"逻辑（已注释）:
    #   if not subject or not paragraphs:
    #       logger.warning("MAIL_DRAFT_LLM2_FALLBACK reason=missing subject/paragraphs")
    #       return {"status": "fallback_template", ...}
    if not body_html and not paragraphs:
        logger.warning("MAIL_DRAFT_LLM2_FAILED reason=missing body")
        raise HTTPException(
            status_code=502,
            detail="LLM-2 (DeepSeek) 返回内容为空或无法解析为邮件正文（v1.7.208 不再返 fallback_template 兜底）。",
        )
    return {
        "status": "success",
        "model": model_name,
        "subject": subject[:200],
        "paragraphs": paragraphs[:6],
        "body_html": body_html,
        "error": None,
        "prompt": full_prompt,
        "raw_text": raw_text,
        "parse_meta": parse_meta,
    }


def _mail_normalize_body_paragraphs(raw_paragraphs: list[str]) -> list[str]:
    """Normalize generated email body layout without forcing a fixed paragraph count."""
    normalized: list[str] = []
    greeting_pattern = re.compile(
        r"^\s*(?P<greeting>(?:(?:Hi|Hello)\s+[\w\u4e00-\u9fff（）()·.\- ]{1,40}|(?:[\w\u4e00-\u9fff（）()·.\- ，,]{1,40})?(?:您好|你好|早上好|下午好|晚上好|Hi|Hello))[，,！!：:]?)\s*(?P<rest>.*)$",
        re.IGNORECASE,
    )
    for raw in raw_paragraphs or []:
        text_value = re.sub(r"\s+", " ", sanitize_text(raw or "")).strip()
        if not text_value:
            continue
        if not normalized:
            match = greeting_pattern.match(text_value)
            if match:
                greeting = match.group("greeting").strip()
                rest = match.group("rest").strip()
                if greeting and rest:
                    normalized.append(greeting)
                    normalized.append(rest)
                    continue
                if greeting:
                    normalized.append(greeting)
                    continue
        normalized.append(text_value)
    compact: list[str] = []
    for item in normalized:
        if compact and re.fullmatch(r"[，,！!。.:：\s]+", item):
            compact[-1] = (compact[-1].rstrip("，,！!。.:： ") + item.strip()).strip()
            continue
        if item and (not compact or compact[-1] != item):
            compact.append(item)
    return compact[:8]


def _mail_strip_markdown_artifacts(value: str | None) -> str:
    """剥离 LLM 正文/主题里多余的 markdown 痕迹(** * --- 等)，仅做出站展示清理，不修改生成脚本或提示词。"""
    s = str(value or "")
    if not s:
        return ""
    # 成对强调标记 ***x*** **x** *x* __x__ -> 保留文字去掉符号
    s = re.sub(r"\*\*\*(.+?)\*\*\*", r"\1", s)
    s = re.sub(r"\*\*(.+?)\*\*", r"\1", s)
    s = re.sub(r"\*(.+?)\*", r"\1", s)
    s = re.sub(r"__(.+?)__", r"\1", s)
    # 水平分隔线/连续符号(3个及以上的 - * _，两侧非单词字符) -> 删除；电话/日期里的单个连字符不受影响
    s = re.sub(r"(?<![\w一-鿿])[-*_]{3,}(?![\w一-鿿])", "", s)
    # 行首或标签后(>、换行、<br>)的列表符号 "- " "* " "+ " -> 删除符号保留文字
    s = re.sub(r"(^|[>\n]|<br\s*/?>)[ \t]*[*+\-][ \t]+", r"\1", s)
    # 残留孤立 **
    s = s.replace("**", "")
    # 清理因去分隔线产生的空段落
    s = re.sub(r"<p>\s*(?:&nbsp;| )?\s*</p>", "", s)
    return s


def _assemble_mail_draft_from_intent_profile(profile: MailDraftIntentProfile) -> MailDraftAssembledContent:
    llm_result = _llm_generate_mail_intro_paragraphs(profile)
    terms = profile.commercial_terms
    # v1.7.215 按用户校准"真为空 vs 真出错"：行业/风险中文映射缺 key 是【数据为空】
    # （CRM 出现了字典里没覆盖的新枚举值），不是【读取出错】。返原始英文值或空串继续，
    # 让前端看到原始值, 单条补字典 — 不打断 V3 测试。
    # 旧 v1.7.208 错误地 raise 500 中断流程。
    industry_cn = _MAIL_INDUSTRY_CN.get(profile.company_industry) or profile.company_industry or ""
    risk_cn = _MAIL_PAYMENT_RISK_CN.get(profile.payment_risk_level) or profile.payment_risk_level or ""

    # v1.7.207 按用户要求注释掉 LLM 失败时的 fallback 模板分支 — 让 LLM 失败直接 raise, 不假装成功.
    # 旧逻辑（已注释，保留作为后续如要恢复 fallback 的参考）:
    #   scenario_cn = _MAIL_SCENARIO_CHINESE.get(profile.scenario, profile.scenario_label)
    #   if llm_result["status"] == "success":
    #       subject_text = llm_result["subject"] or _mail_subject_from_intent_profile(profile)
    #       paragraphs = [html.escape(p) for p in llm_result["paragraphs"]]
    #   else:
    #       # 大模型上游不可用时走硬编码中文兜底模板（含"这是一封 ... 场景第 X 步的草稿样例 ..."meta 字眼）
    #       subject_text = _mail_subject_from_intent_profile(profile)
    #       paragraphs = [
    #           f"{html.escape(profile.recipient_name)} 您好，",
    #           f"这是一封【{html.escape(scenario_cn)}】场景第 {profile.suite_step} 步的草稿样例。"
    #           f"本步目标：{html.escape(profile.objective)}。",
    #       ]
    #       if profile.admitted_fewshot_content:
    #           paragraphs.append(f"参考角度（来自我们历史的高质量邮件范例库）：{html.escape(profile.admitted_fewshot_content[:240])}")
    if llm_result["status"] != "success":
        raise HTTPException(
            status_code=503,
            detail=(
                "大模型 LLM2 (DeepSeek) 草稿生成失败，按 v1.7.207 用户要求不再走 fallback 模板兜底。"
                f"错误: {llm_result.get('error') or '未返回 subject/paragraphs'}"
            ),
        )
    subject_text = _mail_strip_markdown_artifacts(_mail_brand_display_text(llm_result.get("subject") or ""))
    body_html_from_llm = _mail_brand_display_text(sanitize_text(llm_result.get("body_html") or "").strip())
    seller_signature = _mail_brand_display_text(profile.seller_signature)
    if body_html_from_llm:
        body_html = body_html_from_llm
        body_html += f"<p>{html.escape(seller_signature).replace(chr(10), '<br>')}</p>"
    else:
        body_paragraphs = _mail_normalize_body_paragraphs(llm_result["paragraphs"])
        paragraphs = [html.escape(_mail_brand_display_text(p)) for p in body_paragraphs]
        paragraphs.append(html.escape(seller_signature).replace("\n", "<br>"))
        body_html = "".join(f"<p>{paragraph}</p>" for paragraph in paragraphs)
    body_html = _mail_strip_markdown_artifacts(_mail_brand_display_text(body_html))

    review_meta = MailGenerateDraftReviewMetadata(
        crm_profile_signals={
            "company_industry_cn": industry_cn,
            "payment_risk_level_cn": risk_cn,
            "customer_domains": list(profile.customer_domains),
        },
        commercial_terms_for_review={
            "price": terms.price.value,
            "delivery_sla": terms.delivery.value,
            "discount": terms.discount.value,
            "payment_terms": terms.payment_terms.value,
            "note": "以上占位符将在真发件前由 PricingRule 表强制替换；本草稿当前未启用真实发件。",
        },
        lock_notice="本草稿已锁定到人工审稿队列，当前未启用真实发件。",
        suggested_next_step=_MAIL_CTA_CN_BY_STEP.get(
            (profile.scenario, int(profile.suite_step)),
            profile.cta_style or "",
        ),
    )

    return MailDraftAssembledContent(
        subject=subject_text,
        body_html=body_html,
        llm_status=llm_result["status"],
        llm_model_used=llm_result["model"],
        llm_error=llm_result["error"],
        llm_prompt=_mail_brand_display_text(llm_result.get("prompt")),
        review_metadata=review_meta,
    )

def _build_mail_generate_draft_response(
    db: Session,
    payload: MailGenerateDraftRequest,
    precomputed_crm_profile: dict | None = None,
) -> MailGenerateDraftResponse:
    try:
        step = get_mail_sequence_step(payload.scenario, int(payload.suite_step))
        interval = get_mail_sequence_step_interval(payload.scenario, int(payload.suite_step))
    except ValueError as exc:
        raise HTTPException(status_code=422, detail=str(exc)) from exc

    min_score = _mail_fewshot_min_score()
    fewshot_examples = _mail_generate_draft_fewshot_candidates(
        db,
        scenario=payload.scenario,
        suite_step=int(payload.suite_step),
        function_fragments=tuple(step.recommended_snippet_types),
        min_score=min_score,
        limit=3,
    )
    fewshot = fewshot_examples[0] if fewshot_examples else None
    commercial_terms = _resolve_mail_commercial_terms(db, suite_step=int(payload.suite_step))
    sequence_template = _get_mail_sequence_template_for_prompt(
        db,
        payload.scenario,
        int(payload.suite_step),
        customer_key=payload.customer_key,
    )
    if not sequence_template or not sanitize_text(sequence_template.get("ai_instruction_script")).strip():
        raise HTTPException(
            status_code=422,
            detail=f"不存在可用脚本：scenario={payload.scenario}, suite_step={int(payload.suite_step)}, template_customer_key=EMPTY",
        )
    intent_profile = _build_mail_draft_intent_profile(
        payload=payload,
        step=step,
        interval=interval,
        admitted_fewshot=fewshot,
        admitted_fewshots=fewshot_examples,
        commercial_terms=commercial_terms,
        sequence_template=sequence_template,
        precomputed_crm_profile=precomputed_crm_profile,
    )
    intent_profile.prompt_full_email_examples = _mail_full_email_gold_examples_for_prompt(
        db,
        scenario=payload.scenario,
        min_score=min_score,
        limit=5,
    )
    intent_profile.prompt_contract_case_examples = _mail_contract_case_examples_for_prompt(
        db,
        industry=_mail_generation_industry_for_prompt(intent_profile),
        limit=5,
    )
    assembled = _assemble_mail_draft_from_intent_profile(intent_profile)
    delivery_sla_guardrail = _evaluate_and_calibrate_mail_delivery_sla_guardrail(assembled.body_html)
    if delivery_sla_guardrail:
        assembled = MailDraftAssembledContent(
            subject=assembled.subject,
            body_html=delivery_sla_guardrail["calibrated_body_html"],
            llm_status=assembled.llm_status,
            llm_model_used=assembled.llm_model_used,
            llm_error=assembled.llm_error,
            llm_prompt=assembled.llm_prompt,
            review_metadata=assembled.review_metadata,
        )
    recipient_domain_confidentiality_block = _evaluate_mail_recipient_domain_confidentiality_guardrail(
        customer_key=intent_profile.customer_key,
        contact_email=intent_profile.contact_email,
        cc_emails=payload.cc_emails,
        crm_profile={
            "customer_domains": intent_profile.customer_domains,
            "company_industry": intent_profile.company_industry,
            "payment_risk_level": intent_profile.payment_risk_level,
            "crm_profile_lookup_status": intent_profile.crm_profile_lookup_status,
            "crm_profile_source": intent_profile.crm_profile_source,
        },
    )
    financial_price_floor_block = _evaluate_mail_financial_price_floor_guardrail(
        db,
        body_html=assembled.body_html,
        commercial_terms=intent_profile.commercial_terms,
    )
    payment_risk_finance_review_guardrail = _evaluate_mail_payment_risk_finance_review_guardrail(
        payment_risk_level=intent_profile.payment_risk_level,
        crm_profile_lookup_status=intent_profile.crm_profile_lookup_status,
        crm_profile_source=intent_profile.crm_profile_source,
    )
    sensitive_content_red_card_block = _evaluate_mail_sensitive_content_red_card_guardrail(
        subject=assembled.subject,
        body_html=assembled.body_html,
        commercial_terms=intent_profile.commercial_terms,
    )
    placeholder_bypass_red_card_block = _evaluate_mail_placeholder_bypass_guardrail(
        subject=assembled.subject,
        body_html=assembled.body_html,
    )
    gate_results = _build_mail_safety_gate_results(
        recipient_domain_confidentiality_block=recipient_domain_confidentiality_block,
        delivery_sla_guardrail=delivery_sla_guardrail,
        financial_price_floor_block=financial_price_floor_block,
        payment_risk_finance_review_guardrail=payment_risk_finance_review_guardrail,
        sensitive_content_red_card_block=sensitive_content_red_card_block,
        placeholder_bypass_red_card_block=placeholder_bypass_red_card_block,
    )
    overall_outcome = _mail_safety_overall_outcome(gate_results)

    warnings = [
        "仅评审草稿：当前未启用真实发件。",
        *intent_profile.commercial_terms.warnings,
        *_mail_generation_material_gap_warnings(intent_profile),
    ]
    if intent_profile.interval_delay_days > 0:
        warnings.append(
            f"邮件序列默认间隔：本步骤需等待 {intent_profile.interval_delay_days} 天后才生成。"
        )
    if delivery_sla_guardrail:
        warnings.append(
            "黄牌：交付承诺早于标准工期，"
            f"草稿正文已自动校准为 {delivery_sla_guardrail['standard_sla_label']} 并锁定审稿。"
        )
    if payment_risk_finance_review_guardrail:
        warnings.append(
            "黄牌：CRM 显示该客户欠款风险等级偏高，发件前必须经过人工财务审核。"
        )
    if recipient_domain_confidentiality_block:
        warnings.append(
            "红牌：收件人/抄送域名命中竞争对手或高敏感域名单，草稿已硬阻断，真实发件继续保持关闭。"
        )
        return MailGenerateDraftResponse(
            status="blocked_by_recipient_domain_confidentiality_gate",
            draft_status=MailSequenceStatus.BLOCKED.value,
            review_required=True,
            review_mode="red_card_recipient_domain_confidentiality_review",
            real_sending_enabled=False,
            mail_uid=f"mail_draft_{uuid.uuid4().hex[:12]}",
            final_subject=assembled.subject,
            final_body_html=assembled.body_html,
            retrieved_fewshot_id=intent_profile.admitted_fewshot_id,
            fewshot_match_score=intent_profile.admitted_fewshot_score,
            llm_status=assembled.llm_status,
            llm_model_used=assembled.llm_model_used,
            llm_error=assembled.llm_error,
            llm_prompt=assembled.llm_prompt,
            review_metadata=assembled.review_metadata,
            safety_guardrail=MailSafetyGuardrail(
                overall_outcome=overall_outcome,
                status="red_card_hard_block",
                triggered_warnings=warnings,
                is_locked_for_approval=True,
                lock_reason=(
                    "收件域名防泄密门拦截：收件人或抄送邮箱域名命中竞争对手或高敏感域，"
                    "草稿硬阻断，真实发件继续保持关闭。"
                ),
                real_sending_enabled=False,
                draft_status=MailSequenceStatus.BLOCKED.value,
                hard_block=True,
                red_card_code="blocked_by_recipient_domain_confidentiality_gate",
                blocked_by="recipient_domain_confidentiality_guardrail",
                block_details=recipient_domain_confidentiality_block,
                gate_results=gate_results,
            ),
        )
    if sensitive_content_red_card_block:
        warnings.append(
            "红牌：草稿命中敏感内容（内部底价/财务个人账户/未公开返点等），已硬阻断，真实发件继续保持关闭。"
        )
        return MailGenerateDraftResponse(
            status="blocked_by_sensitive_content_red_card_gate",
            draft_status=MailSequenceStatus.BLOCKED.value,
            review_required=True,
            review_mode="red_card_sensitive_content_review",
            real_sending_enabled=False,
            mail_uid=f"mail_draft_{uuid.uuid4().hex[:12]}",
            final_subject=assembled.subject,
            final_body_html=assembled.body_html,
            retrieved_fewshot_id=intent_profile.admitted_fewshot_id,
            fewshot_match_score=intent_profile.admitted_fewshot_score,
            llm_status=assembled.llm_status,
            llm_model_used=assembled.llm_model_used,
            llm_error=assembled.llm_error,
            llm_prompt=assembled.llm_prompt,
            review_metadata=assembled.review_metadata,
            safety_guardrail=MailSafetyGuardrail(
                overall_outcome=overall_outcome,
                status="red_card_hard_block",
                triggered_warnings=warnings,
                is_locked_for_approval=True,
                lock_reason=(
                    "敏感内容红牌门拦截：草稿中包含内部底价、财务个人账户或未公开的返点折扣，"
                    "已硬阻断，真实发件继续保持关闭。"
                ),
                real_sending_enabled=False,
                draft_status=MailSequenceStatus.BLOCKED.value,
                hard_block=True,
                red_card_code="blocked_by_sensitive_content_red_card_gate",
                blocked_by="sensitive_content_red_card_guardrail",
                block_details=sensitive_content_red_card_block,
                gate_results=gate_results,
            ),
        )
    if financial_price_floor_block:
        warnings.append("红牌：草稿中明示价格低于当前 PricingRule 底线价，已硬阻断。")
        return MailGenerateDraftResponse(
            status="blocked_by_financial_safety_gate",
            draft_status=MailSequenceStatus.BLOCKED.value,
            review_required=True,
            review_mode="red_card_financial_safety_review",
            real_sending_enabled=False,
            mail_uid=f"mail_draft_{uuid.uuid4().hex[:12]}",
            final_subject=assembled.subject,
            final_body_html=assembled.body_html,
            retrieved_fewshot_id=intent_profile.admitted_fewshot_id,
            fewshot_match_score=intent_profile.admitted_fewshot_score,
            llm_status=assembled.llm_status,
            llm_model_used=assembled.llm_model_used,
            llm_error=assembled.llm_error,
            llm_prompt=assembled.llm_prompt,
            review_metadata=assembled.review_metadata,
            safety_guardrail=MailSafetyGuardrail(
                overall_outcome=overall_outcome,
                status="red_card_hard_block",
                triggered_warnings=warnings,
                is_locked_for_approval=True,
                lock_reason=(
                    "财务价格底线门拦截：草稿中出现的明示价格低于当前生效的 PricingRule 底价，"
                    "已硬阻断，真实发件继续保持关闭。"
                ),
                real_sending_enabled=False,
                draft_status=MailSequenceStatus.BLOCKED.value,
                hard_block=True,
                red_card_code="blocked_by_financial_safety_gate",
                blocked_by="financial_price_floor_guardrail",
                block_details=financial_price_floor_block,
                gate_results=gate_results,
            ),
        )
    if placeholder_bypass_red_card_block:
        warnings.append(
            "红牌：草稿中残留未被后端替换的客户可见占位符（如 XX/xxxx@xx.com/POxxxx），"
            "已硬阻断，真实发件继续保持关闭。"
        )
        return MailGenerateDraftResponse(
            status="blocked_by_placeholder_bypass_gate",
            draft_status=MailSequenceStatus.BLOCKED.value,
            review_required=True,
            review_mode="red_card_placeholder_bypass_review",
            real_sending_enabled=False,
            mail_uid=f"mail_draft_{uuid.uuid4().hex[:12]}",
            final_subject=assembled.subject,
            final_body_html=assembled.body_html,
            retrieved_fewshot_id=intent_profile.admitted_fewshot_id,
            fewshot_match_score=intent_profile.admitted_fewshot_score,
            llm_status=assembled.llm_status,
            llm_model_used=assembled.llm_model_used,
            llm_error=assembled.llm_error,
            llm_prompt=assembled.llm_prompt,
            review_metadata=assembled.review_metadata,
            safety_guardrail=MailSafetyGuardrail(
                overall_outcome=overall_outcome,
                status="red_card_hard_block",
                triggered_warnings=warnings,
                is_locked_for_approval=True,
                lock_reason=(
                    "占位符绕过门拦截：邮件主题或正文中残留未被后端替换的客户可见占位符，"
                    "已硬阻断，真实发件继续保持关闭。"
                ),
                real_sending_enabled=False,
                draft_status=MailSequenceStatus.BLOCKED.value,
                hard_block=True,
                red_card_code="blocked_by_placeholder_bypass_gate",
                blocked_by="placeholder_bypass_guardrail",
                block_details=placeholder_bypass_red_card_block,
                gate_results=gate_results,
            ),
        )
    return MailGenerateDraftResponse(
        status="drafted",
        draft_status=MailSequenceStatus.DRAFTED.value,
        review_required=True,
        review_mode=(
            "manual_finance_review_required"
            if payment_risk_finance_review_guardrail
            else "human_review_required"
        ),
        real_sending_enabled=False,
        mail_uid=f"mail_draft_{uuid.uuid4().hex[:12]}",
        final_subject=assembled.subject,
        final_body_html=assembled.body_html,
        retrieved_fewshot_id=intent_profile.admitted_fewshot_id,
        fewshot_match_score=intent_profile.admitted_fewshot_score,
        llm_status=assembled.llm_status,
        llm_model_used=assembled.llm_model_used,
        llm_error=assembled.llm_error,
        llm_prompt=assembled.llm_prompt,
        review_metadata=assembled.review_metadata,
        safety_guardrail=MailSafetyGuardrail(
            overall_outcome=overall_outcome,
            status=(
                "yellow_card_sla_calibrated_locked"
                if delivery_sla_guardrail
                else "yellow_card_manual_finance_review_locked"
                if payment_risk_finance_review_guardrail
                else "locked_for_approval"
            ),
            triggered_warnings=warnings,
            is_locked_for_approval=True,
            lock_reason=(
                "履约工期 SLA 校准门：本草稿原本承诺的交付工期早于标准工期，已自动校准为标准工期，"
                "草稿继续锁定到人工审稿，真实发件保持关闭。"
                if delivery_sla_guardrail else
                (
                    "CRM 欠款风险等级偏高，发件前必须经过人工财务审核，"
                    "草稿保持仅评审状态，真实发件继续关闭。"
                )
                if payment_risk_finance_review_guardrail else
                "邮件草稿生成处于仅评审状态，真实发件继续保持关闭。"
            ),
            real_sending_enabled=False,
            draft_status=MailSequenceStatus.DRAFTED.value,
            block_details=delivery_sla_guardrail or payment_risk_finance_review_guardrail,
            gate_results=gate_results,
        ),
    )

