@app.put("/api/v1/system/runtime-llm-settings")
def update_runtime_llm_settings(payload: RuntimeLlmSettings):
    import os, json
    existing = _load_runtime_settings_with_defaults()
    if payload.wecom_system_prompt is not None:
        existing["wecom_system_prompt"] = payload.wecom_system_prompt
        db = SessionLocal()
        try:
            row = _get_or_create_wecom_runtime_config(db)
            row.system_prompt_llm2 = payload.wecom_system_prompt
            row.updated_by = "api/v1/system/runtime-llm-settings"
            db.commit()
        finally:
            db.close()
    if payload.wecom_temperature is not None:
        existing["wecom_temperature"] = payload.wecom_temperature
    if payload.mail_system_prompt is not None:
        existing["mail_system_prompt"] = payload.mail_system_prompt
    if payload.mail_temperature is not None:
        existing["mail_temperature"] = payload.mail_temperature
    if payload.mail_generation_model is not None:
        existing["mail_generation_model"] = _normalize_mail_generation_model(payload.mail_generation_model)

    path = os.path.join(os.path.dirname(__file__), "runtime_llm_settings.json")
    try:
        with open(path, "w", encoding="utf-8") as f:
            json.dump(existing, f, ensure_ascii=False, indent=2)
    except Exception as e:
        raise HTTPException(status_code=500, detail=f"保存 runtime_llm_settings.json 失败: {e}")
    return {"status": "success", "settings": existing}


_TRAIN_AI_MODELS_CACHE = {"at_epoch": 0.0, "items": None}
_TRAIN_AI_MODELS_CACHE_TTL_SECONDS = 300  # 5 分钟; 模型列表很少变, 没必要每次刷新都打外部接口

@app.get("/api/train_ai/models")
async def get_train_ai_models(refresh: bool = Query(default=False)):
    """训练AI 可选模型列表(供下拉选择)，并标出当前选中的模型。"""
    cfg = _train_ai_config()
    try:
        # v1.7.190: 双重保护——
        # (1) 用 asyncio.to_thread 把同步 requests.get 推到 worker 线程, 不再阻塞 FastAPI 事件循环
        #     (之前 sync 调用塞在 async handler 里, 外部 llm.cycleforce.cc 慢一点就把整服务冻住,
        #      连静态 index.html / tailwind.css 都被排队几秒到十几秒)。
        # (2) 5 分钟内存缓存, 模型列表稳定, 不该每次前端打开就外连一次。
        now_epoch = datetime.utcnow().timestamp()
        cached = _TRAIN_AI_MODELS_CACHE
        if cached["items"] is not None and (now_epoch - cached["at_epoch"]) < _TRAIN_AI_MODELS_CACHE_TTL_SECONDS:
            items = cached["items"]
        elif not refresh:
            items = [{"model_name": cfg["model"]}] if cfg.get("model") else []
        else:
            items = await asyncio.to_thread(_train_ai_list_models)
            _TRAIN_AI_MODELS_CACHE["items"] = items
            _TRAIN_AI_MODELS_CACHE["at_epoch"] = now_epoch
        return {
            "status": "success",
            "enabled": cfg["enabled"],
            "current_model": cfg["model"],
            "timeout_seconds": cfg["timeout_seconds"],
            "model_list_refreshed": bool(refresh),
            "model_list_source": "cache" if cached["items"] is not None else ("remote" if refresh else "configured"),
            "total": len(items),
            "items": items,
        }
    except Exception as exc:
        return {
            "status": "error",
            "enabled": cfg["enabled"],
            "current_model": cfg["model"],
            "timeout_seconds": cfg["timeout_seconds"],
            "total": 0,
            "items": [],
            "error": sanitize_text(str(exc))[:200],
        }


def _update_env_file_variable(key: str, value: str) -> bool:
    import os
    env_path = os.path.abspath(os.path.join(os.path.dirname(__file__), "..", ".env"))
    if not os.path.exists(env_path):
        env_path = os.path.abspath(os.path.join(os.path.dirname(__file__), ".env"))
    if not os.path.exists(env_path):
        return False
    try:
        with open(env_path, "r", encoding="utf-8") as f:
            lines = f.readlines()

        found = False
        new_lines = []
        for line in lines:
            stripped = line.strip()
            if stripped.startswith(f"{key}=") or stripped.replace(" ", "").startswith(f"{key}="):
                ending = "\r\n" if line.endswith("\r\n") else "\n"
                new_lines.append(f"{key}={value}{ending}")
                found = True
            else:
                new_lines.append(line)

        if not found:
            ending = "\r\n" if (new_lines and new_lines[-1].endswith("\r\n")) else "\n"
            if new_lines and not new_lines[-1].endswith(ending):
                new_lines.append(ending)
            new_lines.append(f"{key}={value}{ending}")

        with open(env_path, "w", encoding="utf-8") as f:
            f.writelines(new_lines)
        return True
    except Exception as e:
        import logging
        logging.error(f"Failed to update {key} in env: {e}")
        return False


@app.post("/api/train_ai/config")
async def set_train_ai_config(payload: dict = Body(...)):
    """切换训练AI 当前使用的模型(进程内与永久即时生效)。"""
    model = str((payload or {}).get("model") or "").strip()
    if not model:
        raise HTTPException(status_code=400, detail="model 不能为空")
    _TRAIN_AI_RUNTIME["model"] = model
    persisted = _update_env_file_variable("TRAIN_AI_MODEL", model)
    return {
        "status": "success",
        "current_model": _train_ai_config()["model"],
        "persisted": persisted
    }

