@app.get("/api/system/db_lock_status")
async def get_db_lock_status(db: Session = Depends(get_db)):
    """只读数据库锁/慢会话诊断；不主动终止连接。"""
    try:
        active_rows = db.execute(text("""
            SELECT pid, state, wait_event_type, wait_event,
                   EXTRACT(EPOCH FROM (now() - query_start))::int AS age_seconds,
                   left(query, 220) AS query
            FROM pg_stat_activity
            WHERE datname = current_database()
              AND state <> 'idle'
            ORDER BY query_start NULLS LAST
            LIMIT 30
        """)).mappings().all()
        blocked_rows = db.execute(text("""
            SELECT a.pid, a.state, a.wait_event_type, a.wait_event,
                   EXTRACT(EPOCH FROM (now() - a.query_start))::int AS age_seconds,
                   left(a.query, 220) AS query,
                   pg_blocking_pids(a.pid) AS blockers
            FROM pg_stat_activity a
            WHERE cardinality(pg_blocking_pids(a.pid)) > 0
            ORDER BY a.query_start NULLS LAST
            LIMIT 30
        """)).mappings().all()
        table_rows = db.execute(text("""
            SELECT relname, n_live_tup, n_dead_tup, last_autovacuum, last_autoanalyze
            FROM pg_stat_user_tables
            WHERE relname IN ('message_logs', 'api_assist_invocation', 'intent_summaries', 'case_iteration_run')
            ORDER BY relname
        """)).mappings().all()
        return {
            "status": "success",
            "active": [dict(row) for row in active_rows],
            "blocked": [dict(row) for row in blocked_rows],
            "tables": [dict(row) for row in table_rows],
            "timeouts": {
                "statement_timeout_ms": getattr(settings, "DATABASE_STATEMENT_TIMEOUT_MS", None),
                "idle_in_transaction_timeout_ms": getattr(settings, "DATABASE_IDLE_IN_TRANSACTION_TIMEOUT_MS", None),
                "lock_timeout_ms": getattr(settings, "DATABASE_LOCK_TIMEOUT_MS", None),
            },
            "auto_terminate_enabled": False,
            "note": "当前接口只诊断不杀连接；防锁死依赖 PostgreSQL session timeout 自动生效。",
        }
    except Exception as exc:
        return {"status": "error", "error": sanitize_text(str(exc))[:500]}

@app.post("/api/kb/documents/{document_id}/publish")
async def publish_kb_document(
    document_id: str,
    payload: KnowledgePublishRequest | None = None,
    db: Session = Depends(get_db),
):
    doc = db.query(KnowledgeDocument).filter(KnowledgeDocument.document_id == document_id).first()
    if not doc:
        raise HTTPException(status_code=404, detail="Knowledge document not found")
    _ensure_document_action_allowed(doc, "publish")
    _ensure_documents_approved_for_publish([doc])
    publish_payload = payload or KnowledgePublishRequest()
    publish_validation = _ensure_documents_publishable(db, [doc], force=publish_payload.force)
    gate_report = await _ensure_publish_gate(
        [doc],
        db,
        force=publish_payload.force,
        force_reason=publish_payload.force_reason,
        operator=publish_payload.operator,
    )
    doc.version_no = _next_publish_version_no(db, str(doc.document_id), doc.version_no)
    _create_version_snapshot(
        db,
        doc,
        action="publish",
        operator=publish_payload.operator,
        note=publish_payload.force_reason if publish_payload.force else None,
        version_no=doc.version_no,
    )
    updated_chunks, updated_pricing_rules = _sync_related_status(db, doc, "active", "approved")
    db.commit()
    db.refresh(doc)
    return {
        "status": "success",
        "document": _doc_to_dict(doc),
        "updated_chunks": updated_chunks,
        "updated_pricing_rules": updated_pricing_rules,
        "gate_report": gate_report,
        "publish_validation": publish_validation,
        "force_published": publish_payload.force,
    }

