@app.get("/api/v1/mail/sequence-templates")
def list_mail_sequence_templates(db: Session = Depends(get_db)):
    """返回三大邮件场景 × 4 阶段的可编辑脚本模板。"""
    # 多进程下其他 worker 改的内置场景名也能即时生效(从磁盘重载改名覆盖)
    _apply_mail_scenario_label_overrides()
    degraded_error = None
    try:
        rows = _ensure_mail_sequence_templates(db)
        rows = sorted(rows, key=lambda row: (getattr(row, "customer_key", "") or "", row.scenario, row.suite_step))
        serialized_rows = [_serialize_mail_sequence_template(row) for row in rows]
    except SQLAlchemyError as exc:
        db.rollback()
        logger.exception("MAIL_SEQUENCE_TEMPLATE_LOAD_FAILED_USE_BLANKS")
        degraded_error = sanitize_text(str(exc))[:500]
        serialized_rows, grouped_by_case = _blank_mail_sequence_templates_by_case()
    else:
        grouped_by_case = {}
        for item in serialized_rows:
            group_key = item.get("template_group_key") or item.get("customer_key") or item.get("scenario")
            grouped_by_case.setdefault(group_key, {
                "customer_key": item.get("customer_key") or "",
                "template_group_key": group_key,
                "case_label": item["case_label"],
                "scenario": item["scenario"],
                "scenario_label_cn": item["scenario_label_cn"],
                "templates": [],
            })["templates"].append(item)
    grouped: dict[str, list[dict[str, Any]]] = {}
    for item in serialized_rows:
        grouped.setdefault(item["scenario"], []).append(item)
    # 基础 4 个固定场景在前, 用户自建套装(custom_*)按出现顺序追加, 让主页下拉也能选中并编辑。
    _base_case_order = ["new_business_promotion", "re_activation", "new_contact_intro", _MAIL_PRINT_QUOTE_FOLLOWUP_SCENARIO]
    _extra_case_order = [k for k in grouped_by_case.keys() if k not in _base_case_order]
    _full_case_order = _base_case_order + sorted(_extra_case_order)
    return {
        "version": "mail_sequence_template.v1",
        "source": "mail_sequence_template",
        "read_only": False,
        "real_sending_enabled": False,
        "scenario_order": _full_case_order,
        "count": len(serialized_rows),
        "templates": grouped,
        "templates_by_case": grouped_by_case,
        "case_order": _full_case_order,
        "degraded": bool(degraded_error),
        "degraded_reason": degraded_error,
        "requirements_cn": [
            "套装邮件 4 封必须层层递进，不能 4 封重复同一套话。",
            "内容不能只局限于翻译业务，要能支持同传、多媒体本地化、排版印刷、活动物料等多业务开发。",
            "必须使用客户行业和同行业经验，避免泛泛介绍公司能力。",
            "必须使用客户历史合作或 CRM 跟进事实，不能编造。",
            "语气要亲和克制，结尾要有低压力转介绍请求。",
        ],
    }


@app.put("/api/v1/mail/sequence-templates/{scenario}/{suite_step}")
def update_mail_sequence_template(
    scenario: str,
    suite_step: int,
    payload: MailSequenceTemplateUpdateRequest,
    customer_key: str | None = Query(None),
    db: Session = Depends(get_db),
):
    """保存单个场景单个阶段的标题/AI 指令/发送间隔(可一次提交多字段)。自建套装(custom_*)同样可编辑。"""
    is_custom = scenario.startswith("custom_")
    if scenario not in _MAIL_SCENARIO_CHINESE and not is_custom:
        raise HTTPException(status_code=422, detail=f"unsupported scenario: {scenario}")
    # 自建套装可有 1..8 步; 固定场景仍限 1..4。
    if (is_custom and not (1 <= suite_step <= 8)) or (not is_custom and suite_step not in ALL_MAIL_SEQUENCE_STEPS):
        raise HTTPException(status_code=422, detail=f"unsupported suite_step: {suite_step}")
    normalized_customer_key = ""
    _ensure_mail_sequence_templates(db)
    row = db.query(MailSequenceTemplate).filter(
        MailSequenceTemplate.customer_key == normalized_customer_key,
        MailSequenceTemplate.scenario == scenario,
        MailSequenceTemplate.suite_step == suite_step,
    ).first()
    if not row:
        defaults = _default_mail_sequence_template_payload(
            scenario,
            suite_step,
            customer_key=normalized_customer_key,
        )
        row = MailSequenceTemplate(**defaults, updated_by="web_admin")
        db.add(row)
        db.flush()
    if payload.purpose_cn is not None:
        row.purpose_cn = sanitize_text(payload.purpose_cn).strip()[:4000]
    if payload.step_label_cn is not None:
        row.step_label_cn = sanitize_text(payload.step_label_cn).strip()[:120]
    if payload.send_interval_days is not None:
        send_interval_days = int(payload.send_interval_days)
        if send_interval_days < 0:
            raise HTTPException(status_code=422, detail="send_interval_days must be >= 0")
        row.send_timing_cn = str(send_interval_days)
    elif payload.send_timing_cn is not None:
        row.send_timing_cn = sanitize_text(payload.send_timing_cn).strip()[:240]
    if payload.script_template is not None:
        row.script_template = _mail_brand_display_text(sanitize_text(payload.script_template).strip())[:12000]
    if payload.ai_instruction_script is not None:
        row.ai_instruction_script = _mail_brand_display_text(sanitize_text(payload.ai_instruction_script).strip())[:12000]
    row.updated_by = sanitize_text(payload.updated_by or "web_admin")[:120]
    row.version_no = int(row.version_no or 1) + 1
    row.updated_at = datetime.utcnow()
    db.commit()
    db.refresh(row)
    return {
        "ok": True,
        "template": _serialize_mail_sequence_template(row),
        "real_sending_enabled": False,
    }


_MAIL_SUITE_OWNER_PRIORITY_STAFF_IDS = ("0017", "0002", "0141", "0188", "1607")
_MAIL_SUITE_OWNER_PRIORITY_RANK = {staff_id: idx for idx, staff_id in enumerate(_MAIL_SUITE_OWNER_PRIORITY_STAFF_IDS)}

def _fetch_mail_contact_owner_staff_id(customer_key: str) -> str:
    """只读解析客户联系人对应的销售代表工号。

    口径：联系人 Owner -> usrStaff，只取在职(DismissTime IS NULL)的销售；
    一个客户可能有多个联系人/多个 Owner 时，显式优先销售工号优先，其次有邮箱销售优先。
    查不到在职销售返回空串(不退而求其次用离职人员的签名)。
    """
    normalized_key = sanitize_text(customer_key).strip()
    if not normalized_key:
        return ""
    try:
        from crm_database import CRMSessionLocal
        crm_db = CRMSessionLocal()
        def _owner_tokens(raw_owner: str) -> list[str]:
            tokens: list[str] = []
            seen: set[str] = set()
            for token in re.split(r"[,;，、\s]+", str(raw_owner or "")):
                token = token.strip()
                if not token or token in seen:
                    continue
                seen.add(token)
                tokens.append(token)
            return tokens

        def _active_owner_with_email_score(owner: str) -> tuple[int, str] | None:
            staff_row = crm_db.execute(
                text(
                    """
                    SELECT TOP 1
                        s.StaffId,
                        ISNULL(s.Division, '') AS Division,
                        CASE WHEN EXISTS (
                            SELECT 1
                            FROM spEmailAddressBelong a
                            INNER JOIN spEmailAddress b ON a.EmailAddress = b.EmailAddress AND ISNULL(b.IsUse, 0) = 1
                            WHERE a.belongId = s.StaffId
                               OR a.BelongId IN (SELECT StructId FROM usrStaffInDivisionStruct WHERE StaffId = s.StaffId)
                        ) THEN 1 ELSE 0 END AS HasUsableEmail,
                        CASE WHEN EXISTS (
                            SELECT 1
                            FROM spEmailAddressBelong a
                            INNER JOIN spEmailAddress b ON a.EmailAddress = b.EmailAddress AND ISNULL(b.IsUse, 0) = 1
                            INNER JOIN spEmailAddressDefaultSet c ON a.EmailAddress = c.EmailAddress AND c.DefaultStaffId = s.StaffId
                            WHERE a.belongId = s.StaffId
                               OR a.BelongId IN (SELECT StructId FROM usrStaffInDivisionStruct WHERE StaffId = s.StaffId)
                        ) THEN 1 ELSE 0 END AS HasDefaultEmail
                    FROM usrStaff AS s
                    WHERE s.StaffId = :owner
                      AND s.DismissTime IS NULL
                    """
                ),
                {"owner": owner},
            ).fetchone()
            if not staff_row:
                return None
            division = str(staff_row[1] or "")
            sales_priority = 0 if any(k in division for k in ("销售", "电销", "大客户", "市场")) else 1
            has_usable_email = bool(int(staff_row[2] or 0))
            has_default_email = bool(int(staff_row[3] or 0))
            priority_rank = _MAIL_SUITE_OWNER_PRIORITY_RANK.get(owner, 99)
            if has_default_email or has_usable_email:
                group_priority = 0 if owner in _MAIL_SUITE_OWNER_PRIORITY_RANK else 1
            else:
                group_priority = 2 if owner in _MAIL_SUITE_OWNER_PRIORITY_RANK else 3
            email_priority = 0 if has_default_email else (1 if has_usable_email else 2)
            # Lower score wins: priority staff with usable/default mailbox > other staff with mailbox > no-mailbox fallback.
            return (group_priority * 1000 + priority_rank * 10 + email_priority * 2 + sales_priority, owner)

        # CRM 有些联系人 Owner 是多个工号拼接(如 "2012,0017")。这里先拆开逐个判断，
        # 只允许在职员工参与选择，并优先选择有可用/默认企业邮箱的销售代表。
        contact_rows = crm_db.execute(
            text(
                """
                SELECT TOP 10 ISNULL(CAST(c.Owner AS NVARCHAR(240)), '') AS OwnerRaw, c.ContactId
                FROM usrCustomerContact AS c
                LEFT JOIN usrCustomer AS d ON c.CustomerId = d.CustomerId AND d.Deleter IS NULL
                WHERE c.Deleter IS NULL
                  AND ISNULL(CAST(c.Owner AS NVARCHAR(240)), '') <> ''
                  AND (
                    LOWER(ISNULL(CAST(c.ContactId AS NVARCHAR(120)), '')) = :k
                    OR LOWER(ISNULL(CAST(c.NewContactId AS NVARCHAR(120)), '')) = :k
                    OR LOWER(ISNULL(CAST(c.CustomerId AS NVARCHAR(120)), '')) = :k
                    OR LOWER(ISNULL(CAST(d.NewCustomerId AS NVARCHAR(120)), '')) = :k
                    OR LOWER(ISNULL(d.CompanyName, '')) LIKE :like
                    OR LOWER(ISNULL(d.CompanyNameEnglish, '')) LIKE :like
                  )
                ORDER BY c.ContactId DESC
                """
            ),
            {"k": normalized_key.lower(), "like": f"%{normalized_key.lower()}%"},
        ).fetchall()
        scored_owners: list[tuple[int, int, str]] = []
        for row_index, contact_row in enumerate(contact_rows):
            for owner in _owner_tokens(contact_row[0] if contact_row else ""):
                scored = _active_owner_with_email_score(owner)
                if scored is not None:
                    score, staff_id = scored
                    scored_owners.append((score, row_index, staff_id))
        if scored_owners:
            scored_owners.sort(key=lambda item: (item[0], item[1]))
            return scored_owners[0][2]

        try:
            row = crm_db.execute(
                text(
                    """
                    SELECT TOP 1 s.StaffId
                    FROM usrCustomerContact AS c
                    LEFT JOIN usrCustomer AS d ON c.CustomerId = d.CustomerId AND d.Deleter IS NULL
                    INNER JOIN usrStaff AS s ON ISNULL(CAST(c.Owner AS NVARCHAR(120)), '') = s.StaffId
                    WHERE c.Deleter IS NULL
                      AND s.DismissTime IS NULL
                      AND ISNULL(CAST(c.Owner AS NVARCHAR(120)), '') <> ''
                      AND (
                        LOWER(ISNULL(CAST(c.ContactId AS NVARCHAR(120)), '')) = :k
                        OR LOWER(ISNULL(CAST(c.NewContactId AS NVARCHAR(120)), '')) = :k
                        OR LOWER(ISNULL(CAST(c.CustomerId AS NVARCHAR(120)), '')) = :k
                        OR LOWER(ISNULL(CAST(d.NewCustomerId AS NVARCHAR(120)), '')) = :k
                        OR LOWER(ISNULL(d.CompanyName, '')) LIKE :like
                        OR LOWER(ISNULL(d.CompanyNameEnglish, '')) LIKE :like
                      )
                    ORDER BY
                      (CASE WHEN ISNULL(s.Division, '') LIKE '%销售%'
                                 OR ISNULL(s.Division, '') LIKE '%电销%'
                                 OR ISNULL(s.Division, '') LIKE '%大客户%'
                                 OR ISNULL(s.Division, '') LIKE '%市场%'
                            THEN 0 ELSE 1 END),
                      c.ContactId DESC
                    """
                ),
                {"k": normalized_key.lower(), "like": f"%{normalized_key.lower()}%"},
            ).fetchone()
            return sanitize_text(row[0]).strip() if row and row[0] else ""
        finally:
            crm_db.close()
    except Exception:
        logger.exception("MAIL_SUITE_CONTACT_OWNER_LOOKUP_FAILED key=%s", sanitize_text(customer_key))
        return ""


def _fetch_mail_contact_valid_emails(customer_key: str) -> list[str]:
    """只读取客户联系人当前有效(IsCollect='正确')的邮箱清单，来自 usrCustomerContactCommunicateNo。"""
    normalized_key = sanitize_text(customer_key).strip()
    if not normalized_key:
        return []
    try:
        from crm_database import CRMSessionLocal
        crm_db = CRMSessionLocal()
        try:
            # 先用 customer-suite 一致口径定位联系人 ContactId(最近联系人)
            contact_row = crm_db.execute(
                text(
                    """
                    SELECT TOP 1 c.ContactId
                    FROM usrCustomerContact AS c
                    LEFT JOIN usrCustomer AS d ON c.CustomerId = d.CustomerId AND d.Deleter IS NULL
                    WHERE c.Deleter IS NULL
                      AND (
                        LOWER(ISNULL(CAST(c.ContactId AS NVARCHAR(120)), '')) = :k
                        OR LOWER(ISNULL(CAST(c.NewContactId AS NVARCHAR(120)), '')) = :k
                        OR LOWER(ISNULL(CAST(c.CustomerId AS NVARCHAR(120)), '')) = :k
                        OR LOWER(ISNULL(CAST(d.NewCustomerId AS NVARCHAR(120)), '')) = :k
                        OR LOWER(ISNULL(d.CompanyName, '')) LIKE :like
                        OR LOWER(ISNULL(d.CompanyNameEnglish, '')) LIKE :like
                      )
                    ORDER BY c.ContactId DESC
                    """
                ),
                {"k": normalized_key.lower(), "like": f"%{normalized_key.lower()}%"},
            ).fetchone()
            if not contact_row or not contact_row[0]:
                return []
            contact_id = contact_row[0]
            rows = crm_db.execute(
                text(
                    """
                    SELECT CommunicateNo
                    FROM usrCustomerContactCommunicateNo
                    WHERE ContactId = :cid
                      AND CommunicateType = 'ContactEmail'
                      AND ISNULL(IsCollect, '') = '正确'
                    ORDER BY InputTime DESC
                    """
                ),
                {"cid": contact_id},
            ).fetchall()
            emails: list[str] = []
            seen: set[str] = set()
            for r in rows:
                raw = str(r[0] or "").strip()
                if not raw:
                    continue
                # 跳过明显异常的拼接条目(含空格或斜杠的脏数据)
                if "/" in raw or " " in raw:
                    continue
                if "@" not in raw:
                    continue
                key = raw.lower()
                if key in seen:
                    continue
                seen.add(key)
                emails.append(raw)
            return emails
        finally:
            crm_db.close()
    except Exception:
        logger.exception("MAIL_SUITE_VALID_EMAILS_LOOKUP_FAILED key=%s", sanitize_text(customer_key))
        return []


def _mail_suite_serialize_address(email: str, present: str, *, internal_meta: dict[str, str] | None = None) -> str:
    """按 spQueueSend 的收发件人序列化格式拼装一条地址。internal_meta 提供则按内部联系人写元数据。"""
    email = str(email or "").strip()
    present = str(present or "").strip() or email
    parts = [
        '{MsgType}"Email"',
        '{Value}"' + email + '"',
    ]
    if internal_meta:
        for k in ("CustomerTableName", "CompanyName", "CustomerId", "Source", "ID"):
            v = str(internal_meta.get(k, "") or "").strip()
            if v:
                parts.append('{' + k + '}"' + v + '"')
        parts.append('{SourceType}"Internal"')
    else:
        parts.append('{SourceType}"usrInput"')
    parts.append('{Key}"' + email + '"')
    parts.append('{Present}"' + present + '"')
    return f"{present}<{email}>[" + ",".join(parts) + ",]"


def _mail_suite_serialize_receivers(recipients: list[dict[str, str]]) -> str:
    """多个收件人按 ';' 拼接(spQueueSend Receiver/Receivers 格式)。"""
    items = []
    for r in recipients:
        items.append(_mail_suite_serialize_address(r.get("email", ""), r.get("name", ""), internal_meta=r.get("meta")))
    return ";".join(items)


def _fetch_mail_sender_signature_fields(owner_staff_id: str) -> dict[str, str]:
    """只读取销售代表签名要素(分机/手机/中英文名/部门/企业邮箱)，口径对齐既有 CRM 取数逻辑。只读不写。"""
    owner = sanitize_text(owner_staff_id).strip()
    fields = {
        "staff_id": owner, "staff_name": "", "english_name": "",
        "division": "", "extend_no": "", "mobile": "", "email": "",
    }
    if not owner:
        return fields
    try:
        from crm_database import CRMSessionLocal
        crm_db = CRMSessionLocal()
        try:
            staff = crm_db.execute(
                text(
                    "SELECT TOP 1 ISNULL(StaffName,''), ISNULL(StaffEnglishName,''), "
                    "ISNULL(Division,''), ISNULL(Mobile,'') FROM usrStaff WHERE StaffId = :owner"
                ),
                {"owner": owner},
            ).fetchone()
            if staff:
                fields["staff_name"] = sanitize_text(staff[0]).strip()
                fields["english_name"] = sanitize_text(staff[1]).strip()
                fields["division"] = sanitize_text(staff[2]).strip()
                # 手机号是签名要展示的内容，不能走 sanitize_text(会被脱敏成 ***PHONE***)
                fields["mobile"] = str(staff[3] or "").strip()
            ext = crm_db.execute(
                text("SELECT TOP 1 PhoneNum FROM usrTelLinePhoneNumSet WHERE staffId = :owner"),
                {"owner": owner},
            ).fetchone()
            if ext and ext[0] is not None:
                fields["extend_no"] = str(ext[0]).strip()
            email = crm_db.execute(
                text(
                    """
                    SELECT TOP 1 a.EmailAddress
                    FROM spEmailAddressBelong a
                    INNER JOIN spEmailAddress b ON a.EmailAddress = b.EmailAddress AND ISNULL(b.IsUse, 0) = 1
                    LEFT JOIN spEmailAddressDefaultSet AS c ON a.EmailAddress = c.EmailAddress AND c.DefaultStaffId = :owner
                    WHERE a.belongId = :owner
                       OR a.BelongId IN (SELECT StructId FROM usrStaffInDivisionStruct WHERE StaffId = :owner)
                    ORDER BY (CASE WHEN c.EmailAddress IS NOT NULL THEN 1 ELSE 0 END) DESC, a.belongId, a.EmailAddress ASC
                    """
                ),
                {"owner": owner},
            ).fetchone()
            if email and email[0]:
                # 企业邮箱是签名要展示的内容，不能走 sanitize_text(会被脱敏成 ***EMAIL***)
                fields["email"] = str(email[0]).strip()
            return fields
        finally:
            crm_db.close()
    except Exception:
        logger.exception("MAIL_SUITE_SIGNATURE_FIELDS_FAILED owner=%s", owner)
        return fields


def _build_mail_sender_signature_html(fields: dict[str, str]) -> str:
    """按固定版式拼装销售代表签名(变量来自 CRM，固定内容一致)。无姓名则返回空串。"""
    # 这些字段后续都会 html.escape；此处不能用 sanitize_text，否则手机号/邮箱会被脱敏成 ***PHONE***/***EMAIL***
    name = str((fields or {}).get("staff_name") or "").strip()
    english = str((fields or {}).get("english_name") or "").strip()
    division = str((fields or {}).get("division") or "").strip()
    ext = str((fields or {}).get("extend_no") or "").strip()
    mobile = str((fields or {}).get("mobile") or "").strip()
    email = str((fields or {}).get("email") or "").strip()
    if not (name or english):
        return ""
    name_line = (name + (" " + english if english else "")).strip()
    phone_base = "+86 21 5489 6060"
    if ext:
        phone_base += "-" + ext
    phone_line = "Phone: " + phone_base + ("," + mobile if mobile else "")
    web_line = "www.speed-asia.com" + (" " + email if email else "")
    lines = [
        f"<strong>{html.escape(name_line)}</strong>",
        "",
        html.escape(division),
        "上海嘉赛科技有限公司(事必达)",
        html.escape(phone_line),
        html.escape(web_line),
        "中国上海徐汇区肇嘉浜路1065号飞雕国际大厦1409室",
    ]
    inner = "<br>".join(lines)
    return (
        '<div class="mail-signature" style="margin-top:16px;color:#004080;'
        'font-size:13px;line-height:1.7;">' + inner + "</div>"
    )


def _mail_suite_fallback_signature_html() -> str:
    lines = [
        "<strong>事必达销售</strong>",
        "",
        "事必达翻译与本地化部",
        "上海嘉赛科技有限公司(事必达)",
        "Phone: +86 21 5489 6060",
        "www.speed-asia.com",
        "中国上海徐汇区肇嘉浜路1065号飞雕国际大厦1409室",
    ]
    return (
        '<div class="mail-signature" style="margin-top:16px;color:#004080;'
        'font-size:13px;line-height:1.7;">' + "<br>".join(lines) + "</div>"
    )


def _mail_suite_signature_html_for_customer(customer_id: str) -> tuple[str, dict[str, str], str]:
    owner_staff_id = _fetch_mail_contact_owner_staff_id(customer_id)
    signature_fields = _fetch_mail_sender_signature_fields(owner_staff_id) if owner_staff_id else {}
    signature_html = _build_mail_sender_signature_html(signature_fields) if signature_fields else ""
    if not signature_html:
        signature_html = _mail_suite_fallback_signature_html()
    return signature_html, signature_fields, owner_staff_id


_MAIL_SUITE_GENERIC_SIGNOFFS = (
    "事必达国际化服务团队", "事必达销售团队", "事必达客户经理",
    "事必达国际", "事必达销售",
)


def _clean_mail_suite_body_html(body_html: str) -> str:
    """纯输出层清洗 LLM 正文(不改生成脚本): 去开头元信息行/方括号占位/通用落款/markdown/空段落。"""
    s = str(body_html or "")
    # 1) 去掉 LLM 多写的开头元信息行: 收件人/发件人/抄送/主题/公司 ：xxx
    #    正文应从问候语(如 "Feng 您好,")开始
    meta_label = r"(?:收件人|发件人|抄\s*送|主题|公司)"
    s = re.sub(r"(?is)" + meta_label + r"\s*[:：][^<]*?(?=<br\s*/?>|</p>)", "", s)
    # 去掉因此在段首残留的多余 <br>
    s = re.sub(r"(?is)<p>(?:\s*<br\s*/?>)+", "<p>", s)
    # 2) 去掉方括号占位符(如 [你的名字]/[职位]/[您的姓名])
    s = re.sub(r"\[[^\[\]\n]{1,20}\]", "", s)
    # 3) 去掉通用落款行(整段或 <br> 行)
    for generic in _MAIL_SUITE_GENERIC_SIGNOFFS:
        esc = re.escape(generic)
        s = re.sub(r"<p>\s*(?:<br\s*/?>|\s)*" + esc + r"\s*(?:<br\s*/?>|\s)*</p>", "", s)
        s = re.sub(r"(?:<br\s*/?>\s*)*" + esc + r"(?=\s*(?:<br\s*/?>|</p>|$))", "", s)
    # 4) 去掉 "事必达 | 综合国际化服务伙伴" 这类 tagline 落款行(| 或 ｜)
    s = re.sub(r"(?is)<p>\s*(?:<br\s*/?>|\s)*事必达\s*[|｜][^<]*</p>", "", s)
    s = re.sub(r"(?:<br\s*/?>\s*)*事必达\s*[|｜][^<]*?(?=\s*(?:<br\s*/?>|</p>|$))", "", s)
    # 5) 去掉残留 markdown 标记(** * --- 等)
    s = _mail_strip_markdown_artifacts(s)
    # 6) 清理空段落
    s = re.sub(r"(?is)<p>\s*(?:<br\s*/?>|&nbsp;|\s)*</p>", "", s)
    return s


def _apply_mail_suite_signature(body_html: str, signature_html: str) -> str:
    """清洗正文并幂等地换上真实销售代表签名。

    会先剥离任何已存在的 <div class="mail-signature"> 旧签名块(含历史保存的打码签名),
    再追加最新真实签名; signature_html 为空(无在职销售)时只清洗、不动已有签名。
    """
    s = _clean_mail_suite_body_html(body_html)
    if not signature_html:
        return s.rstrip()
    s = re.sub(r'(?is)<div class="mail-signature".*?</div>', "", s).rstrip()
    return s + signature_html


@app.get("/api/v1/mail/suite-scenario-options")
def get_mail_suite_scenario_options(db: Session = Depends(get_db)):
    """返回所有已注册的套装场景选项（value + 中文 label），供前端下拉动态渲染。"""
    _apply_mail_scenario_label_overrides()
    from mail_sequence_strategy import _STRATEGY_REGISTRY, _DYNAMIC_REGISTRY
    scenarios = []
    for s in list(_STRATEGY_REGISTRY) + [k for k in _DYNAMIC_REGISTRY if k not in _STRATEGY_REGISTRY]:
        label = _get_scenario_label_cn(s) or s
        scenarios.append({"value": s, "label": label})
    return {"scenarios": scenarios}


class MailCustomSuiteStepIn(BaseModel):
    label_cn: str = ""
    send_interval_days: int = 0
    ai_instruction: str = ""


class MailCustomSuiteCreateRequest(BaseModel):
    label_cn: str
    steps: list[MailCustomSuiteStepIn]


@app.post("/api/v1/mail/custom-suites")
def create_mail_custom_suite(payload: MailCustomSuiteCreateRequest, db: Session = Depends(get_db)):
    """用户自建套装：保存元数据 + 各步骤模板，并注册到运行时缓存。"""
    label = sanitize_text(payload.label_cn).strip()[:100]
    if not label:
        raise HTTPException(status_code=422, detail="label_cn 不能为空")
    step_count = max(1, min(8, len(payload.steps)))
    import time, hashlib
    scenario = "custom_" + hashlib.md5(f"{label}{time.time()}".encode()).hexdigest()[:8]
    # 检查重名
    if db.query(MailCustomSuite).filter(MailCustomSuite.label_cn == label).first():
        raise HTTPException(status_code=409, detail=f"已存在同名套装：{label}")
    row = MailCustomSuite(scenario=scenario, label_cn=label, step_count=step_count)
    db.add(row)
    db.flush()
    step_labels: dict[int, str] = {}
    for i, step in enumerate(payload.steps[:step_count], start=1):
        slabel = sanitize_text(step.label_cn).strip() or f"第 {i} 封"
        step_labels[i] = slabel
        existing = db.query(MailSequenceTemplate).filter(
            MailSequenceTemplate.scenario == scenario,
            MailSequenceTemplate.suite_step == i,
        ).first()
        if existing is None:
            tmpl = MailSequenceTemplate(
                customer_key="",
                scenario=scenario,
                suite_step=i,
                scenario_label_cn=label,
                step_label_cn=slabel,
                purpose_cn=slabel,
                send_timing_cn=str(max(0, int(step.send_interval_days or 0))),
                variable_notes="",
                script_template="",
                ai_instruction_script=sanitize_text(step.ai_instruction).strip(),
                is_active=True,
                version_no=1,
                updated_by="user_create",
            )
            db.add(tmpl)
        else:
            existing.step_label_cn = slabel
            existing.ai_instruction_script = sanitize_text(step.ai_instruction).strip()
    db.commit()
    # 注册到运行时缓存
    from mail_sequence_strategy import register_dynamic_scenario
    _DYNAMIC_SCENARIO_CHINESE[scenario] = label
    for step_no, lbl in step_labels.items():
        _DYNAMIC_STEP_LABELS[(scenario, step_no)] = lbl
    register_dynamic_scenario(scenario, label, step_count, step_labels)
    return {"scenario": scenario, "label_cn": label, "step_count": step_count}


@app.get("/api/v1/mail/custom-suites")
def list_mail_custom_suites(db: Session = Depends(get_db)):
    rows = db.query(MailCustomSuite).order_by(MailCustomSuite.created_at).all()
    return {"suites": [{"scenario": r.scenario, "label_cn": r.label_cn, "step_count": r.step_count} for r in rows]}


class MailCustomSuiteRenameRequest(BaseModel):
    label_cn: str

    class Config:
        extra = "forbid"


@app.put("/api/v1/mail/custom-suites/{scenario}")
def rename_mail_custom_suite(scenario: str, payload: MailCustomSuiteRenameRequest, db: Session = Depends(get_db)):
    """重命名套装(只改中文显示名; scenario 代码不变, 故生成流程/已存草稿都不受影响)。

    支持两类:
    - 自建套装(custom_*): 改 MailCustomSuite.label_cn + 模板行 + 动态注册。
    - 内置老场景(re_activation 等): 改名持久化到 runtime_llm_settings.json 并热更内存中文名, 不影响 scenario 代码与生成逻辑。
    """
    scenario = (scenario or "").strip()
    label = sanitize_text(payload.label_cn).strip()[:100]
    if not label:
        raise HTTPException(status_code=422, detail="label_cn 不能为空")
    # 内置老场景改名: 仅改显示名, 不动 scenario 代码、不改步骤数、不影响生成
    if not scenario.startswith("custom_"):
        if scenario not in _MAIL_SCENARIO_CHINESE:
            raise HTTPException(status_code=404, detail=f"场景不存在: {scenario}")
        _MAIL_SCENARIO_CHINESE[scenario] = label
        try:
            _save_mail_scenario_label_override(scenario, label)
        except Exception as exc:
            raise HTTPException(status_code=500, detail=f"保存改名失败: {exc}")
        # 同步各阶段模板行的场景中文名, 让模板/下拉显示新名
        for t in db.query(MailSequenceTemplate).filter(MailSequenceTemplate.scenario == scenario).all():
            t.scenario_label_cn = label
        db.commit()
        return {"ok": True, "scenario": scenario, "label_cn": label, "kind": "builtin"}
    row = db.query(MailCustomSuite).filter(MailCustomSuite.scenario == scenario).first()
    if row is None:
        raise HTTPException(status_code=404, detail=f"套装不存在: {scenario}")
    dup = db.query(MailCustomSuite).filter(
        MailCustomSuite.label_cn == label, MailCustomSuite.scenario != scenario
    ).first()
    if dup is not None:
        raise HTTPException(status_code=409, detail=f"已存在同名套装：{label}")
    row.label_cn = label
    # 同步各阶段模板的场景中文名, 让模板/下拉显示新名
    for t in db.query(MailSequenceTemplate).filter(MailSequenceTemplate.scenario == scenario).all():
        t.scenario_label_cn = label
    db.commit()
    # 刷新运行时缓存(中文名 + 动态策略 objective)
    _DYNAMIC_SCENARIO_CHINESE[scenario] = label
    try:
        from mail_sequence_strategy import register_dynamic_scenario
        step_labels = {
            int(t.suite_step): (t.step_label_cn or "").strip()
            for t in db.query(MailSequenceTemplate).filter(MailSequenceTemplate.scenario == scenario).all()
            if (t.step_label_cn or "").strip()
        }
        register_dynamic_scenario(scenario, label, int(row.step_count or len(step_labels) or 4), step_labels)
    except Exception:
        logger.warning("MAIL_CUSTOM_SUITE_RENAME_REGISTER_FAILED scenario=%s", scenario, exc_info=True)
    return {"ok": True, "scenario": scenario, "label_cn": label}



def _build_mail_customer_suite_prompt_only(
    db: Session,
    *,
    payload: MailGenerateDraftRequest,
    precomputed_crm_profile: dict | None = None,
) -> str:
    """Assemble the current LLM prompt without calling the model or changing the saved body."""
    try:
        step = get_mail_sequence_step(payload.scenario, int(payload.suite_step))
        interval = get_mail_sequence_step_interval(payload.scenario, int(payload.suite_step))
    except ValueError as exc:
        raise HTTPException(status_code=422, detail=str(exc)) from exc
    min_score = _mail_fewshot_min_score()
    fewshot_examples = _mail_generate_draft_fewshot_candidates(
        db,
        scenario=payload.scenario,
        suite_step=int(payload.suite_step),
        function_fragments=tuple(step.recommended_snippet_types),
        min_score=min_score,
        limit=3,
    )
    fewshot = fewshot_examples[0] if fewshot_examples else None
    commercial_terms = _resolve_mail_commercial_terms(db, suite_step=int(payload.suite_step))
    sequence_template = _get_mail_sequence_template_for_prompt(
        db,
        payload.scenario,
        int(payload.suite_step),
        customer_key=payload.customer_key,
    )
    if not sequence_template or not sanitize_text(sequence_template.get("ai_instruction_script")).strip():
        raise HTTPException(
            status_code=422,
            detail=f"不存在可用脚本：scenario={payload.scenario}, suite_step={int(payload.suite_step)}, template_customer_key=EMPTY",
        )
    intent_profile = _build_mail_draft_intent_profile(
        payload=payload,
        step=step,
        interval=interval,
        admitted_fewshot=fewshot,
        admitted_fewshots=fewshot_examples,
        commercial_terms=commercial_terms,
        sequence_template=sequence_template,
        precomputed_crm_profile=precomputed_crm_profile,
    )
    intent_profile.prompt_full_email_examples = _mail_full_email_gold_examples_for_prompt(
        db,
        scenario=payload.scenario,
        min_score=min_score,
        limit=5,
    )
    return _mail_brand_display_text(_build_mail_draft_llm_full_prompt(intent_profile))

@app.get("/api/v1/mail/customer-suite")
def get_mail_customer_suite(
    request: Request,
    id: str = Query(..., min_length=1),
    scenario: str | None = Query(None),
    step: int | None = Query(None),
    test: bool = Query(False),
    db: Session = Depends(get_db),
):
    """独立客户套装邮件页数据源：按客户编号真生成套装草稿。

    test=1: 测试模式 — 忽略已保存草稿强制重新调大模型(用于测脚本调整后的真实效果)，且不写库。
    step=N: 只生成第 N 封(测试单封时用)；缺省时按场景实际封数全部生成。
    """
    customer_id = sanitize_text(id).strip()
    if not customer_id:
        raise HTTPException(status_code=422, detail="id is required")
    test_mode = bool(test)
    only_step = int(step) if step is not None else None
    accept = (request.headers.get("accept") or "").lower()
    if "text/html" in accept and "application/json" not in accept:
        return RedirectResponse(url=f"/static/mail-suite.html?id={quote(customer_id, safe='')}")

    seller_name = "事必达销售"
    seller_signature = "事必达销售"
    crm_profile = _lookup_mail_crm_profile(customer_id, "")
    lifecycle_stage = sanitize_text(crm_profile.get("customer_lifecycle_stage"))

    # 场景判定: 手动指定(下拉/URL)优先; 否则按 CRM 生命周期阶段真实判断
    explicit_scenario = sanitize_text(scenario or "").strip()
    if explicit_scenario:
        scenario_norm = explicit_scenario
        scenario_basis = "手动指定场景"
    else:
        scenario_norm, scenario_basis = _mail_scenario_from_lifecycle_stage(lifecycle_stage)
    if not _is_supported_scenario(scenario_norm):
        raise HTTPException(status_code=422, detail=f"unsupported scenario: {scenario_norm}")
    contact_email = sanitize_text(crm_profile.get("contact_email"))
    contact_name = sanitize_text(crm_profile.get("contact_name"))
    draft_contact_email = _mail_demo_contact_email_for_draft(contact_email)
    draft_contact_email_is_placeholder = False
    if not draft_contact_email:
        draft_contact_email = _mail_review_only_draft_contact_email(customer_id, crm_profile)
        draft_contact_email_is_placeholder = bool(draft_contact_email)
    # 构造供 4 个生成线程复用的 CRM 画像，避免每线程重复查 CRM SQL Server
    _contact_domain_for_shared = _normalize_mail_recipient_domain(draft_contact_email)
    if _contact_domain_for_shared:
        _shared_domains = set(crm_profile.get("customer_domains") or ())
        _shared_domains.add(_contact_domain_for_shared)
        shared_crm_profile = {**crm_profile, "customer_domains": tuple(sorted(_shared_domains))}
    else:
        shared_crm_profile = crm_profile
    customer_profile = {
        "customer_id": customer_id,
        "company_name": sanitize_text(crm_profile.get("company_name")) or customer_id,
        "crm_contact_name": contact_name,
        "contact_name": contact_name,
        "contact_email": contact_email,
        "contact_email_note": (
            "CRM 邮箱在接口展示层保持脱敏；本页只生成草稿模板，不真实发信。"
            if draft_contact_email_is_placeholder
            else "CRM 邮箱为空时保持空值；本页只生成草稿模板，不真实发信。"
        ),
        "draft_contact_email_mode": "review_only_placeholder" if draft_contact_email_is_placeholder else "crm_email",
        "company_industry": crm_profile.get("company_industry"),
        "customer_lifecycle_stage": crm_profile.get("customer_lifecycle_stage"),
        "customer_tier": crm_profile.get("customer_tier"),
        "payment_risk_level": crm_profile.get("payment_risk_level"),
        "existing_business_lines": crm_profile.get("existing_business_lines") or [],
        "customer_domains": list(crm_profile.get("customer_domains") or []),
        "crm_profile_lookup_status": crm_profile.get("crm_profile_lookup_status"),
        "crm_profile_source": crm_profile.get("crm_profile_source"),
        "scenario_label_cn": _MAIL_SCENARIO_CHINESE.get(scenario_norm, scenario_norm),
        "seller_name": seller_name,
    }

    # 测试模式不读已保存草稿: 始终重跑大模型, 反映脚本最新改动
    saved_edits = {} if test_mode else {
        int(r.suite_step): {
            "subject": r.subject,
            "body_html": r.body_html,
            "llm_prompt": r.llm_prompt,
            "mail_uid": r.mail_uid,
            "included": r.included,
            "send_interval_days": r.send_interval_days,
            "send_time": r.send_time,
        }
        for r in db.query(MailCustomerSuiteDraftEdit)
        .filter(
            MailCustomerSuiteDraftEdit.customer_id == customer_id,
            MailCustomerSuiteDraftEdit.scenario == scenario_norm,
        )
        .all()
    }

    def _suite_step_send_settings(step: int, saved) -> dict[str, Any]:
        default_interval, default_send_time = _mail_suite_default_send_interval_time(scenario_norm, int(step))
        if saved is not None and saved.get("send_interval_days") is not None:
            interval = int(saved["send_interval_days"])
        else:
            interval = default_interval
        send_time = saved.get("send_time") if (saved is not None and saved.get("send_time")) else default_send_time
        included = bool(saved.get("included")) if saved is not None else True
        return {
            "send_interval_days": interval,
            "default_send_interval_days": default_interval,
            "send_time": send_time,
            "default_send_time": default_send_time,
            "included": included,
        }

    # owner 查询与 valid_emails 查询互相独立，并发执行省一次 CRM 往返
    with ThreadPoolExecutor(max_workers=2, thread_name_prefix="mail-suite-pre") as _pre_ex:
        _owner_fut = _pre_ex.submit(_fetch_mail_contact_owner_staff_id, customer_id)
        _valid_emails_fut = _pre_ex.submit(_fetch_mail_contact_valid_emails, customer_id)
        owner_staff_id = _owner_fut.result()
        valid_emails = _valid_emails_fut.result()
    signature_html, signature_fields, _owner_staff_id_for_signature = _mail_suite_signature_html_for_customer(customer_id)
    # 发件邮箱不能走 sanitize_text(会被脱敏成 ***EMAIL***)
    sender_email = str((signature_fields or {}).get("email") or "").strip()
    sender_name = str((signature_fields or {}).get("english_name") or "").strip() or str((signature_fields or {}).get("staff_name") or "").strip()

    # 客户收件邮箱：人工覆盖优先，否则取 CRM 当前有效邮箱(IsCollect='正确')
    recipient_row = (
        db.query(MailCustomerSuiteRecipient)
        .filter(
            MailCustomerSuiteRecipient.customer_id == customer_id,
            MailCustomerSuiteRecipient.scenario == scenario_norm,
        )
        .one_or_none()
    )
    if recipient_row is not None and (recipient_row.emails or "").strip():
        recipient_emails = [e.strip() for e in re.split(r"[,;\s]+", recipient_row.emails) if e.strip()]
        recipient_emails_source = "manual_override"
    else:
        recipient_emails = valid_emails
        recipient_emails_source = "crm_valid_emails"

    def _generate_one_suite_draft(suite_step: int) -> dict[str, Any]:
        """生成单封套装草稿。供线程池并发调用，每个线程使用独立 DB Session(Session 非线程安全)。"""
        saved = saved_edits.get(int(suite_step))
        payload = MailGenerateDraftRequest(
            customer_key=customer_id,
            contact_email=draft_contact_email,
            scenario=scenario_norm,
            suite_step=int(suite_step),
            current_seller_name=seller_name,
            current_seller_signature=seller_signature,
        )
        try:
            if saved is not None and saved.get("subject") and saved.get("body_html"):
                saved_prompt = saved.get("llm_prompt") or ""
                if not saved_prompt:
                    # 历史保存稿没有 llm_prompt 时，只回填脚本，不重跑 LLM、不覆盖正文。
                    try:
                        prompt_db = SessionLocal()
                        try:
                            saved_prompt = _build_mail_customer_suite_prompt_only(
                                prompt_db,
                                payload=payload,
                                precomputed_crm_profile=shared_crm_profile,
                            )[:20000]
                            prompt_row = (
                                prompt_db.query(MailCustomerSuiteDraftEdit)
                                .filter(
                                    MailCustomerSuiteDraftEdit.customer_id == customer_id,
                                    MailCustomerSuiteDraftEdit.scenario == scenario_norm,
                                    MailCustomerSuiteDraftEdit.suite_step == int(suite_step),
                                )
                                .one_or_none()
                            )
                            if prompt_row is not None:
                                prompt_row.llm_prompt = saved_prompt or None
                                prompt_db.commit()
                        finally:
                            prompt_db.close()
                    except Exception:
                        logger.exception(
                            "MAIL_SUITE_SAVED_PROMPT_BACKFILL_FAILED customer_id=%s step=%s",
                            sanitize_text(customer_id),
                            suite_step,
                        )
                # 已保存过(主题+正文齐全)：直接读取，不再调大模型重生成
                draft = {
                    "final_subject": saved["subject"],
                    "final_body_html": saved["body_html"],
                    "mail_uid": saved.get("mail_uid") or "",
                    "llm_status": "saved_edit",
                    "llm_model_used": "",
                    "llm_prompt": saved_prompt,
                    "from_saved_edit": True,
                }
            else:
                # 并发生成: 每封用独立 Session, 避免与主请求 db 及其他线程共享 Session
                thread_db = SessionLocal()
                try:
                    response = _build_mail_generate_draft_response(thread_db, payload, precomputed_crm_profile=shared_crm_profile)
                finally:
                    thread_db.close()
                draft = response.dict() if hasattr(response, "dict") else dict(response)
                if saved is not None:
                    if saved.get("subject"):
                        draft["final_subject"] = saved["subject"]
                    if saved.get("body_html"):
                        draft["final_body_html"] = saved["body_html"]
            # 始终清洗正文 + 幂等重注入真实签名: 保存过的旧正文/历史打码签名也会被纠正
            draft["final_body_html"] = _apply_mail_suite_signature(
                draft.get("final_body_html") or "", signature_html
            )
            return {
                "suite_step": int(suite_step),
                "step_label_cn": _mail_sequence_step_label_cn(scenario_norm, int(suite_step)),
                "status": "success",
                "draft": draft,
                "send_settings": _suite_step_send_settings(int(suite_step), saved),
            }
        except HTTPException as exc:
            return {
                "suite_step": int(suite_step),
                "step_label_cn": _mail_sequence_step_label_cn(scenario_norm, int(suite_step)),
                "status": "failed",
                "error": exc.detail,
                "draft": None,
                "send_settings": _suite_step_send_settings(int(suite_step), saved),
            }
        except Exception as exc:
            logger.exception("MAIL_CUSTOMER_SUITE_DRAFT_FAILED customer_id=%s suite_step=%s", sanitize_text(customer_id), suite_step)
            return {
                "suite_step": int(suite_step),
                "step_label_cn": _mail_sequence_step_label_cn(scenario_norm, int(suite_step)),
                "status": "failed",
                "error": sanitize_text(str(exc))[:500],
                "draft": None,
                "send_settings": _suite_step_send_settings(int(suite_step), saved),
            }

    # 4 封相互独立, 并发生成: 墙钟时间由"4×单封"降到"≈1×单封"; ex.map 保持原有步序; timeout=90s 防 LLM 挂死
    # 用户自建套装按其实际封数生成，内置场景固定 4 封
    from mail_sequence_strategy import get_dynamic_scenario_step_count
    _custom_step_count = get_dynamic_scenario_step_count(scenario_norm)
    suite_steps = list(range(1, _custom_step_count + 1)) if _custom_step_count else list(ALL_MAIL_SEQUENCE_STEPS)
    # 测试单封: 只生成指定的那一封
    if only_step is not None and only_step in suite_steps:
        suite_steps = [only_step]
    # 全部命中缓存时跳过模板预热（无 LLM 调用，不会触发并发 DDL 锁），节省 10-20 次 DB 查询
    _all_cached = all(
        saved_edits.get(int(s), {}).get("subject") and saved_edits.get(int(s), {}).get("body_html")
        for s in suite_steps
    )
    if not _all_cached:
        # 并发前先在主线程预热模板(建表/补列 DDL + 默认模板播种)一次, 串行完成:
        # 避免 4 个并发线程各自触发同一句 DDL 互相抢表锁导致 LockNotAvailable(锁超时)。
        try:
            _ensure_mail_sequence_templates(db)
        except Exception:
            logger.exception("MAIL_CUSTOMER_SUITE_TEMPLATE_PREWARM_FAILED customer_id=%s", sanitize_text(customer_id))
    try:
        with ThreadPoolExecutor(max_workers=max(1, len(suite_steps)), thread_name_prefix="mail-suite") as executor:
            drafts = list(executor.map(_generate_one_suite_draft, suite_steps, timeout=90))
    except Exception as _exc:
        if "TimeoutError" not in type(_exc).__name__:
            raise
        logger.error("MAIL_CUSTOMER_SUITE_TIMEOUT customer_id=%s scenario=%s", sanitize_text(customer_id), scenario_norm)
        drafts = [
            {
                "suite_step": s,
                "step_label_cn": _mail_sequence_step_label_cn(scenario_norm, int(s)),
                "status": "failed",
                "error": "生成超时（>90s），请重试",
                "draft": None,
                "send_settings": _suite_step_send_settings(int(s), saved_edits.get(int(s))),
            }
            for s in suite_steps
        ]

    # LLM 生成成功后自动存库 — 下次加载(含 Ctrl+F5)直接读库，不再重调 LLM
    # 测试模式不写库: 纯展示, 不污染该客户已保存草稿
    for _item in (drafts if not test_mode else []):
        if _item.get("status") != "success":
            continue
        _d = _item.get("draft") or {}
        if _d.get("from_saved_edit"):
            continue
        _subj = (_d.get("final_subject") or "")[:500]
        _html = _d.get("final_body_html") or ""
        _uid = (_d.get("mail_uid") or "")[:120]
        _step = int(_item.get("suite_step", 0))
        if not _subj or not _html or _step not in ALL_MAIL_SEQUENCE_STEPS:
            continue
        try:
            _row = (
                db.query(MailCustomerSuiteDraftEdit)
                .filter(
                    MailCustomerSuiteDraftEdit.customer_id == customer_id,
                    MailCustomerSuiteDraftEdit.scenario == scenario_norm,
                    MailCustomerSuiteDraftEdit.suite_step == _step,
                )
                .one_or_none()
            )
            if _row is None:
                _row = MailCustomerSuiteDraftEdit(
                    customer_id=customer_id[:120],
                    scenario=scenario_norm,
                    suite_step=_step,
                    included=True,
                )
                db.add(_row)
            _row.subject = _subj
            _row.body_html = _html
            _row.llm_prompt = (_d.get("llm_prompt") or "")[:20000] or None
            if _uid:
                _row.mail_uid = _uid
            db.flush()
        except Exception:
            logger.exception("MAIL_SUITE_AUTOSAVE_FAILED customer_id=%s step=%s", sanitize_text(customer_id), _step)
    try:
        db.commit()
    except Exception:
        logger.exception("MAIL_SUITE_AUTOSAVE_COMMIT_FAILED customer_id=%s", sanitize_text(customer_id))
        db.rollback()

    return {
        "status": "success" if any(item["status"] == "success" for item in drafts) else "failed",
        "source": "crm_sql_customer_suite_id",
        "customer_id": customer_id,
        "scenario": scenario_norm,
        "scenario_label_cn": _MAIL_SCENARIO_CHINESE.get(scenario_norm, scenario_norm),
        "scenario_basis": scenario_basis,
        "customer_lifecycle_stage": lifecycle_stage or "未识别",
        "customer_profile": customer_profile,
        "drafts": drafts,
        "suite_total": len(drafts),
        "sender_email": sender_email,
        "sender_name": sender_name,
        "recipient_emails": recipient_emails,
        "recipient_emails_source": recipient_emails_source,
        "crm_valid_emails": valid_emails,
        "real_sending_enabled": False,
        "note": "套装页只生成草稿和保存反馈，不真实发送邮件。",
    }


def _normalize_suite_send_time(value: str | None) -> str | None:
    text_value = sanitize_text(value or "").strip()
    if not text_value:
        return None
    parts = text_value.split(":")
    if len(parts) != 2:
        raise HTTPException(status_code=422, detail="send_time 必须是 HH:MM 格式")
    try:
        hour = int(parts[0])
        minute = int(parts[1])
    except ValueError as exc:
        raise HTTPException(status_code=422, detail="send_time 必须是 HH:MM 格式") from exc
    if not (0 <= hour <= 23 and 0 <= minute <= 59):
        raise HTTPException(status_code=422, detail="send_time 超出有效范围")
    return f"{hour:02d}:{minute:02d}"


@app.post("/api/v1/mail/customer-suite-draft")
def upsert_mail_customer_suite_draft(
    payload: MailCustomerSuiteDraftEditRequest,
    db: Session = Depends(get_db),
):
    """套装页逐封草稿编辑保存：按 客户编号+场景+第N封 upsert 覆盖，支持部分字段更新。"""
    customer_id = sanitize_text(payload.customer_id).strip()
    scenario = sanitize_text(payload.scenario).strip()
    if not customer_id:
        raise HTTPException(status_code=422, detail="customer_id is required")
    if not _is_supported_scenario(scenario):
        raise HTTPException(status_code=422, detail=f"unsupported scenario: {scenario}")
    if not _is_valid_suite_step(scenario, payload.suite_step):
        raise HTTPException(status_code=422, detail=f"unsupported suite_step: {payload.suite_step}")
    if payload.send_interval_days is not None and int(payload.send_interval_days) < 0:
        raise HTTPException(status_code=422, detail="send_interval_days must be >= 0")

    row = (
        db.query(MailCustomerSuiteDraftEdit)
        .filter(
            MailCustomerSuiteDraftEdit.customer_id == customer_id,
            MailCustomerSuiteDraftEdit.scenario == scenario,
            MailCustomerSuiteDraftEdit.suite_step == int(payload.suite_step),
        )
        .one_or_none()
    )
    created = False
    if row is None:
        row = MailCustomerSuiteDraftEdit(
            customer_id=customer_id[:120],
            scenario=scenario,
            suite_step=int(payload.suite_step),
            included=True,
        )
        db.add(row)
        created = True

    if payload.mail_uid is not None:
        row.mail_uid = sanitize_text(payload.mail_uid).strip()[:120] or None
    if payload.subject is not None:
        row.subject = sanitize_text(payload.subject).strip()[:500] or None
    if payload.body_html is not None:
        row.body_html = sanitize_text(payload.body_html).strip() or None
    if payload.send_interval_days is not None:
        row.send_interval_days = int(payload.send_interval_days)
    if payload.send_time is not None:
        row.send_time = _normalize_suite_send_time(payload.send_time)
    if payload.included is not None:
        row.included = bool(payload.included)
    if payload.llm_prompt is not None:
        row.llm_prompt = sanitize_text(payload.llm_prompt).strip()[:20000] or None

    db.commit()
    db.refresh(row)
    return {
        "ok": True,
        "created": created,
        "draft_edit_id": str(row.draft_edit_id),
        "record": _serialize_mail_customer_suite_draft_edit(row),
        "real_sending_enabled": False,
    }


@app.post("/api/v1/mail/customer-suite-draft/regenerate")
def regenerate_mail_customer_suite_draft(
    payload: MailCustomerSuiteDraftRegenerateRequest,
    db: Session = Depends(get_db),
):
    """强制单封套装邮件重新跑真实生成链路，并覆盖该封已保存稿。"""
    customer_id = sanitize_text(payload.customer_id).strip()
    scenario = sanitize_text(payload.scenario).strip()
    suite_step = int(payload.suite_step or 0)
    if not customer_id:
        raise HTTPException(status_code=422, detail="customer_id is required")
    if not _is_supported_scenario(scenario):
        raise HTTPException(status_code=422, detail=f"unsupported scenario: {scenario}")
    if not _is_valid_suite_step(scenario, suite_step):
        raise HTTPException(status_code=422, detail=f"unsupported suite_step: {suite_step}")

    crm_profile = _lookup_mail_crm_profile(customer_id, "")
    contact_email = sanitize_text(crm_profile.get("contact_email"))
    draft_contact_email = _mail_demo_contact_email_for_draft(contact_email) or _mail_review_only_draft_contact_email(customer_id, crm_profile)
    contact_domain = _normalize_mail_recipient_domain(draft_contact_email)
    if contact_domain:
        shared_domains = set(crm_profile.get("customer_domains") or ())
        shared_domains.add(contact_domain)
        crm_profile = {**crm_profile, "customer_domains": tuple(sorted(shared_domains))}

    request_payload = MailGenerateDraftRequest(
        customer_key=customer_id,
        contact_email=draft_contact_email,
        scenario=scenario,
        suite_step=suite_step,
        current_seller_name="事必达销售",
        current_seller_signature="事必达销售",
    )
    response = _build_mail_generate_draft_response(db, request_payload, precomputed_crm_profile=crm_profile)
    draft = response.model_dump() if hasattr(response, "model_dump") else response.dict()
    signature_html, _signature_fields, _owner_staff_id = _mail_suite_signature_html_for_customer(customer_id)
    draft["final_body_html"] = _apply_mail_suite_signature(draft.get("final_body_html") or "", signature_html)
    row = (
        db.query(MailCustomerSuiteDraftEdit)
        .filter(
            MailCustomerSuiteDraftEdit.customer_id == customer_id,
            MailCustomerSuiteDraftEdit.scenario == scenario,
            MailCustomerSuiteDraftEdit.suite_step == suite_step,
        )
        .one_or_none()
    )
    created = False
    if row is None:
        row = MailCustomerSuiteDraftEdit(
            customer_id=customer_id[:120],
            scenario=scenario,
            suite_step=suite_step,
            included=True,
        )
        db.add(row)
        created = True
    row.subject = (draft.get("final_subject") or "")[:500] or None
    row.body_html = draft.get("final_body_html") or None
    row.mail_uid = (draft.get("mail_uid") or "")[:120] or None
    row.llm_prompt = (draft.get("llm_prompt") or "")[:20000] or None
    db.commit()
    db.refresh(row)

    default_interval = _mail_sequence_default_send_interval_days(scenario, suite_step)
    send_settings = {
        "send_interval_days": int(row.send_interval_days) if row.send_interval_days is not None else default_interval,
        "default_send_interval_days": default_interval,
        "send_time": row.send_time or _MAIL_SUITE_DEFAULT_SEND_TIME,
        "default_send_time": _MAIL_SUITE_DEFAULT_SEND_TIME,
        "included": bool(row.included),
    }
    return {
        "ok": True,
        "created": created,
        "item": {
            "suite_step": suite_step,
            "step_label_cn": _mail_sequence_step_label_cn(scenario, suite_step),
            "status": "success",
            "draft": draft,
            "send_settings": send_settings,
        },
        "record": _serialize_mail_customer_suite_draft_edit(row),
        "real_sending_enabled": False,
    }

@app.post("/api/v1/mail/customer-suite-recipient")
def upsert_mail_customer_suite_recipient(
    payload: MailCustomerSuiteRecipientRequest,
    db: Session = Depends(get_db),
):
    """保存套装页人工编辑后的客户收件邮箱(按 客户编号+场景 upsert)。"""
    customer_id = sanitize_text(payload.customer_id).strip()
    scenario = sanitize_text(payload.scenario).strip()
    if not customer_id:
        raise HTTPException(status_code=422, detail="customer_id is required")
    if not _is_supported_scenario(scenario):
        raise HTTPException(status_code=422, detail=f"unsupported scenario: {scenario}")
    # 邮箱不能走 sanitize_text(会被脱敏成 ***EMAIL***)；这里是收件人地址，原样解析
    raw = str(payload.emails or "")
    emails = [e.strip() for e in re.split(r"[,;\s]+", raw) if e.strip() and "@" in e]
    normalized = ",".join(emails)
    row = (
        db.query(MailCustomerSuiteRecipient)
        .filter(
            MailCustomerSuiteRecipient.customer_id == customer_id,
            MailCustomerSuiteRecipient.scenario == scenario,
        )
        .one_or_none()
    )
    created = False
    if row is None:
        row = MailCustomerSuiteRecipient(customer_id=customer_id[:120], scenario=scenario)
        db.add(row)
        created = True
    row.emails = normalized or None
    db.commit()
    return {"ok": True, "created": created, "emails": emails}


def _mail_suite_html_to_text(html_value: str) -> str:
    s = str(html_value or "")
    s = re.sub(r"(?is)<br\s*/?>", "\n", s)
    s = re.sub(r"(?is)</p>", "\n\n", s)
    s = re.sub(r"(?is)<[^>]+>", "", s)
    s = (s.replace("&nbsp;", " ").replace("&amp;", "&")
           .replace("&lt;", "<").replace("&gt;", ">").replace("&quot;", '"'))
    s = re.sub(r"\n{3,}", "\n\n", s)
    return s.strip()


def _build_mail_eml_bytes(
    sender_email: str,
    sender_name: str,
    to_emails: list[str],
    subject: str,
    body_html: str,
    attachments: list[dict[str, Any]] | None = None,
) -> bytes:
    """生成标准 UTF-8 .eml，供 SFTP 上传后由发送系统投递。

    无附件时保持 multipart/alternative；有附件或内嵌图片时使用 multipart/mixed。
    主题、正文、附件文件名全部使用 UTF-8，避免旧 gbk/eucgb2312_cn 邮件头兼容问题。
    """
    import base64 as _base64
    import email.charset as _ec
    import mimetypes as _mimetypes
    import re as _re
    from email import encoders as _encoders
    from email.header import Header
    from email.mime.base import MIMEBase
    from email.mime.image import MIMEImage
    from email.mime.multipart import MIMEMultipart
    from email.mime.nonmultipart import MIMENonMultipart
    from email.utils import formatdate, make_msgid

    def _safe_filename(name: str, fallback: str) -> str:
        value = str(name or "").replace("\\", "_").replace("/", "_").strip().strip(".")
        value = _re.sub(r"[\r\n\x00-\x1f]+", "_", value)
        return (value or fallback)[:160]

    def _decode_upload(item: dict[str, Any], fallback_name: str) -> dict[str, Any] | None:
        if not isinstance(item, dict):
            return None
        raw_data = str(item.get("data") or item.get("base64") or "")
        if not raw_data:
            return None
        content_type = str(item.get("content_type") or item.get("type") or "").strip()
        if raw_data.startswith("data:"):
            meta, _, payload = raw_data.partition(",")
            raw_data = payload
            if not content_type:
                content_type = meta[5:].split(";", 1)[0]
        try:
            payload_bytes = _base64.b64decode(raw_data, validate=True)
        except Exception:
            return None
        if not payload_bytes:
            return None
        filename = _safe_filename(str(item.get("filename") or item.get("name") or ""), fallback_name)
        if not content_type:
            content_type = _mimetypes.guess_type(filename)[0] or "application/octet-stream"
        disposition = str(item.get("disposition") or "attachment").strip().lower()
        if disposition not in {"attachment", "inline"}:
            disposition = "attachment"
        cid = str(item.get("cid") or "").strip().strip("<>")
        return {
            "filename": filename,
            "content_type": content_type,
            "payload": payload_bytes,
            "disposition": disposition,
            "cid": cid,
        }

    def _extract_inline_data_images(html: str) -> tuple[str, list[dict[str, Any]]]:
        inline_images: list[dict[str, Any]] = []

        def _replace(match) -> str:
            quote = match.group(1)
            mime = match.group(2) or "image/png"
            data = match.group(3) or ""
            try:
                payload_bytes = _base64.b64decode(data, validate=True)
            except Exception:
                return match.group(0)
            cid = make_msgid(domain="speed-asia.com").strip("<>")
            ext = (_mimetypes.guess_extension(mime) or ".png").lstrip(".")
            inline_images.append({
                "filename": f"inline-image-{len(inline_images) + 1}.{ext}",
                "content_type": mime,
                "payload": payload_bytes,
                "disposition": "inline",
                "cid": cid,
            })
            return f"src={quote}cid:{cid}{quote}"

        pattern_img = _re.compile(r"src\s*=\s*(['\"])data:(image/[A-Za-z0-9.+-]+);base64,([^'\"]+)\1", _re.I)
        return pattern_img.sub(_replace, html or ""), inline_images

    text_body = _mail_suite_html_to_text(body_html)
    html_body, inline_images = _extract_inline_data_images(body_html or "")
    upload_attachments = [
        decoded
        for idx, item in enumerate(attachments or [], start=1)
        for decoded in [_decode_upload(item, f"attachment-{idx}")]
        if decoded is not None
    ]

    max_file_bytes = 8 * 1024 * 1024
    max_total_bytes = 50 * 1024 * 1024
    for image in inline_images:
        if len(image["payload"]) > max_file_bytes:
            raise HTTPException(status_code=413, detail=f"图片过大或总大小超过限制：{image['filename']}")
    filtered_uploads: list[dict[str, Any]] = []
    total_bytes = sum(len(img["payload"]) for img in inline_images)
    if total_bytes > max_total_bytes:
        raise HTTPException(status_code=413, detail="正文图片总大小超过限制")
    for item in upload_attachments:
        size = len(item["payload"])
        if size > max_file_bytes or total_bytes + size > max_total_bytes:
            raise HTTPException(status_code=413, detail=f"附件过大或总大小超过限制：{item['filename']}")
        total_bytes += size
        filtered_uploads.append(item)

    def _pick_body_charset(value: str) -> str:
        for candidate in ("gb2312", "gbk", "gb18030"):
            try:
                value.encode(candidate)
                return candidate
            except Exception:
                continue
        return "utf-8"

    cs_name = _pick_body_charset((text_body or "") + (html_body or ""))
    ch = _ec.Charset(cs_name)
    ch.body_encoding = _ec.QP
    ch.header_encoding = _ec.QP
    subject_ch = _ec.Charset("utf-8")
    subject_ch.header_encoding = _ec.BASE64

    def _set_common_headers(root_msg) -> None:
        if to_emails:
            root_msg["To"] = ", ".join(to_emails)
        root_msg["Subject"] = Header(subject or "", subject_ch, header_name="Subject").encode()
        root_msg["Date"] = formatdate(localtime=True)

    _font_css = "font-family:Arial,'Microsoft YaHei',sans-serif;font-size:14px;line-height:1.6;color:#172033;"
    styled_html = (
        "<html><head>"
        f'<meta http-equiv="Content-Type" content="text/html; charset={cs_name}">'
        "<style>body{" + _font_css + "margin:0;} p{margin:0 0 10px;} img{max-width:100%;height:auto;}</style>"
        "</head><body>"
        f'<div style="{_font_css}">' + html_body + "</div>"
        "</body></html>"
    )

    p_text = MIMENonMultipart("text", "plain")
    p_text.set_payload(text_body or "", ch)
    p_html = MIMENonMultipart("text", "html")
    p_html.set_payload(styled_html, ch)

    if inline_images:
        related = MIMEMultipart("related")
        related.attach(p_html)
        for image in inline_images:
            maintype, _, subtype = image["content_type"].partition("/")
            if maintype == "image" and subtype:
                part = MIMEImage(image["payload"], _subtype=subtype)
            else:
                part = MIMEBase(maintype or "application", subtype or "octet-stream")
                part.set_payload(image["payload"])
                _encoders.encode_base64(part)
            part.add_header("Content-ID", f"<{image['cid']}>")
            part.add_header("Content-Disposition", "inline", filename=("utf-8", "", image["filename"]))
            related.attach(part)
        html_container = related
    else:
        html_container = p_html

    alternative = MIMEMultipart("alternative")
    alternative.attach(p_text)
    alternative.attach(html_container)

    if filtered_uploads:
        root = MIMEMultipart("mixed")
        _set_common_headers(root)
        root.attach(alternative)
        for item in filtered_uploads:
            maintype, _, subtype = item["content_type"].partition("/")
            part = MIMEBase(maintype or "application", subtype or "octet-stream")
            part.set_payload(item["payload"])
            _encoders.encode_base64(part)
            if item["disposition"] == "inline" and item.get("cid"):
                part.add_header("Content-ID", f"<{item['cid']}>")
            part.add_header("Content-Disposition", item["disposition"], filename=("utf-8", "", item["filename"]))
            root.attach(part)
    else:
        root = alternative
        _set_common_headers(root)

    raw = root.as_bytes()
    raw = raw.replace(b"\r\n", b"\n").replace(b"\n", b"\r\n")
    return raw


# 套装页 AI 邮件在 CRM 的统一标识(UseRange)。发送系统不按 UseRange 决定是否发送(该字段只是分类标签)，
# 改成专属值便于"邮件统计"页识别哪些是本系统转入的 AI 邮件，与销售手工分类区分。
_MAIL_AI_USE_RANGE = "宣传邮件-AI"


def _insert_spqueue_send_row(crm_db, *, row_guid: str, plan_dt, subject: str, sender_email: str,
                             send_address: str, receiver: str, staff_id: str, eml_ftp_path: str,
                             email_text: str) -> str | None:
    """把一封邮件写入 CRM spQueueSend(待发队列)，由发送系统按 PlanSendTime 真发。

    返回 CRM 触发器为该行生成的 SendId(如 Mal_S260622-000003)：它是 spQueueSend 行真发后落到
    spSendInfo{销售编号} 的稳定关联键(RowId 在两表不一致，SendId 一致)，统计页据此确认真发状态。
    """
    crm_db.execute(
        text(
            "INSERT INTO spQueueSend "
            "(RowId, SessionId, PlanSendTime, Subject, Content, MessageType, FolderId, "
            " EmergencyLevel, SendAddress, InputTime, Receiver, Receivers, SecretReceivers, "
            " InputerStaffId, ProcessNow, RepeatTimes, InstanceType, Inputer, EmlFtpPath, EmailContent, UseRange) "
            "VALUES "
            "(:rowid, NEWID(), :plan, :subject, :content, 'Email', 'OutBox', "
            " 0, :sendaddr, GETDATE(), :receiver, '', '', "
            " :staffid, 0, 0, 'SpeedPersonal.Message.EmailSend', :inputer, :emlpath, :emailcontent, :userange)"
        ),
        {
            "rowid": row_guid,
            "plan": plan_dt,
            "subject": (subject or "")[:500],
            "content": sender_email,
            "sendaddr": send_address,
            "receiver": receiver,
            "staffid": staff_id or "",
            "inputer": staff_id or "",
            "emlpath": eml_ftp_path,
            "emailcontent": email_text or "",
            "userange": _MAIL_AI_USE_RANGE,
        },
    )
    # 关键：发送系统按 spQueueSendFile 找正文 .eml(FtpDir+FileName)。FileType=1 标识 eml 正文文件。
    crm_db.execute(
        text(
            "INSERT INTO spQueueSendFile "
            "(RowId, SendId, FtpDir, FileType, FileName, FileSize, CustomerWildCard, QueueRowId) "
            "VALUES (NEWID(), NULL, :ftpdir, 1, 'MailMainTemp.eml', NULL, 0, :queuerowid)"
        ),
        {"ftpdir": eml_ftp_path, "queuerowid": row_guid},
    )
    crm_db.commit()
    # 触发器在 insert 时已生成 SendId，回读用于本地落库(统计关联键)
    try:
        send_id_row = crm_db.execute(
            text("SELECT SendId FROM spQueueSend WHERE RowId=:rowid"), {"rowid": row_guid}
        ).fetchone()
        return str(send_id_row[0]) if send_id_row and send_id_row[0] else None
    except Exception:
        logger.warning("MAIL_SPQUEUE_READ_SENDID_FAILED rowid=%s", row_guid, exc_info=True)
        return None


@app.post("/api/v1/mail/customer-suite-send")
def send_mail_customer_suite(
    payload: MailCustomerSuiteSendRequest,
    db: Session = Depends(get_db),
):
    """套装页"发送"：把勾选的邮件按 计划时间 + 客户邮箱 备好待发计划(本地暂存)。

    收发件人已按 spQueueSend 格式序列化；真正写入 CRM spQueueSend + 上传 .eml 待 FTP 接入后由后续步骤完成，
    现阶段不会真实发件。
    """
    customer_id = sanitize_text(payload.customer_id).strip()
    scenario = sanitize_text(payload.scenario).strip()
    if not customer_id:
        raise HTTPException(status_code=422, detail="customer_id is required")
    if not _is_supported_scenario(scenario):
        raise HTTPException(status_code=422, detail=f"unsupported scenario: {scenario}")

    # 1) 发件人 = 在职销售签名企业邮箱
    owner_staff_id = _fetch_mail_contact_owner_staff_id(customer_id)
    signature_fields = _fetch_mail_sender_signature_fields(owner_staff_id) if owner_staff_id else {}
    # 发件邮箱不能走 sanitize_text(会被脱敏成 ***EMAIL***)
    sender_email = str((signature_fields or {}).get("email") or "").strip()
    sender_name = str((signature_fields or {}).get("english_name") or "").strip() or str((signature_fields or {}).get("staff_name") or "").strip()
    if not sender_email:
        raise HTTPException(status_code=422, detail="未取到在职销售的发件企业邮箱，无法发送")

    # 2) 收件人 = 入参覆盖 > 已保存覆盖 > CRM 有效邮箱
    if payload.recipient_emails is not None and payload.recipient_emails.strip():
        # 邮箱原样解析，禁用 sanitize_text(否则被脱敏成 ***EMAIL*** 全被过滤)
        recipient_emails = [e.strip() for e in re.split(r"[,;\s]+", str(payload.recipient_emails)) if e.strip() and "@" in e]
    else:
        rrow = (
            db.query(MailCustomerSuiteRecipient)
            .filter(MailCustomerSuiteRecipient.customer_id == customer_id,
                    MailCustomerSuiteRecipient.scenario == scenario)
            .one_or_none()
        )
        if rrow is not None and (rrow.emails or "").strip():
            recipient_emails = [e.strip() for e in re.split(r"[,;\s]+", rrow.emails) if e.strip() and "@" in e]
        else:
            recipient_emails = _fetch_mail_contact_valid_emails(customer_id)
    # 去重保序
    seen = set(); deduped = []
    for e in recipient_emails:
        if e.lower() not in seen:
            seen.add(e.lower()); deduped.append(e)
    recipient_emails = deduped
    if not recipient_emails:
        raise HTTPException(status_code=422, detail="没有可用的客户收件邮箱")

    # 3) 选择要发的封次
    saved_edits = {
        int(r.suite_step): r
        for r in db.query(MailCustomerSuiteDraftEdit)
        .filter(MailCustomerSuiteDraftEdit.customer_id == customer_id,
                MailCustomerSuiteDraftEdit.scenario == scenario).all()
    }
    if payload.suite_steps:
        steps = [s for s in payload.suite_steps if s in ALL_MAIL_SEQUENCE_STEPS]
    else:
        steps = [s for s in ALL_MAIL_SEQUENCE_STEPS
                 if (saved_edits.get(int(s)).included if saved_edits.get(int(s)) is not None else True)]
    if not steps:
        raise HTTPException(status_code=422, detail="没有勾选要发送的邮件")

    # 4) CRM 画像(收件人元数据) + 草稿生成所需信息
    crm_profile = _lookup_mail_crm_profile(customer_id, "")
    contact_name = sanitize_text(crm_profile.get("contact_name"))
    company_name = sanitize_text(crm_profile.get("company_name")) or customer_id
    contact_email = sanitize_text(crm_profile.get("contact_email"))
    draft_contact_email = _mail_demo_contact_email_for_draft(contact_email) or _mail_review_only_draft_contact_email(customer_id, crm_profile)
    seller_name = "事必达销售"
    signature_html = _build_mail_sender_signature_html(signature_fields) if signature_fields else ""

    receiver_meta = {
        "CustomerTableName": "usrCustomer",
        "CompanyName": company_name,
        "CustomerId": customer_id.split("-")[0],
        "Source": "usrCustomerContact",
        "ID": customer_id,
    }
    recipients = [{"email": e, "name": contact_name or e, "meta": receiver_meta} for e in recipient_emails]
    send_address_serialized = _mail_suite_serialize_address(sender_email, sender_name, internal_meta=None)
    receiver_serialized = _mail_suite_serialize_receivers(recipients)

    # 前端带来的每封当前内容(避免重复调大模型)
    provided_drafts = {}
    for d in (payload.drafts or []):
        try:
            provided_drafts[int(d.get("suite_step"))] = d
        except Exception:
            continue

    now_bj = datetime.utcnow() + timedelta(hours=8)
    import uuid as _uuid
    batch_id = _uuid.uuid4().hex
    prepared = []
    for suite_step in steps:
        saved = saved_edits.get(int(suite_step))
        prov = provided_drafts.get(int(suite_step))
        mail_attachments = []
        if prov and str(prov.get("body_html") or "").strip():
            # 直接用页面当前显示/编辑后的内容(已含签名与清洗)，不再调大模型
            final_subject = str(prov.get("subject") or "").strip()
            final_body_html = str(prov.get("body_html") or "")
            mail_attachments = prov.get("attachments") if isinstance(prov.get("attachments"), list) else []
        elif saved is not None and saved.subject and saved.body_html:
            # 次选:已保存内容，同样不调大模型
            final_subject = saved.subject
            final_body_html = saved.body_html
        else:
            # 兜底:页面没带内容且未保存过时才重新生成(慢，正常不会走到)
            req = MailGenerateDraftRequest(
                customer_key=customer_id, contact_email=draft_contact_email, scenario=scenario,
                suite_step=int(suite_step), current_seller_name=seller_name, current_seller_signature=seller_name,
            )
            try:
                resp = _build_mail_generate_draft_response(db, req)
                draft = resp.dict() if hasattr(resp, "dict") else dict(resp)
            except Exception as exc:
                raise HTTPException(status_code=502, detail=f"第 {suite_step} 封草稿生成失败：{sanitize_text(str(exc))[:200]}")
            final_subject = (saved.subject if (saved and saved.subject) else draft.get("final_subject")) or ""
            if saved and saved.body_html:
                draft["final_body_html"] = saved.body_html
            final_body_html = _apply_mail_suite_signature(draft.get("final_body_html") or "", signature_html)
        # 计划发送时间 = (今天 + 间隔天) 当天的 send_time；第 1 封默认当前北京时间 +10 分钟。
        default_interval, default_send_time = _mail_suite_default_send_interval_time(scenario, int(suite_step), now_bj)
        interval = int(saved.send_interval_days) if (saved and saved.send_interval_days is not None) else default_interval
        send_time = (saved.send_time if (saved and saved.send_time) else default_send_time) or "09:00"
        try:
            hh, mm = [int(x) for x in send_time.split(":")]
        except Exception:
            hh, mm = 9, 0
        plan_dt = (now_bj + timedelta(days=max(0, interval))).replace(hour=hh, minute=mm, second=0, microsecond=0)
        body_text = _mail_suite_html_to_text(final_body_html)
        row = MailCustomerSuiteSendPlan(
            batch_id=batch_id, customer_id=customer_id[:120], scenario=scenario, suite_step=int(suite_step),
            sender_email=sender_email[:255], sender_name=(sender_name or "")[:255],
            to_emails=",".join(recipient_emails), subject=final_subject[:500],
            body_html=final_body_html, body_text=body_text,
            plan_send_time=plan_dt, send_address_serialized=send_address_serialized,
            receiver_serialized=receiver_serialized, inputer_staff_id=(owner_staff_id or "")[:120],
            status="prepared",
        )
        db.add(row)
        db.flush()

        # 真发闭环：生成 .eml → SFTP 上传 → 写入 CRM spQueueSend
        step_status = "enqueued"
        step_error = None
        spqueue_rowid = None
        att_count = len(mail_attachments) if isinstance(mail_attachments, list) else 0
        eml_size = 0
        try:
            import mail_sftp
            eml_bytes = _build_mail_eml_bytes(sender_email, sender_name, recipient_emails, final_subject, final_body_html, mail_attachments)
            eml_size = len(eml_bytes)
            logger.info(
                "MAIL_SUITE_SEND_EML customer=%s step=%s attachments=%d eml_bytes=%d",
                sanitize_text(customer_id), suite_step, att_count, eml_size,
            )
            ok, eml_ftp_path = mail_sftp.upload_eml_bytes(eml_bytes)
            if not ok or not eml_ftp_path:
                step_status = "eml_upload_failed"
                step_error = "SFTP 上传失败"
            else:
                spqueue_rowid = str(_uuid.uuid4())
                from crm_database import CRMSessionLocal
                crm_db = CRMSessionLocal()
                try:
                    crm_send_id = _insert_spqueue_send_row(
                        crm_db, row_guid=spqueue_rowid, plan_dt=plan_dt, subject=final_subject,
                        sender_email=sender_email, send_address=send_address_serialized,
                        receiver=receiver_serialized, staff_id=(owner_staff_id or ""),
                        eml_ftp_path=eml_ftp_path, email_text=body_text,
                    )
                finally:
                    crm_db.close()
                row.status = "enqueued"
                row.spqueue_rowid = spqueue_rowid
                # 统计关联键：spSendInfo{销售}.SendId == 此 SendId(真发后据此确认 SendSuccess/FactSendTime)
                row.crm_send_id = crm_send_id
        except Exception as exc:
            logger.exception("MAIL_SUITE_SEND_ENQUEUE_FAILED customer=%s step=%s", sanitize_text(customer_id), suite_step)
            step_status = "enqueue_failed"
            step_error = sanitize_text(str(exc))[:200]
            row.status = step_status

        prepared.append({
            "suite_step": int(suite_step),
            "subject": final_subject,
            "plan_send_time": plan_dt.strftime("%Y-%m-%d %H:%M"),
            "status": step_status,
            "spqueue_rowid": spqueue_rowid,
            "error": step_error,
            "attachment_count": att_count,
            "eml_bytes": eml_size,
        })
    db.commit()
    enqueued = sum(1 for p in prepared if p["status"] == "enqueued")
    return {
        "ok": True,
        "batch_id": batch_id,
        "sender_email": sender_email,
        "recipient_emails": recipient_emails,
        "prepared_count": len(prepared),
        "enqueued_count": enqueued,
        "prepared": prepared,
        "real_sending_enabled": True,
        "note": f"已写入 CRM spQueueSend 待发队列 {enqueued}/{len(prepared)} 封，由发送系统按计划时间真发。",
    }


@app.post("/api/v1/mail/customer-suite-feedback")
def create_mail_customer_suite_feedback(
    payload: MailCustomerSuiteFeedbackRequest,
    db: Session = Depends(get_db),
):
    """独立客户套装邮件页反馈保存：每次提交新建一条记录。"""
    customer_id = sanitize_text(payload.customer_id).strip()
    scenario = sanitize_text(payload.scenario).strip()
    feedback_text = sanitize_text(payload.feedback_text).strip()
    if not customer_id:
        raise HTTPException(status_code=422, detail="customer_id is required")
    if not _is_supported_scenario(scenario):
        raise HTTPException(status_code=422, detail=f"unsupported scenario: {scenario}")
    if not _is_valid_suite_step(scenario, payload.suite_step):
        raise HTTPException(status_code=422, detail=f"unsupported suite_step: {payload.suite_step}")
    if not feedback_text:
        raise HTTPException(status_code=422, detail="feedback_text is required")

    row = MailCustomerSuiteFeedback(
        customer_id=customer_id[:120],
        contact_email=sanitize_text(payload.contact_email or "").strip()[:255] or None,
        company_name=sanitize_text(payload.company_name or "").strip()[:255] or None,
        scenario=scenario,
        suite_step=int(payload.suite_step),
        mail_uid=sanitize_text(payload.mail_uid or "").strip()[:120] or None,
        final_subject=sanitize_text(payload.final_subject or "").strip()[:500] or None,
        final_body_html=sanitize_text(payload.final_body_html or "").strip() or None,
        feedback_text=feedback_text[:20000],
        feedback_source=sanitize_text(payload.feedback_source or "mail_suite_page").strip()[:80] or "mail_suite_page",
        feedback_status=sanitize_text(payload.feedback_status or "submitted").strip()[:50] or "submitted",
        draft_payload=_json_safe(payload.draft_payload or {}),
        customer_profile=_json_safe(payload.customer_profile or {}),
    )
    db.add(row)
    db.commit()
    db.refresh(row)
    return {
        "ok": True,
        "feedback_id": str(row.feedback_id),
        "record": _serialize_mail_customer_suite_feedback(row),
        "storage_policy": "one_feedback_submit_one_row",
        "real_sending_enabled": False,
    }


@app.get("/api/v1/mail/customer-suite-feedback")
def list_mail_customer_suite_feedback(
    limit: int = Query(100, ge=1, le=500),
    customer_id: str | None = Query(None),
    scenario: str | None = Query(None),
    suite_step: int | None = Query(None, ge=1, le=4),
    handled: str | None = Query(None),
    db: Session = Depends(get_db),
):
    """查询独立客户套装邮件页反馈记录，供邮件质检页验证反馈、模板和客户联系人。"""
    q = db.query(MailCustomerSuiteFeedback)
    handled_norm = (handled or "").strip().lower()
    filters = {
        "limit": limit,
        "customer_id": customer_id,
        "scenario": scenario,
        "suite_step": suite_step,
        "handled": handled_norm or None,
    }
    if handled_norm in ("1", "true", "yes", "handled"):
        q = q.filter(MailCustomerSuiteFeedback.handled.is_(True))
    elif handled_norm in ("0", "false", "no", "unhandled"):
        q = q.filter(MailCustomerSuiteFeedback.handled.is_(False))
    if customer_id:
        q = q.filter(MailCustomerSuiteFeedback.customer_id == sanitize_text(customer_id).strip())
    if scenario:
        scenario_norm = sanitize_text(scenario).strip()
        if not _is_supported_scenario(scenario_norm):
            raise HTTPException(status_code=422, detail=f"unsupported scenario: {scenario_norm}")
        q = q.filter(MailCustomerSuiteFeedback.scenario == scenario_norm)
    if suite_step is not None:
        q = q.filter(MailCustomerSuiteFeedback.suite_step == int(suite_step))
    rows = q.order_by(MailCustomerSuiteFeedback.created_at.desc()).limit(limit).all()
    return {
        "version": "mail_customer_suite_feedback.v1",
        "source": "mail_customer_suite_feedback",
        "storage_policy": "one_feedback_submit_one_row",
        "count": len(rows),
        "filters": filters,
        "items": [_serialize_mail_customer_suite_feedback(row) for row in rows],
        "real_sending_enabled": False,
    }


class MailCustomerSuiteFeedbackPatchRequest(BaseModel):
    conclusion: str | None = None
    handled: bool | None = None


@app.patch("/api/v1/mail/customer-suite-feedback/{feedback_id}")
def patch_mail_customer_suite_feedback(
    feedback_id: str,
    payload: MailCustomerSuiteFeedbackPatchRequest,
    db: Session = Depends(get_db),
):
    """质检页对某条反馈记录改"结论"或勾"已处理"(leave 保存)。只改这两列, 不动原始反馈内容。"""
    fid = sanitize_text(feedback_id).strip()
    if not fid:
        raise HTTPException(status_code=422, detail="feedback_id is required")
    row = db.query(MailCustomerSuiteFeedback).filter(MailCustomerSuiteFeedback.feedback_id == fid).one_or_none()
    if row is None:
        raise HTTPException(status_code=404, detail=f"反馈记录不存在: {fid}")
    if payload.conclusion is not None:
        row.conclusion = sanitize_text(payload.conclusion).strip()[:20000] or None
    if payload.handled is not None:
        row.handled = bool(payload.handled)
    db.commit()
    db.refresh(row)
    return {"ok": True, "record": _serialize_mail_customer_suite_feedback(row)}


# ============================================================================
# 自动群发排期引擎(纯函数, 不碰 CRM) + dry-run 预览
# ============================================================================

def _autosend_scenario_step_count(scenario: str) -> int:
    """套装封数: 自建套装按其封数, 内置场景固定 4。"""
    try:
        from mail_sequence_strategy import get_dynamic_scenario_step_count
        n = get_dynamic_scenario_step_count(scenario)
        if n:
            return int(n)
    except Exception:
        pass
    return len(ALL_MAIL_SEQUENCE_STEPS)


def _autosend_cond_eval(contact: dict, cond: dict) -> bool:
    """单条条件判定(都按联系人维度)。amount=历史累计销售合同额; last_coop_days=距上次合作天数(无合作=最远=inf)。"""
    ctype = str(cond.get("type") or "").strip()
    op = str(cond.get("op") or "").strip()
    val = cond.get("value")
    if ctype == "amount":
        amt = float(contact.get("amount") or 0)
        v = float(val or 0)
        return amt < v if op == "<" else (amt > v if op == ">" else False)
    if ctype == "last_coop_days":
        days = contact.get("last_coop_days")
        days = float("inf") if days is None else float(days)   # 无合作=最远
        v = float(val or 0)
        return days < v if op == "<" else (days > v if op == ">" else False)
    if ctype == "business_line":
        target = str(val or "").strip()
        lines = [str(x) for x in (contact.get("business_lines") or [])]
        has = bool(target) and any(target in bl or bl in target for bl in lines)
        return has if op == "has" else (not has)   # has=合作过, not=没合作过
    return False


def _autosend_rule_matches(contact: dict, rule: dict) -> bool:
    conds = rule.get("conditions") or []
    if not conds:
        return True  # 无条件 = 命中所有(可作为兜底行)
    mode = str(rule.get("match_mode") or "and").lower()
    results = [_autosend_cond_eval(contact, c) for c in conds]
    return all(results) if mode == "and" else any(results)


def _autosend_pick_suite(contact: dict, rules: list[dict], used_scenarios: set, fallback_enabled: bool) -> tuple[str | None, str]:
    """按优先级给联系人挑套装: 第一个'命中且没发过'的; 都没有则兜底最后一个套装; 兜底也发过则不发。"""
    if not rules:
        return None, "no_rules"
    for rule in rules:
        if _autosend_rule_matches(contact, rule):
            sc = rule.get("scenario")
            if sc and sc not in used_scenarios:
                return sc, "matched"
            # 命中但已发过 -> 继续往下找
    if fallback_enabled:
        fb = rules[-1].get("scenario")
        if fb and fb not in used_scenarios:
            return fb, "fallback"
    return None, "all_used"  # 兜底也发过


def _autosend_schedule(contacts: list[dict], rules: list[dict], interval_days: list[int],
                       daily_cap: int, start_date, existing_load: dict | None = None,
                       fallback_enabled: bool = True) -> dict:
    """逐人逐封排期。返回 {items, skipped, day_load}。纯计算, 不写任何库。

    - 第1封目标日 = 开始日 + interval[0]; 第k封 = 第k-1封实际落日 + interval[k-1]。
    - 目标日该销售已满(>=上限, 含 existing_load 的 CRM 已有量)则整天跳过, 向后找首个未满天。
    - 当天时间 = 09:00 + 5 分钟 x 当天该销售第几封。
    """
    intervals = [int(x) for x in (interval_days or [0])] or [0]
    cap = max(1, int(daily_cap or 1))

    def gap(step_idx: int) -> int:  # step_idx: 0-based
        return intervals[step_idx] if step_idx < len(intervals) else intervals[-1]

    load = dict(existing_load or {})  # {(owner, 'YYYY-MM-DD'): count}
    items: list[dict] = []
    skipped: list[dict] = []
    for c in contacts:
        owner = str(c.get("owner_staff_id") or "")
        used = set(c.get("used_scenarios") or [])
        scenario, reason = _autosend_pick_suite(c, rules, used, fallback_enabled)
        if scenario is None:
            skipped.append({
                "contact_id": c.get("contact_id"),
                "owner_staff_id": owner,
                "reason": reason,
                "detail": "符合的套装都已发过(含兜底), 本次不发" if reason == "all_used" else "无可用套装规则",
            })
            continue
        step_count = _autosend_scenario_step_count(scenario)
        prev_actual = None
        for step in range(1, step_count + 1):
            if step == 1:
                desired = start_date + timedelta(days=gap(0))
            else:
                desired = prev_actual + timedelta(days=gap(step - 1))
            day = desired
            while load.get((owner, day.isoformat()), 0) >= cap:
                day = day + timedelta(days=1)
            seq = load.get((owner, day.isoformat()), 0)
            minute_total = 9 * 60 + 5 * seq
            hh, mm = divmod(minute_total, 60)
            load[(owner, day.isoformat())] = seq + 1
            items.append({
                "contact_id": c.get("contact_id"),
                "owner_staff_id": owner,
                "email": c.get("email"),
                "scenario": scenario,
                "scenario_label_cn": _get_scenario_label_cn(scenario) or scenario,
                "suite_step": step,
                "plan_date": day.isoformat(),
                "plan_time": f"{hh:02d}:{mm:02d}",
                "seq_in_day": seq,
                "pick_reason": reason,
            })
            prev_actual = day
    # 排期后每销售每天的封数汇总(便于核对上限/顺延)
    day_load = [
        {"owner_staff_id": k[0], "date": k[1], "count": v}
        for k, v in sorted(load.items())
    ]
    return {"items": items, "skipped": skipped, "day_load": day_load}


def _autosend_sort_contacts(contacts: list[dict], sort_rule: str) -> list[dict]:
    """按排序规则给联系人排序(决定谁先排、谁先被顶满顺延)。无合作: 金额=0, 末次=最远。"""
    rule = str(sort_rule or "default").lower()

    def amt(c):
        return float(c.get("amount") or 0)

    def last(c):
        d = c.get("last_coop_days")
        return float("inf") if d is None else float(d)

    if rule == "amount_desc":
        return sorted(contacts, key=amt, reverse=True)
    if rule == "amount_asc":
        return sorted(contacts, key=amt)
    if rule == "last_far":    # 末次合作远->近: 越久远越靠前
        return sorted(contacts, key=last, reverse=True)
    if rule == "last_near":   # 末次合作近->远: 越近越靠前
        return sorted(contacts, key=last)
    if rule == "random":
        import random as _r
        cc = list(contacts)
        _r.shuffle(cc)
        return cc
    return list(contacts)     # default: 保持现有顺序


def _autosend_demo_contacts(n: int) -> list[dict]:
    """合成 n 个同销售联系人, 用于验证'第25个联系人顺延'这类排期, 不碰 CRM。"""
    return [
        {"contact_id": f"DEMO-{i+1:03d}", "owner_staff_id": "DEMO", "amount": 0,
         "last_coop_days": None, "business_lines": [], "email": f"demo{i+1}@example.com", "used_scenarios": []}
        for i in range(max(1, int(n)))
    ]


class AutosendDryRunRequest(BaseModel):
    start_date: str | None = None          # YYYY-MM-DD, 缺省=今天(北京)
    daily_cap: int = 10
    interval_days: list[int] = [0]
    sort_rule: str = "default"             # default/amount_desc/amount_asc/last_far/last_near/random
    rules: list[dict] = []                  # [{scenario, conditions, match_mode}], 顺序即优先级
    fallback_enabled: bool = True
    contacts: list[dict] | None = None      # 内联联系人(验证算法用), 缺省时按 sales_staff_ids 从 CRM 取
    sales_staff_ids: list[str] | None = None
    consider_existing_crm_queue: bool = True
    demo: bool = False
    demo_count: int = 26


@app.post("/api/v1/mail/autosend/dry-run")
def autosend_dry_run(payload: AutosendDryRunRequest, db: Session = Depends(get_db)):
    """自动群发排期预览(dry-run): 只算排期表, 不生成草稿、不写 CRM、不入任何库。

    三种取联系人方式: demo(合成) > contacts(内联) > sales_staff_ids(从 CRM 取该销售名下有效邮箱联系人)。
    """
    # 开始日期
    now_bj = datetime.utcnow() + timedelta(hours=8)
    if payload.start_date:
        try:
            start_date = datetime.strptime(payload.start_date.strip(), "%Y-%m-%d").date()
        except Exception:
            raise HTTPException(status_code=422, detail="start_date 格式应为 YYYY-MM-DD")
    else:
        start_date = now_bj.date()

    # 取联系人
    source = ""
    if payload.demo:
        contacts = _autosend_demo_contacts(payload.demo_count)
        source = "demo"
        rules = payload.rules or [{"scenario": "re_activation", "conditions": [], "match_mode": "and"}]
    elif payload.contacts:
        contacts = payload.contacts
        source = "inline"
        rules = payload.rules
    elif payload.sales_staff_ids:
        contacts = _autosend_load_contacts_for_sales(payload.sales_staff_ids, only_valid_email=True)
        source = "crm_sales"
        rules = payload.rules
    else:
        raise HTTPException(status_code=422, detail="请提供 demo / contacts / sales_staff_ids 之一")

    if not rules:
        raise HTTPException(status_code=422, detail="rules 不能为空(至少一个套装规则, 末位作兜底)")

    # 按排序规则排序(demo 保持合成顺序, 不排序)
    if source != "demo":
        contacts = _autosend_sort_contacts(contacts, payload.sort_rule)

    # 已有 CRM 待发排期占用(按销售按天)
    existing_load = {}
    if payload.consider_existing_crm_queue and source == "crm_sales":
        owners = sorted({str(c.get("owner_staff_id") or "") for c in contacts if c.get("owner_staff_id")})
        existing_load = _autosend_existing_crm_load(owners, start_date)

    result = _autosend_schedule(
        contacts, rules, payload.interval_days, payload.daily_cap, start_date,
        existing_load=existing_load, fallback_enabled=payload.fallback_enabled,
    )
    return {
        "ok": True,
        "mode": "dry_run",
        "source": source,
        "start_date": start_date.isoformat(),
        "daily_cap": payload.daily_cap,
        "interval_days": payload.interval_days,
        "contacts_count": len(contacts),
        "scheduled_count": len(result["items"]),
        "skipped_count": len(result["skipped"]),
        "items": result["items"],
        "skipped": result["skipped"],
        "day_load": result["day_load"],
        "note": "dry-run 仅计算排期, 未生成草稿、未写 CRM、未入库。",
    }


def _autosend_parse_interval_csv(csv: str) -> list[int]:
    out = []
    for x in str(csv or "").split(","):
        x = x.strip()
        if x.lstrip("-").isdigit():
            out.append(int(x))
    return out or [0]


def _autosend_serialize_config(row) -> dict:
    return {
        "sort_rule": row.sort_rule,
        "only_valid_email": bool(row.only_valid_email),
        "interval_days_csv": row.interval_days_csv,
        "interval_days": _autosend_parse_interval_csv(row.interval_days_csv),
        "daily_cap": int(row.daily_cap or 10),
        "fallback_enabled": bool(row.fallback_enabled),
        "dedup_by_history": bool(row.dedup_by_history),
    }


def _autosend_get_or_create_config(db: Session):
    row = db.query(MailAutosendConfig).order_by(MailAutosendConfig.config_id).first()
    if row is None:
        row = MailAutosendConfig()
        db.add(row)
        db.commit()
        db.refresh(row)
    return row


def _autosend_serialize_rule(row) -> dict:
    return {
        "rule_id": str(row.rule_id),
        "priority": int(row.priority or 0),
        "scenario": row.scenario,
        "scenario_label_cn": _get_scenario_label_cn(row.scenario) or row.scenario,
        "conditions": row.conditions or [],
        "match_mode": row.match_mode or "and",
        "enabled": bool(row.enabled),
    }


class AutosendConfigRequest(BaseModel):
    sort_rule: str | None = None
    only_valid_email: bool | None = None
    interval_days: list[int] | None = None
    interval_days_csv: str | None = None
    daily_cap: int | None = None
    fallback_enabled: bool | None = None
    dedup_by_history: bool | None = None


@app.get("/api/v1/mail/autosend/config")
def get_autosend_config(db: Session = Depends(get_db)):
    return {"ok": True, "config": _autosend_serialize_config(_autosend_get_or_create_config(db))}


@app.put("/api/v1/mail/autosend/config")
def put_autosend_config(payload: AutosendConfigRequest, db: Session = Depends(get_db)):
    row = _autosend_get_or_create_config(db)
    if payload.sort_rule is not None:
        row.sort_rule = sanitize_text(payload.sort_rule).strip()[:40] or "default"
    if payload.only_valid_email is not None:
        row.only_valid_email = bool(payload.only_valid_email)
    if payload.interval_days is not None:
        row.interval_days_csv = ",".join(str(int(x)) for x in payload.interval_days) or "0"
    elif payload.interval_days_csv is not None:
        row.interval_days_csv = ",".join(str(x) for x in _autosend_parse_interval_csv(payload.interval_days_csv))
    if payload.daily_cap is not None:
        row.daily_cap = max(1, int(payload.daily_cap))
    if payload.fallback_enabled is not None:
        row.fallback_enabled = bool(payload.fallback_enabled)
    if payload.dedup_by_history is not None:
        row.dedup_by_history = bool(payload.dedup_by_history)
    row.updated_at = datetime.utcnow()
    db.commit()
    db.refresh(row)
    return {"ok": True, "config": _autosend_serialize_config(row)}


@app.get("/api/v1/mail/autosend/suite-rules")
def list_autosend_suite_rules(db: Session = Depends(get_db)):
    rows = db.query(MailAutosendSuiteRule).order_by(MailAutosendSuiteRule.priority, MailAutosendSuiteRule.updated_at).all()
    return {"ok": True, "rules": [_autosend_serialize_rule(r) for r in rows]}


class AutosendRuleIn(BaseModel):
    scenario: str
    conditions: list[dict] = []
    match_mode: str = "and"
    enabled: bool = True


class AutosendRulesReplaceRequest(BaseModel):
    rules: list[AutosendRuleIn] = []


@app.put("/api/v1/mail/autosend/suite-rules")
def replace_autosend_suite_rules(payload: AutosendRulesReplaceRequest, db: Session = Depends(get_db)):
    """整组替换套装优先级规则: 前端发完整有序列表, 顺序即 priority(0,1,2...), 末位为兜底。"""
    db.query(MailAutosendSuiteRule).delete()
    for idx, r in enumerate(payload.rules):
        scenario = sanitize_text(r.scenario).strip()
        if not scenario:
            continue
        db.add(MailAutosendSuiteRule(
            priority=idx,
            scenario=scenario[:80],
            conditions=[c for c in (r.conditions or []) if isinstance(c, dict)],
            match_mode=("or" if str(r.match_mode).lower() == "or" else "and"),
            enabled=bool(r.enabled),
        ))
    db.commit()
    rows = db.query(MailAutosendSuiteRule).order_by(MailAutosendSuiteRule.priority).all()
    return {"ok": True, "rules": [_autosend_serialize_rule(r) for r in rows]}


