def _autosend_existing_crm_load(staff_ids: list[str], start_date) -> dict:
    """读 CRM spQueueSend 已有待发量, 按 (销售, 计划日) 计数, 作为每日上限的起始占用。失败返回 {}。"""
    load: dict = {}
    staff_ids = [s for s in (staff_ids or []) if s]
    if not staff_ids:
        return load
    try:
        from crm_database import CRMSessionLocal
        crm_db = CRMSessionLocal()
        try:
            rows = crm_db.execute(
                text(
                    "SELECT InputerStaffId, CONVERT(varchar(10), PlanSendTime, 23) AS d, COUNT(*) AS n "
                    "FROM spQueueSend "
                    "WHERE MessageType='Email' AND PlanSendTime >= :start "
                    "AND InputerStaffId IN :ids "
                    "GROUP BY InputerStaffId, CONVERT(varchar(10), PlanSendTime, 23)"
                ).bindparams(bindparam("ids", expanding=True)),
                {"start": datetime.combine(start_date, datetime.min.time()), "ids": staff_ids},
            ).fetchall()
            for r in rows:
                owner = str(r[0] or ""); d = str(r[1] or ""); n = int(r[2] or 0)
                if owner and d:
                    load[(owner, d)] = n
        finally:
            crm_db.close()
    except Exception:
        logger.exception("AUTOSEND_EXISTING_CRM_LOAD_FAILED staff=%s", staff_ids)
    return load


def _autosend_load_contacts_for_sales(staff_ids: list[str], only_valid_email: bool = True) -> list[dict]:
    """从 CRM 取指定销售名下、有有效邮箱的联系人, 并按人聚合历史累计销售合同额/末次合作/业务线。

    口径(均按联系人 ContactId):
    - 金额 = SUM(Money1+Money2+Money3) over ContractType='销售合同'。
    - 末次合作 = MAX(COALESCE(ContractTime,StartTime,InputTime)); 距今天数; 无合作=None(最远)。
    - 业务线 = DISTINCT BusinessType。
    - 有效邮箱 = usrCustomerContactCommunicateNo(ContactEmail, IsCollect='正确')。
    """
    staff_ids = [s for s in (staff_ids or []) if s]
    if not staff_ids:
        return []
    out: list[dict] = []
    try:
        from crm_database import CRMSessionLocal
        crm_db = CRMSessionLocal()
        try:
            # 1) 取该销售名下联系人(Owner 含该工号; Owner 可能是多工号拼接, 用 LIKE 粗筛再 Python 拆 token 精确)
            like_clauses = " OR ".join([f"CAST(c.Owner AS NVARCHAR(240)) LIKE :p{i}" for i in range(len(staff_ids))])
            params = {f"p{i}": f"%{sid}%" for i, sid in enumerate(staff_ids)}
            contact_rows = crm_db.execute(
                text(
                    "SELECT DISTINCT c.ContactId, CAST(ISNULL(c.Owner,'') AS NVARCHAR(240)) AS Owner "
                    "FROM usrCustomerContact c "
                    "WHERE c.Deleter IS NULL AND ISNULL(CAST(c.Owner AS NVARCHAR(240)),'')<>'' "
                    f"AND ({like_clauses})"
                ),
                params,
            ).fetchall()
            staff_set = set(staff_ids)
            contacts_map: dict[str, str] = {}  # contact_id -> matched owner staff id
            for cid, owner_raw in contact_rows:
                cid = str(cid or "").strip()
                if not cid:
                    continue
                tokens = [t.strip() for t in re.split(r"[,;，、\s]+", str(owner_raw or "")) if t.strip()]
                owner = next((t for t in tokens if t in staff_set), None)
                if owner:
                    contacts_map.setdefault(cid, owner)
            if not contacts_map:
                return []
            contact_ids = list(contacts_map.keys())

            def _chunks(seq, n=500):
                for i in range(0, len(seq), n):
                    yield seq[i:i + n]

            # 2) 有效邮箱(取最新一个)
            email_map: dict[str, str] = {}
            for chunk in _chunks(contact_ids):
                rows = crm_db.execute(
                    text(
                        "SELECT ContactId, CommunicateNo, InputTime FROM usrCustomerContactCommunicateNo "
                        "WHERE CommunicateType='ContactEmail' AND ISNULL(IsCollect,'')='正确' "
                        "AND ContactId IN :ids ORDER BY InputTime DESC"
                    ).bindparams(bindparam("ids", expanding=True)),
                    {"ids": chunk},
                ).fetchall()
                for cid, no, _t in rows:
                    cid = str(cid or "").strip(); no = str(no or "").strip()
                    if cid and no and "@" in no and "/" not in no and " " not in no:
                        email_map.setdefault(cid, no)

            # 3) 合同聚合: 金额 + 末次合作
            agg_map: dict[str, dict] = {}
            for chunk in _chunks(contact_ids):
                rows = crm_db.execute(
                    text(
                        "SELECT ContactId, "
                        " SUM(ISNULL(Money1,0)+ISNULL(Money2,0)+ISNULL(Money3,0)) AS amt, "
                        " MAX(COALESCE(ContractTime, StartTime, InputTime)) AS last_t "
                        "FROM usrContract WHERE Deleter IS NULL AND ContractType='销售合同' "
                        "AND ContactId IN :ids GROUP BY ContactId"
                    ).bindparams(bindparam("ids", expanding=True)),
                    {"ids": chunk},
                ).fetchall()
                for cid, amt, last_t in rows:
                    agg_map[str(cid or "").strip()] = {"amount": float(amt or 0), "last_t": last_t}

            # 4) 业务线
            line_map: dict[str, set] = {}
            for chunk in _chunks(contact_ids):
                rows = crm_db.execute(
                    text(
                        "SELECT DISTINCT ContactId, CAST(ISNULL(BusinessType,'') AS NVARCHAR(200)) AS bt "
                        "FROM usrContract WHERE Deleter IS NULL AND ContractType='销售合同' "
                        "AND ContactId IN :ids"
                    ).bindparams(bindparam("ids", expanding=True)),
                    {"ids": chunk},
                ).fetchall()
                for cid, bt in rows:
                    bt = str(bt or "").strip()
                    if bt:
                        line_map.setdefault(str(cid or "").strip(), set()).add(bt)

            today = (datetime.utcnow() + timedelta(hours=8)).date()
            for cid, owner in contacts_map.items():
                email = email_map.get(cid)
                if only_valid_email and not email:
                    continue
                agg = agg_map.get(cid) or {}
                last_t = agg.get("last_t")
                last_days = None
                if last_t is not None:
                    try:
                        last_days = max(0, (today - (last_t.date() if hasattr(last_t, "date") else last_t)).days)
                    except Exception:
                        last_days = None
                out.append({
                    "contact_id": cid,
                    "owner_staff_id": owner,
                    "email": email,
                    "amount": float(agg.get("amount") or 0),
                    "last_coop_days": last_days,
                    "business_lines": sorted(line_map.get(cid, set())),
                    "used_scenarios": [],  # step 3 再接历史去重
                })
        finally:
            crm_db.close()
    except Exception:
        logger.exception("AUTOSEND_LOAD_CONTACTS_FAILED staff=%s", staff_ids)
        return []
    return out


def _mail_ai_stats_llm_call(prompt: str) -> dict:
    """供 mail_ai_stats 价值分析复用的 deepseek 调用(强制 JSON)。"""
    return _call_llm2_json_for_mail_draft(prompt, timeout_seconds=30, force_json=True)


def _parse_stat_date(value: str | None, default: "date | None" = None):
    import datetime as _dt
    if not value:
        return default
    try:
        return _dt.date.fromisoformat(value.strip())
    except Exception as exc:
        raise HTTPException(status_code=422, detail=f"日期格式应为 YYYY-MM-DD: {value}") from exc


@app.get("/api/v1/mail/ai-stats/summary")
def get_mail_ai_stats_summary(
    start: str | None = Query(None),
    end: str | None = Query(None),
    staff_id: str | None = Query(None),
    refresh: int = Query(0),
    db: Session = Depends(get_db),
):
    """邮件统计汇总: 按天 x 销售 的 5 指标。

    - 默认只读本地日表 + 当天用本地缓存实时重算(快); refresh=1 时先从 CRM/FTP/deepseek 全量刷新(慢)。
    - 时间口径为北京时间(UTC+8)。
    """
    import mail_ai_stats as _stats
    import datetime as _dt
    today_bj = (_dt.datetime.utcnow() + _dt.timedelta(hours=8)).date()
    end_d = _parse_stat_date(end, today_bj)
    start_d = _parse_stat_date(start, end_d - _dt.timedelta(days=29))
    if start_d > end_d:
        start_d, end_d = end_d, start_d
    refresh_result = None
    try:
        if refresh:
            refresh_result = _stats.refresh_all(db, _mail_ai_stats_llm_call,
                                                lookback_days=max(1, (today_bj - start_d).days + 1))
        else:
            # 当天实时: 仅用本地缓存重算日表(纯本地 SQL, 不碰 CRM/FTP/LLM)
            _stats.compute_and_store_daily(db, start_d, end_d)
    except Exception as exc:
        logger.exception("MAIL_AI_STATS_SUMMARY_COMPUTE_FAILED")
        raise HTTPException(status_code=502, detail=f"统计计算失败: {sanitize_text(str(exc))[:200]}")
    daily = _stats.query_daily(db, start_d, end_d, staff_id)
    totals = {
        "generated_count": sum(d["generated_count"] for d in daily),
        "sent_count": sum(d["sent_count"] for d in daily),
        "reply_count": sum(d["reply_count"] for d in daily),
        "valuable_count": sum(d["valuable_count"] for d in daily),
        "feedback_count": sum(d["feedback_count"] for d in daily),
    }
    return {
        "version": "mail_ai_stats.v1",
        "start": start_d.isoformat(),
        "end": end_d.isoformat(),
        "staff_id": (staff_id or "").strip(),
        "staff_options": _stats.list_staff(db),
        "totals": totals,
        "daily": daily,
        "refreshed": bool(refresh),
        "refresh_result": refresh_result,
    }


@app.get("/api/v1/mail/ai-stats/detail")
def get_mail_ai_stats_detail(
    metric: str = Query(..., min_length=1),
    day: str = Query(..., min_length=1),
    staff_id: str | None = Query(None),
    db: Session = Depends(get_db),
):
    """某天某指标的明细邮件清单(双击单元格打开)。含联系人/主题/正文; 反馈、价值理由有才返回。"""
    import mail_ai_stats as _stats
    metric_norm = (metric or "").strip()
    if metric_norm not in ("generated", "sent", "reply", "valuable", "feedback"):
        raise HTTPException(status_code=422, detail=f"unsupported metric: {metric_norm}")
    day_d = _parse_stat_date(day)
    if day_d is None:
        raise HTTPException(status_code=422, detail="day is required (YYYY-MM-DD)")
    items = _stats.detail_rows(db, metric_norm, day_d, staff_id)
    return {
        "version": "mail_ai_stats_detail.v1",
        "metric": metric_norm,
        "day": day_d.isoformat(),
        "staff_id": (staff_id or "").strip(),
        "count": len(items),
        "items": items,
    }


def _resolve_mail_staff_names(staff_ids: "list[str]") -> "dict[str, str]":
    """销售工号 -> CRM 中文姓名(usrStaff.StaffName)。查不到的留空, 前端回退显示工号。"""
    ids = sorted({(s or "").strip() for s in staff_ids if (s or "").strip()})
    if not ids:
        return {}
    from crm_database import CRMSessionLocal
    crm = CRMSessionLocal()
    out: dict[str, str] = {}
    try:
        for i in range(0, len(ids), 200):
            chunk = ids[i:i + 200]
            params = {f"s{j}": v for j, v in enumerate(chunk)}
            ph = ",".join(f":s{j}" for j in range(len(chunk)))
            for row in crm.execute(text(
                f"SELECT StaffId, ISNULL(CAST(StaffName AS NVARCHAR(120)),'') FROM usrStaff WHERE StaffId IN ({ph})"
            ), params).fetchall():
                out[str(row[0]).strip()] = sanitize_text(str(row[1] or "")).strip()
    except Exception:
        logger.warning("MAIL_STAFF_NAME_RESOLVE_FAILED", exc_info=True)
    finally:
        crm.close()
    return out


@app.get("/api/v1/mail/ai-stats/by-staff")
def get_mail_ai_stats_by_staff(
    day: str | None = Query(None),
    refresh: int = Query(0),
    db: Session = Depends(get_db),
):
    """某一天 各销售 的 5 指标(销售显示中文名)。默认昨天(北京时间)。

    - refresh=1 时先从 CRM/FTP/deepseek 全量刷新再统计; 否则当天用本地缓存实时重算。
    - 双击明细复用 /ai-stats/detail?staff_id=... 接口。
    """
    import mail_ai_stats as _stats
    import datetime as _dt
    today_bj = (_dt.datetime.utcnow() + _dt.timedelta(hours=8)).date()
    day_d = _parse_stat_date(day, today_bj - _dt.timedelta(days=1))  # 默认上一天
    refresh_result = None
    try:
        if refresh:
            refresh_result = _stats.refresh_all(db, _mail_ai_stats_llm_call,
                                                lookback_days=max(1, (today_bj - day_d).days + 1))
        else:
            _stats.compute_and_store_daily(db, day_d, day_d)
    except Exception as exc:
        logger.exception("MAIL_AI_STATS_BY_STAFF_COMPUTE_FAILED")
        raise HTTPException(status_code=502, detail=f"统计计算失败: {sanitize_text(str(exc))[:200]}")
    rows = _stats.query_daily_by_staff(db, day_d)
    name_map = _resolve_mail_staff_names([r["staff_id"] for r in rows])
    for r in rows:
        r["staff_name"] = name_map.get(r["staff_id"], "") or r["staff_id"]
    totals = {
        "generated_count": sum(r["generated_count"] for r in rows),
        "sent_count": sum(r["sent_count"] for r in rows),
        "reply_count": sum(r["reply_count"] for r in rows),
        "valuable_count": sum(r["valuable_count"] for r in rows),
        "feedback_count": sum(r["feedback_count"] for r in rows),
    }
    return {
        "version": "mail_ai_stats_by_staff.v1",
        "day": day_d.isoformat(),
        "is_final": (day_d < today_bj),
        "rows": rows,
        "totals": totals,
        "refreshed": bool(refresh),
        "refresh_result": refresh_result,
    }


@app.get("/api/v1/mail/demo-contacts")
async def get_mail_demo_contacts(db: Session = Depends(get_db)):
    """返回当前邮件 AI 回复测试案例。

    用途：前端邮件质量诊断面板的 Live Demo 区做案例切换 + 默认值预填。
    当前展示/测试只使用 3 个真实客户编号；原 5 个脱敏案例保留在 mail_demo_contact 表中。
    边界：本接口只读 CRM 与 PG；不写任何库；不真发邮件。
    """
    from database import MailDemoContact
    from mail_sequence_strategy import ALL_MAIL_SEQUENCE_STEPS
    suite_total_steps = len(ALL_MAIL_SEQUENCE_STEPS)
    rows = db.query(MailDemoContact).filter(
        MailDemoContact.is_current_test_case.is_(True)
    ).order_by(MailDemoContact.demo_index).all()
    rows_by_key = {
        (row.real_customer_key or "").strip().upper(): row
        for row in rows
        if (row.real_customer_key or "").strip()
    }
    contacts = []
    for current_case in MAIL_CURRENT_DEMO_CASES:
        real_customer_key = current_case["real_customer_key"]
        row = rows_by_key.get(real_customer_key.upper())
        crm_detail = _fetch_mail_current_case_crm_detail(real_customer_key)
        crm_hit = crm_detail.get("crm_lookup_status") == "matched_crm_contact_id_or_customer_id"
        snapshot = {
            **(row.crm_profile_snapshot if row else {}),
            **crm_detail,
        }
        contact_email = _mail_demo_contact_email_for_draft(crm_detail.get("contact_email")) if crm_hit else ""
        draft_contact_email = contact_email
        seller_name = (
            sanitize_text(crm_detail.get("contact_staff_name"))
            or sanitize_text(crm_detail.get("contact_owner_name"))
            or (row.default_seller_name if row else "")
            or "销售测试"
        )
        contacts.append({
            "demo_index": current_case["demo_index"],
            "demo_label": row.demo_label if row else current_case["demo_label"],
            "demo_label_detail": row.demo_label_detail if row else current_case["demo_label_detail"],
            "real_customer_key": real_customer_key,
            "customer_key": real_customer_key,
            "contact_email": contact_email,
            "draft_contact_email": draft_contact_email,
            "contact_name": sanitize_text(crm_detail.get("contact_name")) if crm_hit else "",
            "company_name": sanitize_text(crm_detail.get("company_name")) if crm_hit else "",
            "contact_name_masked": sanitize_text(crm_detail.get("contact_name")) if crm_hit else (row.contact_name_masked if row else "CRM 联系人"),
            "company_name_masked": sanitize_text(crm_detail.get("company_name")) if crm_hit else (row.company_name_masked if row else real_customer_key),
            "company_industry": (sanitize_text(crm_detail.get("company_industry")) if crm_hit else (row.company_industry if row else "CRM 查询失败")) or "未识别",
            "customer_lifecycle_stage": (sanitize_text(crm_detail.get("customer_lifecycle_stage")) if crm_hit else (row.customer_lifecycle_stage if row else "CRM 查询失败")) or "未识别",
            "customer_tier": (sanitize_text(crm_detail.get("customer_tier")) if crm_hit else (row.customer_tier if row else "CRM 查询失败")) or "未识别",
            "payment_risk_level": (sanitize_text(crm_detail.get("payment_risk_level")) if crm_hit else (row.payment_risk_level if row else "CRM 查询失败")) or "未识别",
            "high_risk_flags": (crm_detail.get("high_risk_flags") if crm_hit else (row.high_risk_flags if row else [])) or [],
            "default_scenario": (row.default_scenario if row else current_case["default_scenario"]),
            "default_suite_step": (row.default_suite_step if row else current_case["default_suite_step"]),
            "default_seller_name": seller_name,
            "default_seller_signature": f"{seller_name}\n事必达多业务开发部",
            "source_note": (
                "当前 3 个案例按产品指定客户编号实时只读查询 CRM 原始信息；未脱敏，仅限邮件质量诊断当前案例展示/测试。"
                if crm_hit
                else f"CRM 查询失败：{sanitize_text(crm_detail.get('crm_lookup_error')) or '未查到'}"
            ),
            "refreshed_at": crm_detail.get("refreshed_at") or (row.refreshed_at.isoformat() if row and row.refreshed_at else None),
            "crm_profile_snapshot": snapshot,
            "display_group": row.display_group if row else "current_3_cases",
            "is_current_test_case": True,
            "crm_lookup_status": crm_detail.get("crm_lookup_status"),
            "crm_profile_source": crm_detail.get("crm_profile_source"),
            "is_unmasked_current_case": bool(crm_hit),
        })
    return {
        "version": "mail_demo_contact.v3_current_3_cases",
        "source": "crm_sql_current_case_unmasked_overlay",
        "read_only": True,
        "wrote_to_crm": False,
        "wrote_to_db_in_this_request": False,
        "unmasked_current_cases": True,
        "real_sending_enabled": False,
        "count": len(contacts),
        "contacts": contacts,
        "suite_total_steps": suite_total_steps,
        "legacy_cases_retained": True,
        "current_case_customer_keys": [item["real_customer_key"] for item in MAIL_CURRENT_DEMO_CASES],
        "suite_steps_note": (
            "邮件序列套装总步数。当前所有场景均为 4 步（破冰 → 案例 → 流程 → 样稿）。"
            "未来步数可配置，由 mail_sequence_strategy.ALL_MAIL_SEQUENCE_STEPS 控制。"
        ),
    }


# ===================== 邮件 AI 回复迭代记录（v1.7.205） =====================
# 一次迭代 = 当前 3 案例 × 4 步 = 12 封邮件串行生成，落 mail_iteration_run + mail_iteration_draft。
# 后台线程跑（HTTP 立即返回 run_id），前端轮询查状态。

_MAIL_FALLBACK_TEMPLATE_MARKERS = [
    "这是一封",
    "草稿样例",
    "本步目标",
    "场景第",
    "参考角度（来自我们历史的高质量邮件范例库）",
]


_MAIL_GOLD_HUMAN_STYLE_TERMS = (
    "您好", "供您参考", "如果您", "也欢迎", "随时", "方便", "希望", "期待", "辛苦",
    "省时", "省心", "省力", "一站式", "低压力", "相关团队", "推荐", "转给", "判断",
    "场景", "活动", "资料", "会议", "物料", "多媒体", "排版", "印刷", "同传",
)

_MAIL_GOLD_BUSINESS_STYLE_TERMS = (
    "同传设备", "会议同传", "现场语言支持", "多语种", "国际交流", "国际化沟通",
    "对外展示", "行业活动", "展会活动", "展台搭建", "展会物料", "活动物料",
    "商务礼品", "双语资料", "产品资料", "医学文档", "产品说明书", "法规合规",
    "翻译物料", "翻译", "笔译", "本地化", "排版印刷", "视频译制", "字幕",
    "一站式方式", "一站式配合", "减少多方", "统一协调", "服务范围", "成功案例",
    "案例分享", "供您内部判断", "备选参考", "转发给相关", "相关同事",
)

_MAIL_ROBOTIC_OR_PUSHY_TERMS = (
    "硬性要求", "变量取值", "结构脚本", "AI指令", "必须使用", "本步目标", "草稿样例",
    "立即回复", "尽快下单", "限时优惠", "强烈建议", "务必今天", "报价如下",
)


def _mail_plain_text_from_html(value: str | None) -> str:
    text_value = re.sub(r"<br\s*/?>", "\n", value or "", flags=re.IGNORECASE)
    text_value = re.sub(r"</p\s*>", "\n", text_value, flags=re.IGNORECASE)
    text_value = re.sub(r"<[^>]+>", "", text_value)
    text_value = html.unescape(text_value)
    return re.sub(r"\s+", " ", text_value).strip()


def _mail_gold_similarity_terms(value: str) -> set[str]:
    text_value = sanitize_text(value)
    terms = {
        term
        for term in (*_MAIL_GOLD_HUMAN_STYLE_TERMS, *_MAIL_GOLD_BUSINESS_STYLE_TERMS)
        if term in text_value
    }
    return {term for term in terms if len(term) >= 2}


def _mail_best_approved_gold_similarity(
    db: Session | None,
    *,
    scenario: str,
    body_text: str,
) -> dict:
    if db is None or not body_text:
        return {"score": 0, "best_source_ref": None, "best_title": None, "overlap_terms": []}
    generated_terms = _mail_gold_similarity_terms(body_text)
    if not generated_terms:
        return {"score": 0, "best_source_ref": None, "best_title": None, "overlap_terms": []}
    rows = _mail_approved_full_email_gold_seed_rows(
        db,
        scenario=scenario,
        min_score=Decimal("0.6000"),
        limit=20,
    )
    best_score = 0.0
    best_row = None
    best_overlap: set[str] = set()
    for row in rows:
        gold_terms = _mail_gold_similarity_terms(f"{row.title}\n{row.content}")
        if not gold_terms:
            continue
        overlap = generated_terms & gold_terms
        score = len(overlap) / max(1, min(len(generated_terms), len(gold_terms)))
        if score > best_score:
            best_score = score
            best_row = row
            best_overlap = overlap
    return {
        "score": round(min(best_score, 1.0), 4),
        "best_source_ref": best_row.source_ref if best_row else None,
        "best_title": best_row.title if best_row else None,
        "overlap_terms": sorted(best_overlap, key=lambda item: (-len(item), item))[:12],
    }


def _score_mail_iteration_draft(
    *,
    db: Session | None = None,
    scenario: str = "",
    response_data: dict,
    elapsed_ms: int,
    final_subject: str,
    final_body_html: str,
) -> dict:
    """V34 评分：以人工认可黄金邮件为标准，看亲和度与相似度。"""
    breakdown: dict[str, Any] = {"score_method": "approved_gold_human_likeness_v1"}
    notes_parts = []
    body_text = _mail_plain_text_from_html(final_body_html)
    paragraph_count = len(re.findall(r"<p[^>]*>", final_body_html or ""))
    fallback_markers_hit = [m for m in _MAIL_FALLBACK_TEMPLATE_MARKERS if m in body_text]

    affinity_score = 0
    if re.search(r"(您好|Dear|Hi)\s*[\u4e00-\u9fffA-Za-z\[\] ]{0,30}", body_text):
        affinity_score += 7
    if any(term in body_text for term in ("供您参考", "如果您", "也欢迎", "方便", "随时", "希望")):
        affinity_score += 8
    if any(term in body_text for term in ("省时", "省心", "省力", "一站式", "减少", "统一协调", "备选")):
        affinity_score += 7
    if paragraph_count >= 3 and 120 <= len(body_text) <= 1200:
        affinity_score += 5
    if not any(term in body_text for term in _MAIL_ROBOTIC_OR_PUSHY_TERMS):
        affinity_score += 3
    else:
        notes_parts.append("存在系统化或强推表达")
    breakdown["human_affinity"] = min(30, affinity_score)

    similarity = _mail_best_approved_gold_similarity(db, scenario=scenario, body_text=body_text)
    similarity_score = min(30, int(round(similarity["score"] * 30)))
    if similarity_score < 12:
        notes_parts.append("与人工认可 full_email 的词汇/场景重合偏低")
    breakdown["approved_gold_similarity"] = similarity_score
    breakdown["matched_gold_source_ref"] = similarity.get("best_source_ref")
    breakdown["matched_gold_title"] = similarity.get("best_title")
    breakdown["matched_gold_overlap_terms"] = similarity.get("overlap_terms") or []

    scenario_score = 0
    if any(term in body_text for term in ("行业", "活动", "会议", "资料", "对外", "市场", "培训", "展会", "视频")):
        scenario_score += 7
    if any(term in body_text for term in ("同传", "多媒体", "排版", "印刷", "商务礼品", "展台", "本地化")):
        scenario_score += 7
    if response_data.get("retrieved_fewshot_id"):
        scenario_score += 4
    if re.search(r"贵司|贵公司|合作|业务", body_text):
        scenario_score += 2
    breakdown["scenario_specificity"] = min(20, scenario_score)

    cta_score = 0
    if any(term in body_text for term in ("如果", "后续", "方便", "需要", "相关团队", "同事", "转给", "推荐")):
        cta_score += 7
    if not re.search(r"电话|邮箱|联系人.{0,4}(?:给我|提供|发我)", body_text):
        cta_score += 3
    else:
        notes_parts.append("结尾仍有直接索要联系人倾向")
    breakdown["low_pressure_next_step"] = min(10, cta_score)

    cleanliness_score = 10
    if fallback_markers_hit:
        cleanliness_score -= 4
        notes_parts.append(f"正文含兜底模板痕迹：{fallback_markers_hit}")
    if re.search(r"\{[^}]+\}|unknown|None|变量|字段", body_text, flags=re.IGNORECASE):
        cleanliness_score -= 3
        notes_parts.append("正文残留变量或字段痕迹")
    sg = response_data.get("safety_guardrail") or {}
    overall = sg.get("overall_outcome") or ""
    if overall.startswith("red_card"):
        cleanliness_score -= 5
        notes_parts.append(f"安全门红牌：{overall}")
    elif overall.startswith("yellow_card"):
        cleanliness_score -= 2
        notes_parts.append(f"安全门黄牌：{overall}")
    breakdown["cleanliness_and_safety"] = max(0, cleanliness_score)

    score = sum(
        int(v)
        for k, v in breakdown.items()
        if k in {
            "human_affinity",
            "approved_gold_similarity",
            "scenario_specificity",
            "low_pressure_next_step",
            "cleanliness_and_safety",
        }
    )
    return {
        "score": score,
        "breakdown": breakdown,
        "notes": "；".join(notes_parts) or "按人工认可黄金邮件标准：亲和、具体、低压力且与 approved full_email 风格接近",
    }


def _run_one_mail_iteration_draft(
    *,
    db: Session,
    run_id: str,
    demo_contact: dict,
    suite_step: int,
) -> None:
    """跑单封草稿，落 mail_iteration_draft 一行。"""
    from database import MailIterationDraft
    demo_index = demo_contact["demo_index"]
    scenario = demo_contact["default_scenario"]
    payload = MailGenerateDraftRequest(
        customer_key=demo_contact["customer_key"],
        contact_email=demo_contact["contact_email"],
        cc_emails=[],
        scenario=scenario,
        suite_step=suite_step,
        current_seller_name=demo_contact.get("default_seller_name") or "销售测试",
        current_seller_signature=demo_contact.get("default_seller_signature") or "销售测试\n事必达翻译与本地化部",
    )

    started_at = datetime.utcnow()
    draft_row = MailIterationDraft(
        run_id=run_id,
        demo_index=demo_index,
        demo_label=demo_contact.get("demo_label"),
        scenario=scenario,
        suite_step=suite_step,
        customer_key=payload.customer_key,
        contact_email=payload.contact_email,
        request_payload=payload.model_dump(),
        status="running",
        started_at=started_at,
    )
    db.add(draft_row)
    db.commit()

    try:
        # 注意: _build_mail_generate_draft_response 内部会调用 _assemble_mail_draft_from_intent_profile
        # 我们需要拿到 llm_prompt，但 response 顶层 contract 没暴露。这里直接复算一份 prompt 落库。
        # 为了准确，我们调一份内部装配再读 assembled.llm_prompt。
        step = get_mail_sequence_step(payload.scenario, int(payload.suite_step))
        interval = get_mail_sequence_step_interval(payload.scenario, int(payload.suite_step))
        min_score = _mail_fewshot_min_score()
        fewshot_examples = _mail_generate_draft_fewshot_candidates(
            db,
            scenario=payload.scenario,
            suite_step=int(payload.suite_step),
            function_fragments=tuple(step.recommended_snippet_types),
            min_score=min_score,
            limit=3,
        )
        fewshot = fewshot_examples[0] if fewshot_examples else None
        commercial_terms = _resolve_mail_commercial_terms(db, suite_step=int(payload.suite_step))
        sequence_template = _get_mail_sequence_template_for_prompt(
            db,
            payload.scenario,
            int(payload.suite_step),
            customer_key=payload.customer_key,
        )
        if not sequence_template or not sanitize_text(sequence_template.get("ai_instruction_script")).strip():
            raise HTTPException(
                status_code=422,
                detail=f"不存在可用脚本：scenario={payload.scenario}, suite_step={int(payload.suite_step)}, template_customer_key=EMPTY",
            )
        intent_profile = _build_mail_draft_intent_profile(
            payload=payload,
            step=step,
            interval=interval,
            admitted_fewshot=fewshot,
            admitted_fewshots=fewshot_examples,
            commercial_terms=commercial_terms,
            sequence_template=sequence_template,
        )
        intent_profile.prompt_full_email_examples = _mail_full_email_gold_examples_for_prompt(
            db,
            scenario=payload.scenario,
            min_score=min_score,
            limit=5,
        )
        intent_profile.prompt_contract_case_examples = _mail_contract_case_examples_for_prompt(
            db,
            industry=_mail_generation_industry_for_prompt(intent_profile),
            limit=5,
        )
        assembled = _assemble_mail_draft_from_intent_profile(intent_profile)
        # 拿到 llm_prompt 后调真正 endpoint 拿完整响应
        response = _build_mail_generate_draft_response(db, payload)
        response_dict = response.model_dump()

        elapsed_ms = int((datetime.utcnow() - started_at).total_seconds() * 1000)
        quality = _score_mail_iteration_draft(
            db=db,
            scenario=payload.scenario,
            response_data=response_dict,
            elapsed_ms=elapsed_ms,
            final_subject=response.final_subject,
            final_body_html=response.final_body_html,
        )

        # 更新落库
        draft_row.llm_prompt = (assembled.llm_prompt or "")[:8000]
        draft_row.llm_status = response.llm_status
        draft_row.llm_model_used = response.llm_model_used
        draft_row.llm_error = response.llm_error
        draft_row.response_payload = response_dict
        draft_row.final_subject = response.final_subject
        draft_row.final_body_html = response.final_body_html
        draft_row.retrieved_fewshot_id = response.retrieved_fewshot_id
        if response.fewshot_match_score is not None:
            try:
                draft_row.fewshot_match_score = Decimal(str(response.fewshot_match_score)).quantize(Decimal("0.0001"))
            except Exception:
                pass
        sg = response_dict.get("safety_guardrail") or {}
        draft_row.overall_outcome = sg.get("overall_outcome")
        draft_row.safety_status = sg.get("status")
        draft_row.quality_score = Decimal(str(quality["score"]))
        draft_row.quality_breakdown = quality["breakdown"]
        draft_row.quality_notes = quality["notes"]
        draft_row.elapsed_ms = elapsed_ms
        draft_row.status = "success"
        draft_row.finished_at = datetime.utcnow()
        db.commit()
    except Exception as exc:
        logger.exception("MAIL_ITERATION_DRAFT_FAILED run=%s demo=%s step=%s", run_id, demo_index, suite_step)
        draft_row.status = "failed"
        draft_row.error_message = str(exc)[:500]
        draft_row.finished_at = datetime.utcnow()
        draft_row.elapsed_ms = int((datetime.utcnow() - started_at).total_seconds() * 1000)
        try:
            db.commit()
        except Exception:
            db.rollback()


def _run_mail_iteration_background(run_id: str, run_label: str) -> None:
    """后台线程入口：跑当前 3 案例 × 4 步 = 12 封，落库并更新 run 统计。"""
    from database import MailIterationRun, MailIterationDraft, MailDemoContact
    from mail_sequence_strategy import ALL_MAIL_SEQUENCE_STEPS
    db = SessionLocal()
    try:
        run_row = db.query(MailIterationRun).filter(MailIterationRun.run_id == run_id).first()
        if not run_row:
            logger.error("MAIL_ITERATION_RUN not found: %s", run_id)
            return
        run_row.started_at = datetime.utcnow()
        run_row.status = "running"
        db.commit()

        demo_rows = db.query(MailDemoContact).filter(
            MailDemoContact.is_current_test_case.is_(True)
        ).order_by(MailDemoContact.demo_index).all()
        rows_by_key = {
            (r.real_customer_key or "").strip().upper(): r
            for r in demo_rows
            if (r.real_customer_key or "").strip()
        }
        demo_contacts = []
        for current_case in MAIL_CURRENT_DEMO_CASES:
            r = rows_by_key.get(current_case["real_customer_key"].upper())
            crm_detail = _fetch_mail_current_case_crm_detail(current_case["real_customer_key"])
            contact_email = _mail_demo_contact_email_for_draft(
                crm_detail.get("contact_email")
                if crm_detail.get("crm_lookup_status") == "matched_crm_contact_id_or_customer_id"
                else (r.contact_email_masked if r else "")
            )
            demo_contacts.append({
                "demo_index": current_case["demo_index"],
                "demo_label": r.demo_label if r else current_case["demo_label"],
                "customer_key": current_case["real_customer_key"],
                "contact_email": contact_email,
                "default_scenario": r.default_scenario if r else current_case["default_scenario"],
                "default_suite_step": r.default_suite_step if r else current_case["default_suite_step"],
                "default_seller_name": r.default_seller_name if r else "销售测试",
                "default_seller_signature": r.default_seller_signature if r else "销售测试\n事必达多业务开发部",
            })

        steps = list(ALL_MAIL_SEQUENCE_STEPS)
        total = len(demo_contacts) * len(steps)
        run_row.total_drafts = total
        db.commit()

        for contact in demo_contacts:
            for step_no in steps:
                _run_one_mail_iteration_draft(
                    db=db, run_id=run_id, demo_contact=contact, suite_step=step_no
                )

        # 汇总统计
        all_drafts = db.query(MailIterationDraft).filter(MailIterationDraft.run_id == run_id).all()
        succeeded = sum(1 for d in all_drafts if d.status == "success")
        failed = sum(1 for d in all_drafts if d.status == "failed")
        llm_success = sum(1 for d in all_drafts if d.llm_status == "success")
        llm_fallback = sum(1 for d in all_drafts if d.llm_status == "fallback_template")
        scored = [float(d.quality_score) for d in all_drafts if d.quality_score is not None]
        elapsed = [d.elapsed_ms for d in all_drafts if d.elapsed_ms is not None]

        run_row.succeeded_drafts = succeeded
        run_row.failed_drafts = failed
        run_row.llm_success_count = llm_success
        run_row.llm_fallback_count = llm_fallback
        run_row.avg_quality_score = Decimal(str(round(sum(scored) / len(scored), 2))) if scored else None
        run_row.min_quality_score = Decimal(str(round(min(scored), 2))) if scored else None
        run_row.max_quality_score = Decimal(str(round(max(scored), 2))) if scored else None
        run_row.avg_elapsed_ms = int(sum(elapsed) / len(elapsed)) if elapsed else None
        run_row.finished_at = datetime.utcnow()
        run_row.status = "success" if failed == 0 else ("partial" if succeeded > 0 else "failed")
        db.commit()
        logger.info("MAIL_ITERATION_RUN_COMPLETED run=%s status=%s succeeded=%d failed=%d", run_id, run_row.status, succeeded, failed)
    except Exception as exc:
        logger.exception("MAIL_ITERATION_RUN_FAILED run=%s", run_id)
        try:
            run_row = db.query(MailIterationRun).filter(MailIterationRun.run_id == run_id).first()
            if run_row:
                run_row.status = "failed"
                run_row.error_message = str(exc)[:1000]
                run_row.finished_at = datetime.utcnow()
                db.commit()
        except Exception:
            db.rollback()
    finally:
        db.close()


class MailIterationRunRequest(BaseModel):
    run_label: str | None = None
    triggered_by: str | None = None
    notes: str | None = None

    model_config = {"extra": "forbid"}


@app.post("/api/v1/mail/iterations/run")
def trigger_mail_iteration_run(payload: MailIterationRunRequest, db: Session = Depends(get_db)):
    """触发一次邮件 AI 回复迭代：当前 3 案例 × 4 步 = 12 封，后台线程跑完落库。立即返回 run_id。"""
    from database import MailIterationRun, MailDemoContact
    import threading
    # 当前迭代只跑产品指定的 3 个客户编号；旧 5 个脱敏案例保留但不参与新测试。
    demo_count = len(MAIL_CURRENT_DEMO_CASES)

    # 自增版本号
    last = db.query(MailIterationRun).order_by(MailIterationRun.version_no.desc()).first()
    next_version = (last.version_no + 1) if last else 1

    runtime_settings = _load_runtime_settings_with_defaults()
    sys_prompt = runtime_settings.get("mail_system_prompt") or _MAIL_DRAFT_LLM_SYSTEM_PROMPT
    run_row = MailIterationRun(
        version_no=next_version,
        run_label=(payload.run_label or f"邮件迭代 v{next_version}").strip(),
        triggered_by=(payload.triggered_by or "manual").strip(),
        triggered_at=datetime.utcnow(),
        status="queued",
        notes=(payload.notes or "").strip() or None,
        pipeline_snapshot={
            "llm_model": getattr(settings, "LLM1_MODEL", "") or "llm1",
            "llm_url": getattr(settings, "LLM1_API_URL", "") or "",
            "system_prompt_first_120_chars": sys_prompt[:120],
            "demo_contact_count": demo_count,
            "demo_contact_scope": "current_3_cases",
            "current_case_customer_keys": [item["real_customer_key"] for item in MAIL_CURRENT_DEMO_CASES],
            "version_no": next_version,
            "snapshot_at": datetime.utcnow().isoformat(timespec="seconds") + "Z",
        },
    )
    db.add(run_row)
    db.commit()
    db.refresh(run_row)
    run_id = str(run_row.run_id)
    run_label = run_row.run_label

    threading.Thread(
        target=_run_mail_iteration_background,
        args=(run_id, run_label),
        daemon=True,
        name=f"mail-iteration-{run_id[:8]}",
    ).start()

    return {
        "run_id": run_id,
        "version_no": next_version,
        "run_label": run_label,
        "status": "queued",
        "total_drafts_planned": demo_count * 4,
        "started_in_background_thread": True,
        "notice": "本次迭代会串行跑当前 3 案例 × 4 步 = 12 封邮件，预计 3-8 分钟。前端轮询 GET /api/v1/mail/iterations/{run_id} 查看实时进度。",
    }


