@app.get("/api/v1/mail/gold-fewshot-seeds")
def list_mail_gold_fewshot_seeds(db: Session = Depends(get_db)):
    """返回 email_fragment_asset 表里邮件 Few-Shot 用的全部黄金种子。

    v1.7.213 起包含两类来源：
      - source_type='mail_gold_seed'              : 25 条销售开发邮件 (greetings/example/process), 来源 docs/mail_gold_candidates/latest_*.json
      - source_type='mail_pricing_constraint_seed': 20 条报价/约束话术规则 (quotation/constraint), 来源 knowledge_chunk 表

    本接口只读, 不真写库。
    """
    MAIL_FEWSHOT_SOURCE_TYPES = ('mail_gold_seed', 'mail_pricing_constraint_seed')
    rows = db.query(EmailFragmentAsset).filter(
        EmailFragmentAsset.source_type.in_(MAIL_FEWSHOT_SOURCE_TYPES)
    ).order_by(EmailFragmentAsset.source_ref).all()

    # 人工评审(认可/不认可+点评)按 fragment_id 索引, 一条种子一行最新
    review_map = {
        str(rv.fragment_id): rv
        for rv in db.query(MailGoldSeedReview).all()
    }

    items = []
    for r in rows:
        review = review_map.get(str(r.fragment_id))
        snapshot = r.source_snapshot or {}
        # v1.7.219: 拍平切片元信息供前端展示
        segment_metadata = None
        if snapshot.get("segment_no") is not None:
            segment_metadata = {
                "segment_no": snapshot.get("segment_no"),
                "segment_total": snapshot.get("segment_total"),
                "segment_char_count": snapshot.get("segment_char_count"),
                "segment_start_char": snapshot.get("segment_start_char"),
                "segment_end_char": snapshot.get("segment_end_char"),
                "kg_fragment_inferred": snapshot.get("kg_fragment_inferred"),
                "function_fragment_mapped": snapshot.get("function_fragment_mapped"),
                "parent_candidate_id": snapshot.get("parent_candidate_id"),
                "parent_subject": snapshot.get("parent_subject"),
                "split_method": snapshot.get("split_method"),
                "bullet_cleaned": snapshot.get("bullet_cleaned", False),
            }
        items.append({
            "fragment_id": str(r.fragment_id),
            "source_type": r.source_type,
            "source_ref": r.source_ref,
            "title": r.title,
            "content": r.content,
            "content_preview": (r.content or "")[:200],
            "scenario_label": r.scenario_label,
            "intent_label": r.intent_label,
            "function_fragment": r.function_fragment,
            "language_style": r.language_style,
            "useful_score": float(r.useful_score) if r.useful_score is not None else None,
            "library_type": r.library_type,
            "usable_for_reply": r.usable_for_reply,
            "allowed_for_generation": r.allowed_for_generation,
            "publishable": r.publishable,
            "status": r.status,
            "candidate_rank": snapshot.get("candidate_rank"),
            "desensitized_status": snapshot.get("desensitized_status"),
            "desensitized_fields": snapshot.get("desensitized_fields") or [],
            "sqlserver_source_ref": snapshot.get("sqlserver_source_ref"),
            "kb_chunk_id": snapshot.get("kb_chunk_id"),
            "kb_business_line": snapshot.get("kb_business_line"),
            "score_source": snapshot.get("score_source"),
            "seed_source_file": snapshot.get("seed_source_file"),
            "segment_metadata": segment_metadata,
            "selection_reason": (
                (snapshot.get("promo_analysis") or {}).get("selection_reason")
                if r.function_fragment == "full_email"
                else ""
            ),
            "promo_analysis": (
                snapshot.get("promo_analysis")
                if r.function_fragment == "full_email"
                else None
            ),
            "review_status": review.review_status if review else None,
            "review_comment": review.review_comment if review else None,
            "review_updated_at": review.updated_at.isoformat() if review and review.updated_at else None,
            "created_at": r.created_at.isoformat() if r.created_at else None,
            "updated_at": r.updated_at.isoformat() if r.updated_at else None,
        })

    # 排序: 先按 source_type (mail_gold_seed 前 / pricing_constraint 后), 再按 candidate_rank / source_ref
    _source_order = {"mail_gold_seed": 0, "mail_pricing_constraint_seed": 1}
    items.sort(key=lambda x: (
        _source_order.get(x.get("source_type"), 9),
        x.get("candidate_rank") or 9999,
        x.get("source_ref") or "",
    ))

    return {
        "version": "mail_gold_fewshot_seeds.v2",
        "source": "email_fragment_asset where source_type IN ('mail_gold_seed','mail_pricing_constraint_seed')",
        "read_only": True,
        "count": len(items),
        "seeds": items,
        "loader_scripts": [
            "backend/seed_mail_gold_candidates.py",
            "backend/seed_mail_pricing_constraint_from_kb.py",
        ],
        "data_origins": {
            "mail_gold_seed": "docs/mail_gold_candidates/latest_mail_gold_candidates.json（脱敏后入库）",
            "mail_pricing_constraint_seed": "knowledge_chunk 表 chunk_type IN ('constraint','rule' AND knowledge_type='pricing')",
        },
    }


class MailGoldSeedReviewRequest(BaseModel):
    fragment_id: str
    review_status: str  # approved / rejected
    review_comment: str | None = None
    source_ref: str | None = None
    reviewer: str | None = None


@app.post("/api/v1/mail/gold-seed-review")
def save_mail_gold_seed_review(payload: MailGoldSeedReviewRequest, db: Session = Depends(get_db)):
    """保存黄金种子的人工评审(认可/不认可 + 点评)。一条种子一行, 再次提交覆盖最新。"""
    status = (payload.review_status or "").strip()
    if status not in ("approved", "rejected", "needs_revision"):
        raise HTTPException(status_code=400, detail="review_status 必须是 approved / rejected / needs_revision")
    fragment_id = (payload.fragment_id or "").strip()
    if not fragment_id:
        raise HTTPException(status_code=400, detail="fragment_id 不能为空")

    # 校验种子存在
    seed = db.query(EmailFragmentAsset).filter(
        EmailFragmentAsset.fragment_id == fragment_id
    ).first()
    if not seed:
        raise HTTPException(status_code=404, detail="未找到对应黄金种子")

    review = db.query(MailGoldSeedReview).filter(
        MailGoldSeedReview.fragment_id == fragment_id
    ).first()
    comment = (payload.review_comment or "").strip() or None
    if review:
        review.review_status = status
        review.review_comment = comment
        review.source_ref = payload.source_ref or seed.source_ref
        review.reviewer = payload.reviewer or review.reviewer
    else:
        review = MailGoldSeedReview(
            fragment_id=fragment_id,
            source_ref=payload.source_ref or seed.source_ref,
            review_status=status,
            review_comment=comment,
            reviewer=payload.reviewer,
        )
        db.add(review)
    db.commit()
    db.refresh(review)
    return {
        "status": "success",
        "fragment_id": fragment_id,
        "review_status": review.review_status,
        "review_comment": review.review_comment,
        "review_updated_at": review.updated_at.isoformat() if review.updated_at else None,
    }


class MailGoldSeedContentRequest(BaseModel):
    fragment_id: str
    title: str | None = None
    content: str | None = None


@app.post("/api/v1/mail/gold-seed-content")
def save_mail_gold_seed_content(payload: MailGoldSeedContentRequest, db: Session = Depends(get_db)):
    """保存对黄金种子主题/正文的人工修改。空字段不更新。"""
    fragment_id = (payload.fragment_id or "").strip()
    if not fragment_id:
        raise HTTPException(status_code=400, detail="fragment_id 不能为空")
    seed = db.query(EmailFragmentAsset).filter(
        EmailFragmentAsset.fragment_id == fragment_id
    ).first()
    if not seed:
        raise HTTPException(status_code=404, detail="未找到对应黄金种子")

    changed = []
    if payload.title is not None:
        new_title = payload.title.strip()
        if not new_title:
            raise HTTPException(status_code=400, detail="主题不能为空")
        if new_title != (seed.title or ""):
            seed.title = new_title[:255]
            changed.append("title")
    if payload.content is not None:
        if payload.content != (seed.content or ""):
            seed.content = payload.content
            changed.append("content")
    if changed:
        # 标记人工编辑过, 便于后续追溯
        snap = dict(seed.source_snapshot or {})
        snap["manual_edited"] = True
        snap["manual_edited_fields"] = sorted(set((snap.get("manual_edited_fields") or []) + changed))
        seed.source_snapshot = snap
        seed.updated_at = datetime.utcnow()
        db.commit()
        db.refresh(seed)
    return {
        "status": "success",
        "fragment_id": fragment_id,
        "changed": changed,
        "title": seed.title,
        "content": seed.content,
        "updated_at": seed.updated_at.isoformat() if seed.updated_at else None,
    }


def _local_contract_case_to_dict(item: MailContractCase) -> dict[str, Any]:
    flags = item.quality_flags or []
    if not isinstance(flags, list):
        flags = [flags]
    return {
        "contract_id": item.contract_id,
        "customer_id": item.customer_id,
        "contact_id": item.contact_id,
        "total_money": float(item.total_money or 0),
        "amount_bucket": item.amount_bucket,
        "product_name_all": item.product_name_all,
        "business_type": item.business_type,
        "contract_description": item.contract_description,
        "company_name": item.company_name,
        "input_time": item.input_time.isoformat(timespec="seconds") if item.input_time else None,
        "contract_time": item.contract_time.isoformat(timespec="seconds") if item.contract_time else None,
        "start_time": item.start_time.isoformat(timespec="seconds") if item.start_time else None,
        "end_time": item.end_time.isoformat(timespec="seconds") if item.end_time else None,
        "business_line_inferred": item.business_line_inferred,
        "language_pair_inferred": item.language_pair_inferred,
        "industry_inferred": item.industry_inferred,
        "quality_flags": flags,
        "mail_case_text": item.mail_case_text,
        "case_text_raw": "；".join(
            part for part in [
                f"业务类型：{item.business_type}" if item.business_type else "",
                f"产品：{item.product_name_all}" if item.product_name_all else "",
                f"描述：{item.contract_description}" if item.contract_description else "",
                f"行业线索：{item.industry_inferred}" if item.industry_inferred and item.industry_inferred != "unknown" else "",
            ]
            if part
        ),
        "storage_suggestion": {
            "target": "mail_contract_case_library",
            "ready_for_generation": bool(
                float(item.total_money or 0) >= 5000
                and item.contract_description
                and len(item.contract_description) >= 4
                and "可能是补差价/尾款" not in flags
            ),
            "needs_review": True,
            "reason": "当前接口只读展示原始合同案例候选，未脱敏、未入库；入库前需人工确认产品/行业/描述是否可作为案例。",
        },
    }


