CASELIB_BACKGROUND_THREAD: dict[str, threading.Thread] = {}


def _caselib_resolve_git_info() -> dict:
    info = {"sha": None, "short_sha": None, "branch": None, "dirty": False}
    try:
        repo_root = os.path.dirname(os.path.dirname(os.path.abspath(__file__)))
        sha = subprocess.run(["git", "rev-parse", "HEAD"], cwd=repo_root,
                             capture_output=True, text=True, timeout=5)
        if sha.returncode == 0:
            info["sha"] = sha.stdout.strip()
            info["short_sha"] = info["sha"][:8]
        br = subprocess.run(["git", "rev-parse", "--abbrev-ref", "HEAD"], cwd=repo_root,
                            capture_output=True, text=True, timeout=5)
        if br.returncode == 0:
            info["branch"] = br.stdout.strip()
        st = subprocess.run(["git", "status", "--porcelain"], cwd=repo_root,
                            capture_output=True, text=True, timeout=5)
        if st.returncode == 0:
            info["dirty"] = bool(st.stdout.strip())
    except Exception as e:
        logging.getLogger(__name__).warning(f"git info fail: {e}")
    return info


def _caselib_next_version_no(db: Session) -> int:
    row = db.execute(text("SELECT COALESCE(MAX(version_no), 0) FROM case_iteration_run")).fetchone()
    return int((row[0] if row else 0) or 0) + 1


def _caselib_load_json(v):
    if v is None: return None
    if isinstance(v, (dict, list)): return v
    try:
        return json.loads(v)
    except Exception:
        return v


def _caselib_ai_score_from_step7(step7) -> float | None:
    """AI 质量分：reply_scores_v2.ai_candidates 中 overall 最高者(7 维绝对质量, qwen14b)。"""
    data = _caselib_load_json(step7) or {}
    if not isinstance(data, dict):
        return None
    cands = data.get("ai_candidates") or []
    scores = []
    for item in cands:
        if not isinstance(item, dict) or item.get("score_reason") == "llm1_failed":
            continue
        val = item.get("overall_score")
        if val is None and isinstance(item.get("scores"), dict):
            val = item["scores"].get("overall")
        try:
            if val is not None:
                scores.append(float(val))
        except Exception:
            continue
    return round(max(scores), 2) if scores else None


def _caselib_sales_score_from_step7(step7) -> float | None:
    data = _caselib_load_json(step7) or {}
    if not isinstance(data, dict):
        return None
    replies = data.get("actual_sales_replies") or []
    if not replies:
        return None
    scores = []
    for item in replies:
        if not isinstance(item, dict) or item.get("score_reason") == "llm1_failed":
            continue
        val = item.get("overall_score")
        if val is None and isinstance(item.get("scores"), dict):
            val = item["scores"].get("overall")
        try:
            if val is not None:
                scores.append(float(val))
        except Exception:
            continue
    return round(sum(scores) / len(scores), 2) if scores else None


