@app.get("/api/case_lib/results/{result_id}")
async def caselib_get_result_detail(result_id: str):
    """单行完整详情(7步链路 + 完整案例背景)，供前端 hover 浮层与双击弹窗按需懒加载。
    两种 ID 都支持:
      1) 迭代评测的 CaseIterationResult.result_id
      2) v1.7.188: 实时验证(daily)的 ApiAssistInvocation.invocation_id
         —— daily 列表为了控制响应体积只下发 step4_knowledge 的瘦字段(40KB→<1KB),
         需要完整 hits/evidence/replyable_hits 时由前端 caselibEnsureResultDetail 调本接口懒加载。"""
    db = SessionLocal()
    try:
        rr = db.query(CaseIterationResult).filter(
            CaseIterationResult.result_id == result_id
        ).first()
        if rr:
            case_meta = None
            c = db.query(CaseLibraryCase).filter(
                CaseLibraryCase.case_id == str(rr.case_id)
            ).first()
            if c:
                turns = db.query(CaseLibraryDialogueTurn).filter(
                    CaseLibraryDialogueTurn.case_id == str(rr.case_id)
                ).order_by(CaseLibraryDialogueTurn.turn_no).all()
                case_meta = _caselib_serialize_case(c, turns, None)
            item = _caselib_serialize_result(rr, case_meta)
            if rr.turn_id:
                t = db.query(CaseLibraryDialogueTurn).filter(
                    CaseLibraryDialogueTurn.turn_id == rr.turn_id
                ).first()
                if t:
                    item["turn"] = _caselib_serialize_turn(t)
            return {"status": "success", "result": item}

        # v1.7.188: 回退到 ApiAssistInvocation(daily/实时验证)。result_id 是 invocation_id(UUID)。
        # 非 UUID 形态(如本地占位 'daily_turn_...') 直接 404。
        inv = None
        try:
            inv = db.query(ApiAssistInvocation).filter(
                ApiAssistInvocation.invocation_id == result_id
            ).first()
        except Exception:
            inv = None
        if inv and inv.result_payload:
            rp = dict(inv.result_payload or {})
            kv2 = rp.get("knowledge_v2")
            item = {
                "result_id": str(inv.invocation_id),
                "case_id": inv.session_id,
                "scenario_code": "实时",
                "step1_summary": {
                    "topic": rp.get("topic"),
                    "core_demand": rp.get("core_demand"),
                    "status": rp.get("status") or "done",
                },
                "step2_crm_info": rp.get("crm_info"),
                "step3_thread_business_fact": rp.get("thread_business_fact"),
                # 完整 knowledge_v2(hits / evidence_refs / evidence_context / replyable_hits)
                "step4_knowledge": {
                    "knowledge_status": rp.get("knowledge_status") or (kv2.get("status") if isinstance(kv2, dict) else None) or "done",
                    "knowledge_v2": kv2 if isinstance(kv2, dict) else None,
                },
                "step6_sales_advice": rp.get("reply_reference") or "",
                "step7_reply_scores": rp.get("reply_scores_v2"),
                "stage_status": rp.get("stage_status") or {},
                "quality_score": float(inv.quality_score) if inv.quality_score is not None else None,
                "quality_status": inv.quality_status,
                "training_ai_reply": (rp.get("training_ai") or {}).get("reply") if isinstance(rp.get("training_ai"), dict) else "",
            }
            return {"status": "success", "result": item}

        raise HTTPException(status_code=404, detail="result not found")
    finally:
        db.close()


@app.get("/api/case_lib/cases")
async def caselib_list_cases(scenario_code: str | None = Query(default=None)):
    db = SessionLocal()
    try:
        q = db.query(CaseLibraryCase)
        if scenario_code:
            q = q.filter(CaseLibraryCase.scenario_code == scenario_code)
        rows = q.order_by(CaseLibraryCase.scenario_code, CaseLibraryCase.scenario_rank).all()
        case_ids = [str(c.case_id) for c in rows]
        turns_by_case: dict[str, list[CaseLibraryDialogueTurn]] = {cid: [] for cid in case_ids}
        if case_ids:
            turn_rows = db.query(CaseLibraryDialogueTurn).filter(
                CaseLibraryDialogueTurn.case_id.in_(case_ids)
            ).order_by(CaseLibraryDialogueTurn.case_id, CaseLibraryDialogueTurn.turn_no).all()
            for t in turn_rows:
                turns_by_case.setdefault(str(t.case_id), []).append(t)
        sales_scores_by_case: dict[str, list[float]] = {}
        if case_ids:
            rr_rows = db.query(CaseIterationResult.case_id, CaseIterationResult.step7_reply_scores).filter(
                CaseIterationResult.case_id.in_(case_ids)
            ).all()
            for cid, step7 in rr_rows:
                score = _caselib_sales_score_from_step7(step7)
                if score is not None:
                    sales_scores_by_case.setdefault(str(cid), []).append(score)
        manual_avg_by_case = {
            cid: round(sum(vals) / len(vals), 2)
            for cid, vals in sales_scores_by_case.items()
            if vals
        }
        return {
            "status": "success",
            "total": len(rows),
            "cases": [
                _caselib_serialize_case(
                    c,
                    turns_by_case.get(str(c.case_id), []),
                    manual_avg_by_case.get(str(c.case_id)),
                )
                for c in rows
            ],
        }
    finally:
        db.close()


@app.get("/api/case_lib/cases/{case_id}")
async def caselib_get_case(case_id: str):
    db = SessionLocal()
    try:
        c = db.query(CaseLibraryCase).filter(CaseLibraryCase.case_id == case_id).first()
        if not c:
            raise HTTPException(status_code=404, detail="case not found")
        turns = db.query(CaseLibraryDialogueTurn).filter(
            CaseLibraryDialogueTurn.case_id == case_id
        ).order_by(CaseLibraryDialogueTurn.turn_no).all()
        score_rows = db.query(CaseIterationResult.step7_reply_scores).filter(
            CaseIterationResult.case_id == case_id
        ).all()
        scores = [
            s for (step7,) in score_rows
            for s in [_caselib_sales_score_from_step7(step7)]
            if s is not None
        ]
        avg = round(sum(scores) / len(scores), 2) if scores else None
        return {"status": "success", "case": _caselib_serialize_case(c, turns, avg)}
    finally:
        db.close()


def parse_session_id(uid: str, sales_ids: list) -> tuple | None:
    if not uid.startswith("single_"):
        return None
    core = uid[7:]
    for s_id in sales_ids:
        if core.startswith(s_id + "_"):
            return s_id, core[len(s_id) + 1:]
        elif core.endswith("_" + s_id):
            return s_id, core[:-len(s_id) - 1]
    return None


def _get_daily_validation_stats(db: Session, day_start: datetime, day_end: datetime):
    """按企微实时辅助 API 记录统计每日验证轮次。

    入参 day_start/day_end 为北京-naive 自然日边界；ApiAssistInvocation.triggered_at
    是 UTC，函数内转换为 UTC 边界。统计口径与 /api/case_lib/daily_validation/{date}?view=api
    对齐：只统计销售-外部联系人的客户消息锚点调用，并按 (session_id, anchor_message_id)
    去重，优先保留已评分且较新的调用。这样列表的完成进度不再显示 0/0。
    """
    day_start_utc = day_start - timedelta(hours=8)
    day_end_utc = day_end - timedelta(hours=8)
    sales_ids = ["alicehe", "davidXiaoMeiPeng", "HanHan", "joycesheng", "WangHuiYing"]

    invs = db.query(ApiAssistInvocation).filter(
        ApiAssistInvocation.triggered_at >= day_start_utc,
        ApiAssistInvocation.triggered_at < day_end_utc,
        ApiAssistInvocation.session_id.isnot(None),
        ApiAssistInvocation.anchor_message_id.isnot(None),
    ).all()

    def _is_external_single_session(session_id: str | None) -> bool:
        parsed = parse_session_id(str(session_id or ""), sales_ids)
        if not parsed:
            return False
        _sales_userid, external_userid = parsed
        return str(external_userid or "").startswith(("wm", "wo"))

    def _inv_rank(inv: ApiAssistInvocation) -> tuple:
        scored = 1 if (inv.quality_status == "scored" or inv.quality_score is not None) else 0
        return (scored, inv.triggered_at or datetime.min)

    inv_map = {}
    for inv in invs:
        if not _is_external_single_session(inv.session_id):
            continue
        key = (inv.session_id, inv.anchor_message_id)
        existing = inv_map.get(key)
        if existing is None or _inv_rank(inv) >= _inv_rank(existing):
            inv_map[key] = inv

    selected = list(inv_map.values())
    valid_scores = []
    total_latency = 0
    latency_count = 0

    for inv in selected:
        payload = inv.result_payload if isinstance(inv.result_payload, dict) else {}
        rs2 = payload.get("reply_scores_v2") if isinstance(payload, dict) else None
        ai_overall = _caselib_ai_score_from_step7(rs2)
        if ai_overall is None and inv.quality_score is not None:
            ai_overall = float(inv.quality_score)
        if ai_overall is not None:
            valid_scores.append(ai_overall)
        timings = payload.get("timings_ms") if isinstance(payload, dict) else None
        if isinstance(timings, dict):
            try:
                latency = int(float(timings.get("total_ms") or 0))
            except (TypeError, ValueError):
                latency = 0
            if latency > 0:
                total_latency += latency
                latency_count += 1

    avg_score = round(sum(valid_scores) / len(valid_scores), 2) if valid_scores else None
    avg_latency = int(total_latency / latency_count) if latency_count > 0 else None
    return len(selected), avg_score, avg_latency


def _get_daily_validation_stats_range(
    db: Session, range_start_bj: datetime, range_end_bj: datetime
) -> dict[str, tuple[int, float | None, int | None]]:
    """一次性统计 [range_start_bj, range_end_bj) 北京自然日区间内每天的验证轮次。

    替代"按天循环 N 次全行查询"以避免语句超时(QueryCanceled):
      1. 第一遍只查轻量列(不含大 JSON result_payload), 整段一次取出, 按北京日分桶并去重;
      2. 第二遍仅对去重命中的 invocation_id 批量补取 result_payload/quality_score。
    返回 {北京日期字符串: (count, avg_score, avg_latency)}。
    """
    range_start_utc = range_start_bj - timedelta(hours=8)
    range_end_utc = range_end_bj - timedelta(hours=8)
    sales_ids = ["alicehe", "davidXiaoMeiPeng", "HanHan", "joycesheng", "WangHuiYing"]

    def _is_external_single_session(session_id: str | None) -> bool:
        parsed = parse_session_id(str(session_id or ""), sales_ids)
        if not parsed:
            return False
        _sales_userid, external_userid = parsed
        return str(external_userid or "").startswith(("wm", "wo"))

    light_rows = db.query(
        ApiAssistInvocation.invocation_id,
        ApiAssistInvocation.session_id,
        ApiAssistInvocation.anchor_message_id,
        ApiAssistInvocation.triggered_at,
        ApiAssistInvocation.quality_status,
        ApiAssistInvocation.quality_score,
    ).filter(
        ApiAssistInvocation.triggered_at >= range_start_utc,
        ApiAssistInvocation.triggered_at < range_end_utc,
        ApiAssistInvocation.session_id.isnot(None),
        ApiAssistInvocation.anchor_message_id.isnot(None),
    ).all()

    # per_day[day_str][(session_id, anchor)] = (rank_tuple, light_row)
    per_day: dict[str, dict[tuple, tuple]] = {}
    for r in light_rows:
        if not _is_external_single_session(r.session_id):
            continue
        triggered = r.triggered_at or datetime.min
        day_str = (triggered + timedelta(hours=8)).date().isoformat()
        key = (r.session_id, r.anchor_message_id)
        scored = 1 if (r.quality_status == "scored" or r.quality_score is not None) else 0
        rank = (scored, triggered)
        bucket = per_day.setdefault(day_str, {})
        existing = bucket.get(key)
        if existing is None or rank >= existing[0]:
            bucket[key] = (rank, r)

    selected_ids = [row.invocation_id for bucket in per_day.values() for (_rank, row) in bucket.values()]
    payload_by_id: dict[Any, tuple] = {}
    if selected_ids:
        # 分批 IN 查询; chunk=50 避免大 JSON 列单批超 statement_timeout(20s)
        for i in range(0, len(selected_ids), 50):
            chunk = selected_ids[i : i + 50]
            for inv_id, payload, qscore in db.query(
                ApiAssistInvocation.invocation_id,
                ApiAssistInvocation.result_payload,
                ApiAssistInvocation.quality_score,
            ).filter(ApiAssistInvocation.invocation_id.in_(chunk)).all():
                payload_by_id[inv_id] = (payload, qscore)

    result: dict[str, tuple[int, float | None, int | None]] = {}
    for day_str, bucket in per_day.items():
        valid_scores: list[float] = []
        total_latency = 0
        latency_count = 0
        for (_rank, row) in bucket.values():
            payload, qscore = payload_by_id.get(row.invocation_id, (None, row.quality_score))
            payload = payload if isinstance(payload, dict) else {}
            ai_overall = _caselib_ai_score_from_step7(payload.get("reply_scores_v2"))
            if ai_overall is None and qscore is not None:
                ai_overall = float(qscore)
            if ai_overall is not None:
                valid_scores.append(ai_overall)
            timings = payload.get("timings_ms")
            if isinstance(timings, dict):
                try:
                    latency = int(float(timings.get("total_ms") or 0))
                except (TypeError, ValueError):
                    latency = 0
                if latency > 0:
                    total_latency += latency
                    latency_count += 1
        avg_score = round(sum(valid_scores) / len(valid_scores), 2) if valid_scores else None
        avg_latency = int(total_latency / latency_count) if latency_count > 0 else None
        result[day_str] = (len(bucket), avg_score, avg_latency)
    return result


def _caselib_list_iterations_sync(limit: int, include_daily_stats: bool) -> dict:
    db = SessionLocal()
    try:
        rows = db.query(CaseIterationRun).order_by(
            CaseIterationRun.triggered_at.desc()
        ).limit(limit).all()

        # 每天一行日常验证记录。只取"近 N 天": 历史全量(从 2026-05-26 起)会让下方
        # _get_daily_validation_stats_range 第二遍批量拉 result_payload 大 JSON 超出
        # 数据库 statement_timeout 抛 QueryCanceled(列表 500)。近 5 天扫描量/JSON 量
        # 骤降, 既消除超时又满足"列表只看近几天"的需求; 取数口径不变, 数字不变。
        from datetime import date as pydate
        DAILY_VALIDATION_RECENT_DAYS = 5
        today = (datetime.utcnow() + timedelta(hours=8)).date()
        start_date = today - timedelta(days=DAILY_VALIDATION_RECENT_DAYS - 1)
        daily_rows = []
        # v1.7.310: 整段一次性统计, 避免按天循环 N 次全行查询导致语句超时(QueryCanceled)。
        daily_stats_map: dict[str, tuple] = {}
        if include_daily_stats:
            range_start_bj = datetime(start_date.year, start_date.month, start_date.day)
            range_end_bj = datetime(today.year, today.month, today.day) + timedelta(days=1)
            daily_stats_map = _get_daily_validation_stats_range(db, range_start_bj, range_end_bj)
        curr = start_date
        while curr <= today:
            date_str = curr.isoformat()
            # v1.7.192: 与明细页一致, 按"北京本地自然日"取数。
            day_start_bj = datetime(curr.year, curr.month, curr.day)
            day_end_bj = day_start_bj + timedelta(days=1)

            count, avg_score, avg_latency = daily_stats_map.get(date_str, (0, None, None))

            daily_rows.append({
                "run_id": f"daily_{date_str.replace('-', '')}",
                "version_no": "实时验证",
                "git_commit_sha": "",
                "git_short_sha": "",
                "git_branch": "",
                "git_dirty": False,
                "changed_paths": [],
                "change_summary": f"{date_str} 企微日常会话双向验证",
                "pipeline_config": {},
                "status": "success",
                "total_cases": count,
                "completed_cases": count,
                "success_cases": count,
                "failed_cases": 0,
                "avg_quality_score": avg_score,
                "min_quality_score": None,
                "max_quality_score": None,
                "avg_latency_ms": avg_latency,
                "improvement_analysis": "日常真实会话统计" if include_daily_stats else "日常真实会话入口；本次请求未统计每日轮次",
                "ai_next_step_plan": "",
                "analysis_codex": "",
                "analysis_antigravity": "",
                "analysis_claude_code": "",
                "analysis_summary": "",
                "backup_commit_sha": "",
                "backup_status": "",
                "triggered_by": "api_assist",
                # 北京-naive, 不加 Z; 前端 caselibFormatTime 检测无时区标记 → 不再 +8。
                "triggered_at": day_start_bj.isoformat(),
                "started_at": day_start_bj.isoformat(),
                "finished_at": day_end_bj.isoformat(),
                "error_message": "",
            })
            curr += timedelta(days=1)

        serialized_runs = [_caselib_serialize_run(r) for r in rows]
        combined = daily_rows + serialized_runs
        combined.sort(key=lambda x: x.get("triggered_at") or "", reverse=True)

        return {
            "status": "success",
            "total": len(combined),
            "iterations": combined[:limit],
        }
    finally:
        db.close()


@app.get("/api/case_lib/iterations")
async def caselib_list_iterations(
    limit: int = Query(default=50, ge=1, le=500),
    include_daily_stats: bool = Query(default=True),
):
    # 整段同步 DB 工作(全历史 invocation 扫描 + 大 JSON 聚合)丢到 worker 线程,
    # 不在事件循环主线程上跑; 否则单个慢请求(可达 ~189s)会卡死所有并发请求
    # (详情页/train_ai/models 等会一起排队冻住), 表现为"整站加载卡死"。
    return await asyncio.to_thread(_caselib_list_iterations_sync, limit, include_daily_stats)


@app.get("/api/case_lib/daily_validation/{date}")
async def get_daily_validation_detail(
    date: str,
    view: str = Query(default="api"),
    limit: int = Query(default=300, ge=1, le=1000),
    db: Session = Depends(get_db),
):
    """获取指定日期的日常实时验证明细列表，格式与 iterations/{run_id} 结果对齐"""
    total_started = perf_counter()
    timings_ms: dict[str, float] = {}

    def _mark_timing(name: str, started_at: float) -> None:
        timings_ms[name] = round((perf_counter() - started_at) * 1000, 2)

    try:
        parsed_date = datetime.fromisoformat(date[:10])
    except Exception:
        raise HTTPException(status_code=400, detail="invalid date format, use YYYY-MM-DD")

    # v1.7.192: 修正历史误判 —— 服务器跑在 Beijing TZ, MessageLog.timestamp 由
    # archive_service datetime.fromtimestamp() 写入, 是"北京-naive", **不是 UTC**。
    # 之前 day_start 减 8 小时是按"MessageLog 是 UTC"的错误假设做的, 实际效果是把
    # 北京 5.27 16:00 ~ 5.28 16:00 的消息全网了进来 —— 用户看到的"5.27 数据混进 5.28 详情"。
    # 修正后两表分别按各自实际时区过滤:
    #   - MessageLog (北京-naive): 用 day_start_bj
    #   - ApiAssistInvocation.triggered_at (datetime.utcnow 真 UTC): 用 day_start_utc = bj - 8h
    day_start_bj = datetime(parsed_date.year, parsed_date.month, parsed_date.day)
    day_end_bj = day_start_bj + timedelta(days=1)
    day_start_utc = day_start_bj - timedelta(hours=8)
    day_end_utc = day_end_bj - timedelta(hours=8)
    # 兼容旧代码引用名
    day_start = day_start_bj
    day_end = day_end_bj

    sales_ids = ["alicehe", "davidXiaoMeiPeng", "HanHan", "joycesheng", "WangHuiYing"]
    SALES_NAME_MAP = {
        "alicehe": "何珺",
        "davidXiaoMeiPeng": "肖美鹏",
        "HanHan": "韩瑾",
        "joycesheng": "盛晔",
        "WangHuiYing": "王慧莹"
    }

    stage_started = perf_counter()
    api_fast_view = str(view or "").lower() == "api"
    invs: list[ApiAssistInvocation] = []
    if api_fast_view:
        invs = db.query(ApiAssistInvocation).filter(
            ApiAssistInvocation.triggered_at >= day_start_utc,
            ApiAssistInvocation.triggered_at < day_end_utc,
            ApiAssistInvocation.session_id.isnot(None),
        ).order_by(ApiAssistInvocation.triggered_at.desc()).limit(limit).all()
        _mark_timing("query_invocations_ms", stage_started)

        stage_started = perf_counter()
        api_session_ids = sorted({str(inv.session_id) for inv in invs if inv.session_id})
        logs = []
        if api_session_ids:
            logs = db.query(MessageLog).filter(
                MessageLog.user_id.in_(api_session_ids),
                MessageLog.timestamp >= day_start_bj,
                MessageLog.timestamp < day_end_bj,
                MessageLog.is_mock.is_(False)
            ).order_by(MessageLog.timestamp.asc()).all()
        _mark_timing("query_session_logs_ms", stage_started)
    else:
        logs = db.query(MessageLog).filter(
            MessageLog.timestamp >= day_start_bj,
            MessageLog.timestamp < day_end_bj,
            MessageLog.is_mock.is_(False)
        ).order_by(MessageLog.timestamp.asc()).all()
        _mark_timing("query_all_day_logs_ms", stage_started)

    stage_started = perf_counter()
    session_logs = {}
    for l in logs:
        session_logs.setdefault(l.user_id, []).append(l)

    target_sessions = {}
    for uid, msgs in session_logs.items():
        parsed = parse_session_id(uid, sales_ids)
        if parsed:
            sales_userid, external_userid = parsed
            if external_userid.startswith("wm") or external_userid.startswith("wo"):
                target_sessions[uid] = msgs
    _mark_timing("group_sessions_ms", stage_started)

    if not api_fast_view:
        stage_started = perf_counter()
        invs = db.query(ApiAssistInvocation).filter(
            ApiAssistInvocation.session_id.in_(list(target_sessions.keys())) if target_sessions else False,
            ApiAssistInvocation.triggered_at >= day_start_utc - timedelta(hours=1),
            ApiAssistInvocation.triggered_at < day_end_utc + timedelta(hours=1)
        ).all()
        _mark_timing("query_invocations_ms", stage_started)

    # 同一锚点消息可能被多次触发(先 pending 占位、后补打分)，匹配时优先取"已打分"且最新的那次，
    # 避免命中早先的 pending_no_sales_reply 占位导致 AI 回复/质量分显示为空。
    def _inv_rank(inv: ApiAssistInvocation) -> tuple:
        scored = 1 if (inv.quality_status == "scored" or inv.quality_score is not None) else 0
        return (scored, inv.triggered_at or datetime.min)

    stage_started = perf_counter()
    inv_map = {}
    for inv in invs:
        if inv.anchor_message_id is None:
            continue
        key = (inv.session_id, inv.anchor_message_id)
        existing = inv_map.get(key)
        if existing is None or _inv_rank(inv) >= _inv_rank(existing):
            inv_map[key] = inv
    _mark_timing("build_invocation_map_ms", stage_started)

    results = []
    run_id = f"daily_{date.replace('-', '')}"

    stage_started = perf_counter()
    for uid, msgs in target_sessions.items():
        parsed = parse_session_id(uid, sales_ids)
        if not parsed:
            continue
        sales_userid, external_userid = parsed
        sales_chinese = SALES_NAME_MAP.get(sales_userid, sales_userid)

        consolidated = []
        for m in msgs:
            if not consolidated:
                consolidated.append({
                    "sender_type": m.sender_type,
                    "content": m.content,
                    "timestamp": m.timestamp,
                    "ids": [m.id]
                })
            else:
                last = consolidated[-1]
                if last["sender_type"] == m.sender_type:
                    last["content"] += "\n" + m.content
                    last["ids"].append(m.id)
                    last["timestamp"] = m.timestamp
                else:
                    consolidated.append({
                        "sender_type": m.sender_type,
                        "content": m.content,
                        "timestamp": m.timestamp,
                        "ids": [m.id]
                    })

        groups = []
        current_customer = None
        for turn in consolidated:
            if turn["sender_type"] == "customer":
                if current_customer:
                    groups.append({
                        "type": "unreplied",
                        "customer": current_customer,
                        "sales": None,
                        "timestamp": current_customer["timestamp"]
                    })
                current_customer = turn
            elif turn["sender_type"] == "sales":
                if current_customer:
                    groups.append({
                        "type": "qa",
                        "customer": current_customer,
                        "sales": turn,
                        "timestamp": turn["timestamp"]
                    })
                    current_customer = None
                else:
                    groups.append({
                        "type": "sales_initiated",
                        "customer": None,
                        "sales": turn,
                        "timestamp": turn["timestamp"]
                    })
        if current_customer:
            groups.append({
                "type": "unreplied",
                "customer": current_customer,
                "sales": None,
                "timestamp": current_customer["timestamp"]
            })

        # 一次性载入该会话(最新 ref_time 之前最多 1000 条)历史，循环内内存切片做每轮背景。
        # 替代原来"每轮一次远程查询"的 N+1：那会对远程库几百次往返，曾导致本接口跑 ~28 分钟、
        # 最终 Postgres 连接被掐断(server closed the connection unexpectedly)，并堵死事件循环拖慢全部接口。
        _ref_times = [g.get("timestamp") for g in groups if g.get("timestamp")]
        session_hist_asc: list[MessageLog] = []
        if _ref_times:
            _latest_ref = max(_ref_times)
            session_hist_asc = db.query(MessageLog).filter(
                MessageLog.user_id == uid,
                MessageLog.timestamp < _latest_ref,
                MessageLog.is_mock.is_(False)
            ).order_by(MessageLog.timestamp.desc()).limit(1000).all()
            session_hist_asc.reverse()  # 转回正序，便于按 ref_time 切片

        for idx, g in enumerate(groups):
            matched_inv = None
            cust = g["customer"]

            if cust:
                for rid in cust["ids"]:
                    if (uid, rid) in inv_map:
                        matched_inv = inv_map[(uid, rid)]
                        break
                if not matched_inv:
                    for inv in invs:
                        if inv.session_id == uid:
                            time_diff = abs((inv.triggered_at - cust["timestamp"]).total_seconds())
                            if time_diff < 180:
                                matched_inv = inv
                                break
            if api_fast_view and not matched_inv:
                continue

            ref_time = cust["timestamp"] if cust else (g["sales"]["timestamp"] if g["sales"] else None)
            history_msgs = []
            if ref_time:
                # 与上线链路 find_existing_single_session_id(limit=15) 对齐：背景只取触发点之前最近 15 条。
                # 从已一次性载入的 session_hist_asc 内存切片，不再每轮查库。
                # 排除属于当前合并轮次的所有消息ID，防止发送中的“多段首句”由于时序提早而被误判成历史背景。
                current_ids = set()
                if cust and "ids" in cust:
                    current_ids.update(cust["ids"])
                if g["sales"] and "ids" in g["sales"]:
                    current_ids.update(g["sales"]["ids"])
                history_msgs = [
                    m for m in session_hist_asc
                    if m.timestamp < ref_time and m.id not in current_ids
                ][-15:]

            # v1.7.192: 修正 v1.7.191 的误判 —— 服务器在 Beijing TZ 跑,
            # MessageLog.timestamp(由 archive_service datetime.fromtimestamp 写入)是"北京-naive",
            # 不是 UTC。所以 API 边界不再 +8(那会把已是北京的时间再前推 8 小时变成次日凌晨),
            # 直接原样 isoformat 下发, 前端 caselibFmtMsgTime 不做时区转换, 就是北京时间。
            def _bj_iso(dt):
                return dt.isoformat() if dt else ""
            bg_count = len(history_msgs)
            context_messages = []
            for m in history_msgs:
                context_messages.append({
                    "role": "customer" if m.sender_type == "customer" else "sales",
                    "msg_time": _bj_iso(m.timestamp),
                    "content": m.content
                })

            core_dialog = []
            if cust:
                core_dialog.append({
                    "role": "customer",
                    "msg_time": _bj_iso(cust["timestamp"]),
                    "content": cust["content"]
                })
            if g["sales"]:
                core_dialog.append({
                    "role": "sales",
                    "msg_time": _bj_iso(g["sales"]["timestamp"]),
                    "content": g["sales"]["content"]
                })

            result_id = str(matched_inv.invocation_id) if matched_inv else f"daily_turn_{uid}_{idx}"

            scores_payload = None
            ai_score = None          # AI 质量分：AI 候选回复的 7 维总分(绝对质量,qwen14b)
            sales_score = None       # 原始回复分：人工原始回复的 7 维总分(同模型 qwen14b)
            similarity_score = None  # 相似分：AI 回复 vs 原始回复的贴合代理分(同模型 qwen14b)
            kb1_eval = None
            kb2_eval = None

            if matched_inv:
                kb1_eval = float(matched_inv.kb1_eval_score) if matched_inv.kb1_eval_score is not None else None
                kb2_eval = float(matched_inv.kb2_eval_score) if matched_inv.kb2_eval_score is not None else None

                # AI 质量分 + 原始回复分：取自 reply_scores_v2(7 维绝对质量)，AI 与原始同模型同维度
                rs2 = _caselib_load_json((matched_inv.result_payload or {}).get("reply_scores_v2")) \
                    if isinstance(matched_inv.result_payload, dict) else None
                scores_payload = rs2 if isinstance(rs2, dict) else {}
                ai_score = _caselib_ai_score_from_step7(scores_payload)
                sales_score = _caselib_sales_score_from_step7(scores_payload)

                # 相似分：贴合代理分(quality_similarity.best_score，即原 quality_score)
                sim_payload = _caselib_load_json(matched_inv.quality_similarity) or {}
                best_sim = sim_payload.get("best_score") if isinstance(sim_payload, dict) else None
                if best_sim is None and matched_inv.quality_score is not None:
                    best_sim = float(matched_inv.quality_score)
                similarity_score = float(best_sim) if best_sim is not None else None
                # 把相似分明细并入 scores_payload，供前端浮层查看
                if isinstance(scores_payload, dict) and isinstance(sim_payload, dict):
                    scores_payload["reply_similarity"] = sim_payload

            cust_text = cust["content"] if cust else "【当天销售发起】"
            sales_text = g["sales"]["content"] if g["sales"] else ""

            case_meta = {
                "case_id": uid,
                "scenario_code": "实时",
                "scenario_name": "日常真实会话",
                "scenario_rank": 0,
                "case_title": f"{sales_chinese}与{external_userid}",
                "quality_score_md": None,
                "manual_quality_score_avg": None,
                "md_section_anchor": "",
                "context_count": bg_count,
                "context_messages": context_messages,
                "core_dialog": core_dialog,
            }

            turn_meta = {
                "turn_id": "",
                "turn_no": idx + 1,
                "customer_text": cust_text,
                "sales_text": sales_text,
                "actual_sales_score": sales_score,
                "actual_sales_scores": {},
                # v1.7.191: 同 context_messages.msg_time, 在 API 边界 UTC→北京 一次性转好,
                # 前端无需(也不应)再 +8 二次转换。
                "timestamp": _bj_iso(g["timestamp"]) if g.get("timestamp") else "",
            }

            step1 = None
            if matched_inv and matched_inv.result_payload:
                step1 = {
                    "topic": matched_inv.result_payload.get("topic") or "日常会话",
                    "core_demand": matched_inv.result_payload.get("core_demand") or "",
                    "status": matched_inv.result_payload.get("status") or "done"
                }
            elif cust:
                step1 = {
                    "topic": "常规沟通",
                    "core_demand": cust_text[:30],
                    "status": "manual"
                }
            else:
                step1 = {
                    "topic": "销售发起",
                    "core_demand": "",
                    "status": "manual"
                }

            kb_status = ""
            kb_hit_count = 0
            kb_used_count = None
            step4_knowledge = None
            train_ai_payload = None
            if matched_inv and matched_inv.result_payload:
                kb_status = matched_inv.result_payload.get("knowledge_status") or "done"
                kv2 = matched_inv.result_payload.get("knowledge_v2")
                if isinstance(kv2, dict):
                    kb_hit_count, kb_used_count = _caselib_kb_counts(kv2)
                    kb_hit_count = kb_hit_count or 0
                    # v1.7.188: 列表只放瘦字段(<1KB), 单条 hits / evidence_refs / evidence_context / replyable_hits
                    # 全文(占整行 82%, ~40KB)由前端 caselibEnsureResultDetail 调
                    # /api/case_lib/results/{invocation_id} 懒加载, 命中浮层渲染时再取。
                    # 实测: 1 行 49KB → 9KB 左右; 50 条 invocation 的天: 2.5MB → 450KB。
                    step4_knowledge = {
                        "knowledge_status": kb_status,
                        "knowledge_v2": {
                            "status": kv2.get("status"),
                            "query_text": kv2.get("query_text"),
                            "retrieval_quality": kv2.get("retrieval_quality"),
                            "no_hit_reason": kv2.get("no_hit_reason"),
                            # hits/evidence_refs/replyable_hits/evidence_context 不放
                            # 计数已由外层 r.kb_hit_count / r.kb_used_count 携带
                        },
                    }
                ta = matched_inv.result_payload.get("training_ai")
                if isinstance(ta, dict):
                    train_ai_payload = ta

            # 详情页只读：CRM 画像只取调用时已存的 result_payload.crm_info，
            # 不在详情加载时实时查 CRM(SQL Server)，避免外连阻塞/拖慢甚至卡死整个加载。
            # 未匹配到 API 调用的轮次，画像列留空。
            crm_info = None
            if matched_inv and matched_inv.result_payload:
                crm_info = matched_inv.result_payload.get("crm_info")

            # 耗时双行 (v1.7.193 重定义, 让两行不再恒等):
            #   第1行 fetch_to_output_ms = "主链路耗时" = pipeline_total_ms (LLM1+知识+LLM2+训练AI 全部跑完那一刻)
            #   第2行 api_total_ms       = "全程墙钟"   = total_ms (含 sanitize/落库/commit/回写, 即真实墙钟)
            #   两者差值 = 尾段开销 (序列化 + ApiAssistInvocation 落库 + db.commit + 二阶段回写)
            # 旧逻辑 (差值 = 前置补偿) 因生产路径 archive_sync 改为异步, 前置≈0, 两行恒等失去意义。
            # 兼容: 老记录(2026-05-28 之前)没有 pipeline_total_ms 字段, 退回老算法继续展示。
            fetch_to_output_ms = None
            api_total_ms = None
            timings_payload = {}
            if matched_inv and matched_inv.result_payload:
                _timings = matched_inv.result_payload.get("timings_ms") or {}
                timings_payload = _jsonable(_timings) if isinstance(_timings, dict) else {}
                _total = _timings.get("total_ms")
                _pipeline = _timings.get("pipeline_total_ms")
                if _total is not None:
                    api_total_ms = int(_total)
                    if _pipeline is not None:
                        # 新记录: 直接读 pipeline_total_ms, 差值即尾段开销
                        fetch_to_output_ms = int(max(float(_pipeline), 0))
                    else:
                        # 老记录回退: 按旧"减前置补偿"算法
                        _pre = 0.0
                        for _k in ("normalize_request_ms", "build_session_id_ms", "archive_sync_ms"):
                            _v = _timings.get(_k)
                            if _v is not None:
                                _pre += float(_v)
                        fetch_to_output_ms = int(max(_total - _pre, 0))

            item = {
                "result_id": result_id,
                "run_id": run_id,
                "case_id": uid,
                "turn_id": None,
                "scenario_code": "实时",
                "scenario_rank": 0,
                "turn_no": idx + 1,
                "step1_summary": step1,
                "step2_crm_info": crm_info,
                "step6_sales_advice": matched_inv.result_payload.get("reply_reference") if matched_inv else "",
                # 训练AI(另一条途径)与当前流程并行,与第6步/分数列共用一列(分两行展示)。
                # training_ai_score 暂为 None(独立打分后续完成)。
                "training_ai_reply": (train_ai_payload.get("reply") if train_ai_payload else ""),
                "training_ai_status": (train_ai_payload.get("status") if train_ai_payload else None),
                "training_ai_latency_ms": (train_ai_payload.get("latency_ms") if train_ai_payload else None),
                "training_ai_model": (train_ai_payload.get("model") if train_ai_payload else None),
                "training_ai_error": (train_ai_payload.get("error") if train_ai_payload else ""),
                "training_ai_score": (float(train_ai_payload["quality_score"]) if train_ai_payload and train_ai_payload.get("quality_score") is not None else None),
                "training_ai_scores": (train_ai_payload.get("scores") if train_ai_payload else None),
                "step7_reply_scores": scores_payload,
                "stage_status": matched_inv.result_payload.get("stage_status") if matched_inv else {},
                "step4_knowledge": step4_knowledge,
                "kb_status": kb_status,
                "kb_hit_count": kb_hit_count,
                "kb_used_count": kb_used_count,
                "bg_count": bg_count,
                "quality_score": ai_score,
                "similarity_score": similarity_score,
                "kb1_eval_score": kb1_eval,
                "kb2_eval_score": kb2_eval,
                "quality_status": matched_inv.quality_status if matched_inv else "manual_success",
                "latency_ms": int(matched_inv.result_payload.get("timings_ms", {}).get("total_ms", 0)) if matched_inv and matched_inv.result_payload else None,
                "fetch_to_output_ms": fetch_to_output_ms,
                "api_total_ms": api_total_ms,
                "timings_ms": timings_payload,
                "status": "success" if matched_inv else "manual",
                "case": case_meta,
                "turn": turn_meta,
            }
            results.append(item)
    _mark_timing("build_results_ms", stage_started)

    stage_started = perf_counter()
    results.sort(key=lambda x: str(x.get("turn", {}).get("timestamp") or ""), reverse=False)

    total_cases = len(results)
    avg_score = None
    valid_scores = [r["quality_score"] for r in results if r["quality_score"] is not None]
    if valid_scores:
        avg_score = round(sum(valid_scores) / len(valid_scores), 2)

    iteration_summary = {
        "run_id": run_id,
        "version_no": "实时验证",
        "git_commit_sha": "",
        "git_short_sha": "",
        "git_branch": "",
        "git_dirty": False,
        "changed_paths": [],
        "change_summary": f"{date} 企微日常会话双向验证明细",
        "pipeline_config": {},
        "status": "success",
        "total_cases": total_cases,
        "completed_cases": total_cases,
        "success_cases": total_cases,
        "failed_cases": 0,
        "avg_quality_score": avg_score,
        "min_quality_score": round(min(valid_scores), 2) if valid_scores else None,
        "max_quality_score": round(max(valid_scores), 2) if valid_scores else None,
        "avg_latency_ms": int(sum(r["latency_ms"] for r in results if r["latency_ms"] is not None) / len([r for r in results if r["latency_ms"] is not None])) if [r for r in results if r["latency_ms"] is not None] else 0,
        "improvement_analysis": "",
        "ai_next_step_plan": "",
        "analysis_codex": "",
        "analysis_antigravity": "",
        "analysis_claude_code": "",
        "analysis_summary": "",
        "backup_commit_sha": "",
        "backup_status": "",
        "triggered_by": "api_assist",
        # v1.7.192: day_start_bj 已是"北京-naive 5.28 00:00", 不再加 'Z' 后缀(那会把它当 UTC, 前端 +8 后变成 5.28 08:00)。
        # 现在: 北京-naive 字符串 → 前端 caselibFormatTime 检测无时区标记 → 不转换, 原样显示 5.28 00:00。
        "triggered_at": day_start_bj.isoformat(),
        "started_at": day_start_bj.isoformat(),
        "finished_at": day_end_bj.isoformat(),
        "error_message": "",
    }
    _mark_timing("build_summary_ms", stage_started)
    timings_ms["total_ms"] = round((perf_counter() - total_started) * 1000, 2)
    if timings_ms["total_ms"] >= 1000 or api_fast_view:
        logger.info(
            "CASELIB_DAILY_DETAIL_TIMING date=%s view=%s limit=%s logs=%s sessions=%s invocations=%s results=%s timings_ms=%s",
            date,
            view,
            limit,
            len(logs),
            len(target_sessions),
            len(invs),
            len(results),
            json.dumps(timings_ms, ensure_ascii=False),
        )

    return {
        "status": "success",
        "iteration": iteration_summary,
        "results": results
    }


@app.get("/api/case_lib/iterations/{run_id}")
async def caselib_get_iteration_detail(run_id: str):
    db = SessionLocal()
    total_started = perf_counter()
    timings_ms: dict[str, float] = {}

    def _mark_timing(name: str, started_at: float) -> None:
        timings_ms[name] = round((perf_counter() - started_at) * 1000, 2)

    try:
        stage_started = perf_counter()
        r = db.query(CaseIterationRun).filter(CaseIterationRun.run_id == run_id).first()
        _mark_timing("query_run_ms", stage_started)
        if not r:
            raise HTTPException(status_code=404, detail="iteration not found")
        # 列表只取轻量字段：跳过 step3/step5/step7候选全文 大列(详情页/浮层按需懒加载)
        stage_started = perf_counter()
        results = db.query(CaseIterationResult).options(
            defer(CaseIterationResult.step3_thread_business_fact),
            defer(CaseIterationResult.step5_llm1_compare),
            defer(CaseIterationResult.step7_reply_styles),
        ).filter(
            CaseIterationResult.run_id == run_id
        ).all()
        _mark_timing("query_results_ms", stage_started)
        case_ids = [str(rr.case_id) for rr in results]
        case_map = {}
        turn_map = {}
        bg_count_by_case: dict[str, int] = {}
        if case_ids:
            # 案例只取元信息列 + context_messages(用于统计背景条数)，不带 core_dialog 大数组
            stage_started = perf_counter()
            cases = db.query(CaseLibraryCase).options(
                defer(CaseLibraryCase.core_dialog),
            ).filter(
                CaseLibraryCase.case_id.in_(case_ids)
            ).all()
            _mark_timing("query_cases_ms", stage_started)
            stage_started = perf_counter()
            for c in cases:
                ctx = _caselib_load_json(c.context_messages)
                bg_count_by_case[str(c.case_id)] = len(ctx) if isinstance(ctx, list) else 0
            case_ids2 = [str(c.case_id) for c in cases]
            if case_ids2:
                # 轮次只取文本/评分列，跳过 messages/context_messages 大数组
                stage_started = perf_counter()
                turn_rows = db.query(CaseLibraryDialogueTurn).options(
                    defer(CaseLibraryDialogueTurn.messages),
                    defer(CaseLibraryDialogueTurn.context_messages),
                ).filter(
                    CaseLibraryDialogueTurn.case_id.in_(case_ids2)
                ).order_by(CaseLibraryDialogueTurn.case_id, CaseLibraryDialogueTurn.turn_no).all()
                _mark_timing("query_turns_ms", stage_started)
                for t in turn_rows:
                    turn_map[str(t.turn_id)] = _caselib_serialize_turn_thin(t)
            stage_started = perf_counter()
            sales_scores_by_case: dict[str, list[float]] = {}
            for rr in results:
                score = _caselib_sales_score_from_step7(rr.step7_reply_scores)
                if score is not None:
                    sales_scores_by_case.setdefault(str(rr.case_id), []).append(score)
            manual_avg_by_case = {
                cid: round(sum(vals) / len(vals), 2)
                for cid, vals in sales_scores_by_case.items()
                if vals
            }
            case_map = {
                str(c.case_id): _caselib_serialize_case_thin(
                    c,
                    manual_avg_by_case.get(str(c.case_id)),
                    bg_count_by_case.get(str(c.case_id)),
                )
                for c in cases
            }
            _mark_timing("build_case_maps_ms", stage_started)
        stage_started = perf_counter()
        rows = []
        for rr in results:
            item = _caselib_serialize_result_thin(
                rr,
                case_map.get(str(rr.case_id)),
                bg_count_by_case.get(str(rr.case_id)),
            )
            if rr.turn_id:
                item["turn"] = turn_map.get(str(rr.turn_id))
            rows.append(item)
        rows.sort(key=lambda x: (
            x.get("scenario_code") or "",
            x.get("scenario_rank") or 0,
            x.get("turn_no") or 0,
        ))
        _mark_timing("build_rows_ms", stage_started)
        timings_ms["total_ms"] = round((perf_counter() - total_started) * 1000, 2)
        if timings_ms["total_ms"] >= 1000:
            logger.info(
                "CASELIB_ITERATION_DETAIL_TIMING run_id=%s results=%s rows=%s timings_ms=%s",
                run_id,
                len(results),
                len(rows),
                json.dumps(timings_ms, ensure_ascii=False),
            )
        return {
            "status": "success",
            "iteration": _caselib_serialize_run(r),
            "results": rows,
        }
    finally:
        db.close()


class CaseLibStartIterationRequest(BaseModel):
    change_summary: str | None = None
    mode: str = "dry_run"  # dry_run / real
    triggered_by: str | None = None
    max_cases: int | None = None  # 仅跑前 N 个案例(按场景-排名序)，用于小批量验证；None=全部


def _caselib_run_dry(case_payload: dict) -> dict:
    core = case_payload.get("core_dialog") or []
    ctx = case_payload.get("context_messages") or []
    customer_msgs = [m for m in core if m.get("role") == "customer"]
    sales_msgs = [m for m in core if m.get("role") == "sales"]
    base_score = 60 + min(20, len(core) * 1.5)
    if customer_msgs and sales_msgs: base_score += 5
    if len(ctx) >= 10: base_score += 3
    base_score = round(min(95.0, base_score) + (hash(case_payload.get("case_id","")) % 7), 2)
    kb1 = round(min(95.0, base_score - 2 + (hash(case_payload.get("case_id","")+"kb1") % 5)), 2)
    kb2 = round(min(95.0, base_score - 4 + (hash(case_payload.get("case_id","")+"kb2") % 6)), 2)
    advice = (
        f"[DryRun] 针对 {case_payload.get('scenario_code')} 场景"
        f"（{case_payload.get('scenario_name')}），建议结合客户最新关切，"
        f"引用案例ID={case_payload.get('md_section_anchor')} 复盘要点。"
    )
    return {
        "step1_summary": {
            "topic": case_payload.get("case_title"),
            "core_demand": (customer_msgs[-1]["content"] if customer_msgs else ""),
            "status": "dry_run",
        },
        "step2_crm_info": {"customer_tier": "unknown", "history_orders": 0},
        "step3_thread_business_fact": {"business_state": "exploration"},
        "step4_knowledge": {"hits": [], "knowledge_status": "dry_run_stub"},
        "step5_llm1_compare": {"note": "dry_run skipped"},
        "step6_sales_advice": advice,
        "step6_compare_advice": advice + "（对比模型 dry_run）",
        "step7_reply_styles": [
            {"style": "professional", "text": advice},
            {"style": "friendly", "text": advice + " 加表情"},
        ],
        "step7_reply_scores": {"professional": kb1, "friendly": kb2},
        "quality_score": base_score,
        "kb1_eval_score": kb1,
        "kb2_eval_score": kb2,
        "quality_status": "dry_run_success",
        "latency_ms": 50 + (hash(case_payload.get("case_id","")) % 200),
        "stage_status": {
            "mode": "dry_run",
            "turn_no": case_payload.get("turn_no"),
            "customer_question": case_payload.get("customer_question"),
            "actual_sales_reply": case_payload.get("actual_sales_reply"),
        },
    }


def _caselib_parse_msg_time(raw_value: str | None, fallback: datetime) -> datetime:
    try:
        return datetime.fromisoformat(str(raw_value or "")[:19])
    except Exception:
        return fallback


def _caselib_sorted_messages(messages: list[dict], *, base_ts: datetime) -> list[dict]:
    indexed: list[tuple[datetime, int, dict]] = []
    for idx, item in enumerate(messages or []):
        msg = dict(item or {})
        msg["_case_order"] = idx
        indexed.append((_caselib_parse_msg_time(msg.get("msg_time"), base_ts + timedelta(seconds=idx)), idx, msg))
    indexed.sort(key=lambda item: (item[0], item[1]))
    return [item[2] for item in indexed]


def _caselib_split_for_api_trigger(case_payload: dict) -> dict:
    base_ts = datetime.utcnow() - timedelta(days=30)
    context_messages = _caselib_sorted_messages(case_payload.get("context_messages") or [], base_ts=base_ts)
    core_dialog = _caselib_sorted_messages(case_payload.get("core_dialog") or [], base_ts=base_ts + timedelta(hours=1))
    if not core_dialog:
        return {
            "visible_messages": context_messages,
            "post_trigger_messages": [],
            "trigger_message": None,
            "actual_sales_replies": [],
            "trigger_index": None,
        }

    actual_start_idx = None
    for idx in range(len(core_dialog) - 1, -1, -1):
        if core_dialog[idx].get("role") != "sales":
            continue
        if any(item.get("role") == "customer" for item in core_dialog[:idx]):
            actual_start_idx = idx
            break

    if actual_start_idx is not None:
        while actual_start_idx > 0 and core_dialog[actual_start_idx - 1].get("role") == "sales":
            actual_start_idx -= 1
        trigger_idx = None
        for idx in range(actual_start_idx - 1, -1, -1):
            if core_dialog[idx].get("role") == "customer":
                trigger_idx = idx
                break
    else:
        trigger_idx = None
        for idx in range(len(core_dialog) - 1, -1, -1):
            if core_dialog[idx].get("role") == "customer":
                trigger_idx = idx
                break

    if trigger_idx is None:
        trigger_idx = len(core_dialog) - 1

    visible_core = core_dialog[:trigger_idx + 1]
    post_trigger = core_dialog[trigger_idx + 1:]
    actual_sales_replies: list[dict] = []
    collecting = False
    for item in post_trigger:
        if item.get("role") == "sales":
            collecting = True
            actual_sales_replies.append(item)
            continue
        if collecting and item.get("role") == "customer":
            break

    trigger_message = core_dialog[trigger_idx] if 0 <= trigger_idx < len(core_dialog) else None
    return {
        "visible_messages": context_messages + visible_core,
        "post_trigger_messages": post_trigger,
        "trigger_message": trigger_message,
        "actual_sales_replies": actual_sales_replies,
        "trigger_index": trigger_idx,
    }


def _caselib_case_payload_for_turn(case_payload: dict, turn_payload: dict) -> dict:
    """Build one runnable test input from a case turn.

    The visible context must stop before this turn's sales answer: background is
    the 15 rows before the customer question, and core_dialog is only this turn
    (customer question + reference sales answer for scoring/comparison).
    """
    payload = dict(case_payload)
    messages = _caselib_sorted_messages(
        turn_payload.get("messages") or [],
        base_ts=datetime.utcnow() - timedelta(days=30),
    )
    customer_msgs = [m for m in messages if m.get("role") == "customer"]
    sales_msgs = [m for m in messages if m.get("role") == "sales"]
    payload["turn_id"] = turn_payload.get("turn_id")
    payload["turn_no"] = turn_payload.get("turn_no")
    payload["core_dialog"] = messages
    payload["context_messages"] = turn_payload.get("context_messages") or []
    payload["customer_question"] = "\n".join((m.get("content") or "").strip() for m in customer_msgs if (m.get("content") or "").strip())
    payload["actual_sales_reply"] = "\n".join((m.get("content") or "").strip() for m in sales_msgs if (m.get("content") or "").strip())
    payload["case_title"] = f"{case_payload.get('case_title') or ''} · 第{turn_payload.get('turn_no')}轮"
    return payload


def _caselib_real_failure(
    *,
    quality_status: str,
    latency_ms: int,
    error_message: str,
    stage_status: dict | None = None,
) -> dict:
    stage = dict(stage_status or {})
    stage["caselib_error"] = sanitize_text(error_message)[:300]
    return {
        "quality_status": quality_status[:50],
        "latency_ms": latency_ms,
        "stage_status": stage,
        "error_message": error_message[:500],
        "quality_score": None,
        "kb1_eval_score": None,
        "kb2_eval_score": None,
    }


# 案例库迭代评测策略（V9 起）：
#   - 单版本：每轮只生成 1 条 AI 回复（主模型 + 单风格 + 单知识库），不再跑 8 个对比版本
#   - 跳过评分：链路到 step6 AI 生成即截止，不调用 step7 LLM 评分；评分可后续用 rescore 端点单独补
CASELIB_EVAL_SINGLE_VERSION = True
CASELIB_EVAL_SKIP_SCORING = True


def _caselib_real_external_userid(db, group_key: str | None) -> str | None:
    """按案例 group_key 从原始企微数据(wecom_raw_import)找回客户真实 external_userid。

    案例库源于真实企微会话，客户真实 ID 存在原始表 role='customer' 行的 from_id 列
    （例如 wmS8sICwAA1yHly1pg8N0_fuYPW6M-4w）。取该 group 下出现最多的客户 from_id。
    找不到时返回 None，调用方回退到合成 ID（保持原行为，不报错）。
    """
    if not group_key:
        return None
    try:
        row = db.execute(text("""
            SELECT from_id, COUNT(*) AS n
            FROM wecom_raw_import
            WHERE group_key = :gk AND role = 'customer'
              AND from_id IS NOT NULL AND from_id <> ''
            GROUP BY from_id
            ORDER BY n DESC
            LIMIT 1
        """), {"gk": group_key}).fetchone()
        return row[0] if row and row[0] else None
    except Exception:
        return None


def _caselib_run_real(case_payload: dict, run_id: str) -> dict:
    db = SessionLocal()
    cid = case_payload.get("case_id", "0")[:12]
    # 客户侧优先用真实 external_userid，使 CRM 客户画像与「企微实时智能」页面一致；
    # 优先取案例表已回填的字段，其次按 group_key 实时找回，都没有才回退合成 ID。
    # 销售侧始终用 caselib_ 合成 ID，保证注入会话与真实企微会话隔离、跑完即清。
    real_ext = (case_payload.get("external_userid")
                or _caselib_real_external_userid(db, case_payload.get("group_key")))
    external_userid = real_ext or f"caselib_ext_{cid}"
    sales_userid = f"caselib_sales_{run_id[:8]}"
    # 与 build_single_session_id 严格一致：sorted + 'single_' 前缀 + '_' 连接
    participants = sorted([sales_userid.strip(), external_userid.strip()])
    session_id = f"single_{'_'.join(participants)}"
    session_id_candidates = [session_id]
    started = perf_counter()
    try:
        split_payload = _caselib_split_for_api_trigger(case_payload)
        visible_msgs = split_payload.get("visible_messages") or []
        trigger_message = split_payload.get("trigger_message") or {}
        if not visible_msgs or not trigger_message or trigger_message.get("role") != "customer":
            return _caselib_real_failure(
                quality_status="real_no_customer_trigger",
                latency_ms=int((perf_counter() - started) * 1000),
                error_message="案例无法解析出客户触发点，已停止真实模式运行",
                stage_status={"mode": "real", "caselib_split": split_payload},
            )
        # is_mock=False 才会被 find_existing_single_session_id 命中；
        # 用 caselib_* 前缀的 session_id 保证不会与真实企微 session 重叠，跑完即清理
        db.execute(text("DELETE FROM message_logs WHERE user_id=:sid"), {"sid": session_id})
        base_ts = datetime.utcnow() - timedelta(days=30)
        for i, m in enumerate(visible_msgs):
            try:
                ts = datetime.fromisoformat((m.get("msg_time") or base_ts.isoformat())[:19])
            except Exception:
                ts = base_ts + timedelta(seconds=i)
            db.execute(text("""
                INSERT INTO message_logs (user_id, sender_type, content, timestamp, is_mock)
                VALUES (:uid, :st, :c, :ts, FALSE)
            """), {
                "uid": session_id,
                "st": m.get("role") or "customer",
                "c": m.get("content") or "",
                "ts": ts,
            })
        db.commit()

        # 自动探测后端端口（env PORT 优先；否则尝试 8071/8000）
        host = os.environ.get("BACKEND_HOST", "127.0.0.1")
        env_port = os.environ.get("PORT") or os.environ.get("CASELIB_BACKEND_PORT")
        port_candidates = [int(env_port)] if env_port else [8071, 8000]
        resp = None
        last_err = None
        for p in port_candidates:
            try:
                url = f"http://{host}:{p}/api/wecom/sidebar_assist"
                r = requests.post(url, json={
                    "external_userid": external_userid,
                    "userid": sales_userid,
                    "force_refresh": True,
                    "sync_archive_before_read": False,
                    "trigger_source": "web_manual",
                    # 案例库评测走真实链路；V9 起：单版本(主模型+单风格+单知识库) + 跳过 step7 评分(到 step6 截止)
                    "evaluation_full_pipeline": True,
                    "eval_single_version": CASELIB_EVAL_SINGLE_VERSION,
                    "eval_skip_scoring": CASELIB_EVAL_SKIP_SCORING,
                }, timeout=int(os.environ.get("CASELIB_REQUEST_TIMEOUT_SECONDS") or "180"))
                resp = r
                break
            except Exception as e:
                last_err = e
        latency_ms = int((perf_counter() - started) * 1000)
        if resp is None:
            return _caselib_real_failure(
                quality_status="real_conn_fail",
                latency_ms=latency_ms,
                error_message=f"无法连接本地后端: {last_err}",
                stage_status={"mode": "real", "caselib_split": split_payload},
            )
        if resp.status_code != 200:
            return _caselib_real_failure(
                quality_status=f"real_http_{resp.status_code}",
                latency_ms=latency_ms,
                error_message=(resp.text or "")[:500],
                stage_status={"mode": "real", "caselib_split": split_payload},
            )
        body = resp.json() or {}
        # sidebar_assist 把 7 步结果直接平铺在 body 顶层
        crm = body.get("crm_info") or {}
        tbf = body.get("thread_business_fact") or {}
        knowledge_v2 = body.get("knowledge_v2") or body.get("knowledge_base") or {}
        knowledge_external = body.get("knowledge_external_api") or {}
        llm1_compare = body.get("llm1_compare_summary") or {}
        # 主建议在 reply_reference；备选/对比在 reply_reference_compare
        sales_advice = body.get("reply_reference") or ""
        compare_advice = body.get("reply_reference_compare") or ""
        styles = body.get("reply_style_results_v2") or body.get("reply_style_results") or []
        scores_obj = body.get("reply_scores_v2") or body.get("reply_scores") or {}
        stage_status = body.get("stage_status") or {}
        stage_status["caselib_split"] = {
            "trigger_message": trigger_message,
            "turn_no": case_payload.get("turn_no"),
            "customer_question": case_payload.get("customer_question"),
            "actual_sales_reply": case_payload.get("actual_sales_reply"),
            "visible_message_count": len(visible_msgs),
            "post_trigger_message_count": len(split_payload.get("post_trigger_messages") or []),
            "actual_sales_reply_count": len(split_payload.get("actual_sales_replies") or []),
            "actual_sales_replies": split_payload.get("actual_sales_replies") or [],
        }
        snap_id = body.get("snapshot_id") or body.get("api_invocation_id")
        # 排除评分耗时，只记录到 AI 回复生成为止
        try:
            scoring_ms = float(
                (stage_status.get("node_timings_ms") or {})
                .get("llm2", {}).get("parts_ms", {})
                .get("reply_scoring_ms") or 0
            )
            latency_ms = max(0, latency_ms - int(scoring_ms))
        except Exception:
            pass

        # 若顶层无 advice，取 styles[0]['reply_reference'] 或 ['text']
        if not sales_advice and isinstance(styles, list) and styles:
            first = styles[0] or {}
            sales_advice = first.get("reply_reference") or first.get("text") or first.get("content") or ""

        # 质量分：reply_scores_v2 结构是 {ai_candidates:[{overall_score, scores:{...}, knowledge_source}], actual_sales_replies:[...], dimensions:[...]}
        # AI 质量分 = ai_candidates 中 overall_score 最高者
        # 私域库分 = knowledge_source==knowledge_v2 的候选 overall 最高
        # 外部库分 = knowledge_source==knowledge_external_api 的候选 overall 最高
        qs = None
        kb1 = None; kb2 = None
        try:
            ai_candidates = []
            if isinstance(scores_obj, dict):
                ai_candidates = scores_obj.get("ai_candidates") or []
            if ai_candidates:
                # 最佳总分
                qs = max(
                    (float(c.get("overall_score") or 0) for c in ai_candidates if c.get("overall_score") is not None),
                    default=None,
                )
                # 按知识来源分组取最高
                kb1_pool = [float(c.get("overall_score") or 0) for c in ai_candidates if c.get("knowledge_source") == "knowledge_v2" and c.get("overall_score") is not None]
                kb2_pool = [float(c.get("overall_score") or 0) for c in ai_candidates if c.get("knowledge_source") == "knowledge_external_api" and c.get("overall_score") is not None]
                kb1 = max(kb1_pool) if kb1_pool else None
                kb2 = max(kb2_pool) if kb2_pool else None
        except Exception:
            pass
        has_advice = bool(sales_advice)
        has_llm1 = (stage_status.get("llm1") == "done")
        has_llm2 = (stage_status.get("llm2") == "done")
        # 跳过评分模式下，链路到 step6 即算完整成功（qs 必然为 None，不能据此判失败）
        pipeline_ok = has_advice and has_llm1 and has_llm2
        status_label = (
            "real_success" if (pipeline_ok and (CASELIB_EVAL_SKIP_SCORING or qs is not None))
            else ("real_score_missing" if pipeline_ok else ("real_partial" if has_advice else "real_pipeline_empty"))
        )
        return {
            "step1_summary": {
                "topic": body.get("topic"),
                "core_demand": body.get("core_demand"),
                "key_facts": body.get("key_facts"),
                "todo_items": body.get("todo_items"),
                "risks": body.get("risks"),
                "to_be_confirmed": body.get("to_be_confirmed"),
                "status": body.get("status"),
                "evidence_refs": body.get("evidence_refs"),
            },
            "step2_crm_info": crm,
            "step3_thread_business_fact": tbf,
            "step4_knowledge": {
                "knowledge_v2": knowledge_v2,
                "knowledge_external_api": knowledge_external,
                "knowledge_status": stage_status.get("knowledge_v2") or stage_status.get("knowledge"),
                "knowledge_confidence_score": body.get("knowledge_confidence_score"),
                "knowledge_manual_review_required": body.get("knowledge_manual_review_required"),
            },
            "step5_llm1_compare": llm1_compare,
            "step6_sales_advice": sales_advice,
            "step6_compare_advice": compare_advice,
            "step7_reply_styles": styles,
            "step7_reply_scores": scores_obj,
            "snapshot_id": str(snap_id) if snap_id else None,
            "quality_score": round(qs, 2) if qs is not None else None,
            "kb1_eval_score": round(kb1, 2) if kb1 is not None else None,
            "kb2_eval_score": round(kb2, 2) if kb2 is not None else None,
            "quality_status": status_label,
            "latency_ms": latency_ms,
            "stage_status": stage_status,
        }
    except Exception as e:
        return _caselib_real_failure(
            quality_status="real_error",
            latency_ms=int((perf_counter() - started) * 1000),
            error_message=str(e),
            stage_status={"mode": "real"},
        )
    finally:
        # 跑完即清理本案例注入的所有 caselib_* 消息和摘要，避免污染统计页面
        try:
            for sid in session_id_candidates:
                db.execute(text("DELETE FROM message_logs WHERE user_id=:sid"), {"sid": sid})
                db.execute(text("DELETE FROM intent_summaries WHERE user_id=:sid"), {"sid": sid})
                db.execute(text("DELETE FROM reply_chain_snapshot WHERE session_id=:sid"), {"sid": sid})
            db.commit()
        except Exception:
            pass
        db.close()


def _caselib_compose_improvement_analysis(db: Session, run: CaseIterationRun, scores: list[float]) -> str:
    lines = []
    lines.append(f"本次迭代版本号 v{run.version_no}，案例总数 {run.total_cases}，成功 {run.success_cases}，失败 {run.failed_cases}。")
    if scores:
        avg = sum(scores) / len(scores)
        lines.append(f"平均质量分 {avg:.2f}，最低 {min(scores):.2f}，最高 {max(scores):.2f}。")
        below = [s for s in scores if s < avg - 5]
        if below:
            lines.append(f"低于均值5分以上的案例数：{len(below)}（占 {len(below)*100//len(scores)}%）。")
    rows = db.execute(text("""
        SELECT scenario_code, COUNT(*), AVG(quality_score), MIN(quality_score)
        FROM case_iteration_result
        WHERE run_id=:rid AND quality_score IS NOT NULL
        GROUP BY scenario_code ORDER BY AVG(quality_score) ASC
    """), {"rid": str(run.run_id)}).fetchall()
    if rows:
        lines.append("\n各场景平均分（升序，优先改进前3场景）：")
        for r in rows:
            lines.append(f"  {r[0]}: n={r[1]} avg={float(r[2] or 0):.2f} min={float(r[3] or 0):.2f}")
        worst = rows[:3]
        if worst:
            lines.append("\n下一步重点优化建议：")
            for r in worst:
                lines.append(f"  - {r[0]} 平均{float(r[2] or 0):.2f}：检查该场景 prompt 模板/知识检索过滤条件/示例对照。")
    return "\n".join(lines)


def _caselib_compose_ai_next_plan(run: CaseIterationRun, db: Session | None = None) -> str:
    """
    AI 自我测试迭代步骤及要求：
    - 静态硬要求（避免跳过/假执行）
    - 动态扫描本次 run 的 60 个结果，把命中的失败原因写入清单
    """
    issues: list[str] = []
    if db is not None:
        # 扫描本次的失败/降级状态
        rows = db.execute(text("""
            SELECT quality_status, COUNT(*), STRING_AGG(DISTINCT COALESCE(stage_status->>'caselib_error',''), ' | ')
            FROM case_iteration_result
            WHERE run_id=:rid
            GROUP BY quality_status
        """), {"rid": str(run.run_id)}).fetchall()
        for st, n, err_agg in rows:
            if not st: continue
            tag = st
            err_msg = (err_agg or "").strip(' |')[:300]
            if tag == "real_success":
                issues.append(f"- ✅ {tag}: {n} 个案例（pipeline 全通）")
            elif "dry_run_success" in tag:
                issues.append(f"- ℹ️ {tag}: {n} 个案例（本次 mode=dry_run，不真调LLM）")
            else:
                detail = f"，错误样本：{err_msg}" if err_msg else ""
                issues.append(f"- ❌ {tag}: {n} 个案例{detail}")
    # 历史已知坑（本轮开发遇到过）
    known_bugs = (
        "## 历史已知坑（本轮调试已捕获，下次必须先验证）\n"
        "1. **session_id 必须用 `build_single_session_id` 格式**：`single_{sorted([sales_userid, external_userid])_joined_by_underscore}`，"
        "不可用 `sales|external` 或 `sales_external`。否则 sidebar_assist 找不到消息（latest_dialog_count=0）。\n"
        "2. **message_logs.is_mock 必须 = FALSE**：`find_existing_single_session_id` 过滤了 is_mock=TRUE 的行；"
        "case_lib 注入的消息要写 is_mock=FALSE，配合 caselib_* 专用 session_id 防污染，再在 finally 清理。\n"
        "3. **trigger_source 影响落库表**：传 `api` 会落 api_assist_invocation；传 `web_manual` 落 reply_chain_snapshot。"
        "case_lib 不依赖任一表，**直接解析 sidebar_assist HTTP 响应 body**（最稳）。\n"
        "4. **响应字段是顶层平铺，不在 `summary` 下**：topic / core_demand / key_facts / risks / todo_items / "
        "to_be_confirmed / reply_reference / knowledge_v2 / reply_style_results_v2 / reply_scores_v2 都在 body 根级。\n"
        "5. **真实建议文本 = `body['reply_reference']`**；`sales_advice_v2` 这个 key 在响应里**不存在**，会读到空串。\n"
        "6. **后端端口不能写死 8000**：本项目默认跑在 8071。`_caselib_run_real` 内已加端口探测顺序 [env PORT, 8071, 8000]。\n"
        "7. **DB 列宽限制**：`quality_status` 是 VARCHAR(50)，所有写入前必须 `[:50]` 截断，错误详情塞到 `stage_status` JSON。\n"
    )
    rules = (
        "## 下一次迭代必须遵守（防跳过/假执行）\n"
        f"1. 先 `python backend/_case_lib_import.py` 同步案例库与 sales_scenario_cases_v2.md。\n"
        f"2. 后端必须实际启动并验证 8071 端口 LISTENING（`netstat`），不能只做语法检查就声称跑通。\n"
        f"3. 触发 mode=real，**60/60 必须 quality_status=real_success**；任何 fallback_dry / pipeline_empty / conn_fail 视作未完成。\n"
        f"4. 详情页随机抽 3 个案例点开，肉眼核对 step1.topic、step4.knowledge_v2.hits、step6_sales_advice 都是真实 LLM 输出（不能是 [DryRun] 开头）。\n"
        f"5. 本版若有 real_pipeline_empty 或 real_partial 占比 >5%，**禁止 git 备份**，先排查 LLM 配置/知识库可用性。\n"
        f"6. 改进相对上一版 avg_quality_score 必须 ≥ 上版（同模式比同模式：dry vs dry，real vs real）。\n"
        "7. 完成后人工填写 change_summary，把上一轮 AI 计划里要求处理的『已知坑』逐条标记是否已经规避。\n"
    )
    head = f"# v{run.version_no} 案例迭代自检报告\n\n"
    body_issues = "## 本轮状态分布\n" + "\n".join(issues) + "\n\n" if issues else ""
    return head + body_issues + known_bugs + "\n" + rules


def _caselib_git_backup(version_no: int) -> tuple[str | None, str]:
    """完成迭代后：本地 commit + push 到 GitHub origin（当前分支）。
    任一环节失败都安全返回（不阻塞迭代），状态码体现到 backup_status。
    """
    repo_root = os.path.dirname(os.path.dirname(os.path.abspath(__file__)))
    try:
        st = subprocess.run(["git", "status", "--porcelain"], cwd=repo_root,
                            capture_output=True, text=True, timeout=10)
        if st.returncode != 0:
            return None, f"status_failed: {st.stderr.strip()[:120]}"
        commit_made = False
        if st.stdout.strip():
            add = subprocess.run(["git", "add", "-A"], cwd=repo_root,
                                 capture_output=True, text=True, timeout=20)
            if add.returncode != 0:
                return None, f"add_failed: {add.stderr.strip()[:120]}"
            msg = f"chore(caselib): iteration v{version_no} auto-backup"
            cm = subprocess.run(["git", "commit", "-m", msg], cwd=repo_root,
                                capture_output=True, text=True, timeout=20)
            if cm.returncode != 0:
                return None, f"commit_failed: {cm.stderr.strip()[:120]}"
            commit_made = True
        sha_proc = subprocess.run(["git", "rev-parse", "HEAD"], cwd=repo_root,
                                  capture_output=True, text=True, timeout=10)
        head_sha = sha_proc.stdout.strip() if sha_proc.returncode == 0 else None

        # 推送当前分支到 origin
        branch_proc = subprocess.run(["git", "rev-parse", "--abbrev-ref", "HEAD"],
                                     cwd=repo_root, capture_output=True, text=True, timeout=10)
        branch = branch_proc.stdout.strip() if branch_proc.returncode == 0 else None
        push_status = "skipped_no_branch"
        if branch:
            push = subprocess.run(["git", "push", "origin", branch], cwd=repo_root,
                                  capture_output=True, text=True, timeout=60)
            if push.returncode == 0:
                push_status = "pushed"
            else:
                push_status = f"push_failed: {push.stderr.strip()[:120]}"
        # 组合 backup_status：commit + push 两阶段
        if commit_made and push_status == "pushed":
            return head_sha, "committed_and_pushed"
        if commit_made:
            return head_sha, f"committed_only_{push_status}"
        # 无新改动，但仍可推
        if push_status == "pushed":
            return head_sha, "clean_no_change_pushed"
        return head_sha, f"clean_no_change_{push_status}"
    except Exception as e:
        return None, f"exception: {str(e)[:120]}"


def _caselib_run_iteration_background(run_id: str, mode: str, max_cases: int | None = None):
    log = logging.getLogger(__name__)
    db = SessionLocal()
    try:
        run = db.query(CaseIterationRun).filter(CaseIterationRun.run_id == run_id).first()
        if not run:
            log.warning(f"caselib run not found: {run_id}")
            return
        run.status = "running"
        run.started_at = datetime.utcnow()
        db.commit()

        cases = db.query(CaseLibraryCase).order_by(
            CaseLibraryCase.scenario_code, CaseLibraryCase.scenario_rank
        ).all()
        # 小批量验证：仅取前 N 个案例（按场景-排名序）
        if max_cases and max_cases > 0:
            cases = cases[:max_cases]
        case_ids = [str(c.case_id) for c in cases]
        turns = db.query(CaseLibraryDialogueTurn).filter(
            CaseLibraryDialogueTurn.case_id.in_(case_ids)
        ).order_by(
            CaseLibraryDialogueTurn.scenario_code,
            CaseLibraryDialogueTurn.scenario_rank,
            CaseLibraryDialogueTurn.turn_no,
        ).all() if case_ids else []
        turns_by_case: dict[str, list[CaseLibraryDialogueTurn]] = {}
        for t in turns:
            turns_by_case.setdefault(str(t.case_id), []).append(t)
        jobs: list[tuple[CaseLibraryCase, CaseLibraryDialogueTurn]] = [
            (c, t) for c in cases for t in turns_by_case.get(str(c.case_id), [])
        ]
        run.total_cases = len(jobs)
        db.commit()

        for c, t in jobs:
            existing = db.query(CaseIterationResult).filter(
                CaseIterationResult.run_id == run_id,
                CaseIterationResult.case_id == c.case_id,
                CaseIterationResult.turn_no == t.turn_no,
            ).first()
            if existing: continue
            r = CaseIterationResult(
                run_id=run.run_id,
                case_id=c.case_id,
                turn_id=t.turn_id,
                scenario_code=c.scenario_code,
                scenario_rank=c.scenario_rank,
                turn_no=t.turn_no,
                status="queued",
            )
            db.add(r)
        db.commit()

        scores = []; latencies = []
        success_n = 0; failed_n = 0; completed_n = 0
        for c, t in jobs:
            case_payload = _caselib_case_payload_for_turn(
                _caselib_serialize_case(c),
                _caselib_serialize_turn(t),
            )
            rr = db.query(CaseIterationResult).filter(
                CaseIterationResult.run_id == run_id,
                CaseIterationResult.case_id == c.case_id,
                CaseIterationResult.turn_no == t.turn_no,
            ).first()
            rr.status = "running"
            rr.started_at = datetime.utcnow()
            db.commit()

            try:
                if mode == "real":
                    out = _caselib_run_real(case_payload, run_id=run_id)
                else:
                    out = _caselib_run_dry(case_payload)
                rr.step1_summary = out.get("step1_summary")
                rr.step2_crm_info = out.get("step2_crm_info")
                rr.step3_thread_business_fact = out.get("step3_thread_business_fact")
                rr.step4_knowledge = out.get("step4_knowledge")
                rr.step5_llm1_compare = out.get("step5_llm1_compare")
                rr.step6_sales_advice = out.get("step6_sales_advice")
                rr.step6_compare_advice = out.get("step6_compare_advice")
                rr.step7_reply_styles = out.get("step7_reply_styles")
                rr.step7_reply_scores = out.get("step7_reply_scores")
                rr.snapshot_id = out.get("snapshot_id")
                rr.quality_score = out.get("quality_score")
                rr.kb1_eval_score = out.get("kb1_eval_score")
                rr.kb2_eval_score = out.get("kb2_eval_score")
                rr.quality_status = (out.get("quality_status") or "")[:50]  # DB列上限50
                rr.latency_ms = out.get("latency_ms")
                rr.stage_status = out.get("stage_status")
                is_real_failure = mode == "real" and out.get("quality_status") != "real_success"
                if is_real_failure:
                    rr.status = "failed"
                    rr.error_message = out.get("error_message") or out.get("quality_status") or "real mode failed"
                    failed_n += 1
                else:
                    rr.status = "success"
                    success_n += 1
                if not is_real_failure and out.get("quality_score") is not None:
                    scores.append(float(out["quality_score"]))
                if not is_real_failure and out.get("latency_ms") is not None:
                    latencies.append(int(out["latency_ms"]))
            except Exception as e:
                rr.status = "failed"
                rr.error_message = str(e)[:500]
                failed_n += 1
            rr.finished_at = datetime.utcnow()
            completed_n += 1
            run.completed_cases = completed_n
            run.success_cases = success_n
            run.failed_cases = failed_n
            db.commit()

        if scores:
            avg = sum(scores) / len(scores)
            run.avg_quality_score = round(avg, 2)
            run.min_quality_score = round(min(scores), 2)
            run.max_quality_score = round(max(scores), 2)
        if latencies:
            run.avg_latency_ms = int(sum(latencies) / len(latencies))
        run.status = "success" if failed_n == 0 else ("partial" if success_n > 0 else "failed")
        run.finished_at = datetime.utcnow()
        run.improvement_analysis = _caselib_compose_improvement_analysis(db, run, scores)
        run.ai_next_step_plan = _caselib_compose_ai_next_plan(run, db)
        db.commit()

        try:
            sha, status = _caselib_git_backup(run.version_no)
            run.backup_commit_sha = sha
            run.backup_status = status
            db.commit()
        except Exception as e:
            run.backup_status = f"failed: {str(e)[:120]}"
            db.commit()
    except Exception as e:
        log.exception("caselib iteration failed")
        try:
            run = db.query(CaseIterationRun).filter(CaseIterationRun.run_id == run_id).first()
            if run:
                run.status = "failed"
                run.error_message = str(e)[:500]
                run.finished_at = datetime.utcnow()
                db.commit()
        except Exception:
            pass
    finally:
        db.close()
        CASELIB_BACKGROUND_THREAD.pop(run_id, None)


@app.post("/api/case_lib/iterations/start")
async def caselib_start_iteration(payload: CaseLibStartIterationRequest):
    db = SessionLocal()
    try:
        gi = _caselib_resolve_git_info()
        version_no = _caselib_next_version_no(db)
        prev = db.query(CaseIterationRun).order_by(
            CaseIterationRun.version_no.desc()
        ).first()
        changed_paths: list[str] = []
        repo_root = os.path.dirname(os.path.dirname(os.path.abspath(__file__)))
        if prev and prev.git_commit_sha and gi["sha"] and prev.git_commit_sha != gi["sha"]:
            try:
                diff = subprocess.run(
                    ["git", "diff", "--name-only", prev.git_commit_sha, gi["sha"]],
                    cwd=repo_root, capture_output=True, text=True, timeout=10
                )
                if diff.returncode == 0:
                    changed_paths = [x for x in diff.stdout.splitlines() if x.strip()]
            except Exception:
                pass
        if gi["dirty"]:
            try:
                st = subprocess.run(["git", "status", "--porcelain"], cwd=repo_root,
                                    capture_output=True, text=True, timeout=5)
                if st.returncode == 0:
                    pending = [ln[3:].strip() for ln in st.stdout.splitlines() if ln.strip()]
                    changed_paths = list(set(changed_paths) | set(pending))
            except Exception:
                pass

        run = CaseIterationRun(
            version_no=version_no,
            git_commit_sha=gi["sha"], git_short_sha=gi["short_sha"],
            git_branch=gi["branch"], git_dirty=gi["dirty"],
            changed_paths=changed_paths,
            change_summary=payload.change_summary or "",
            pipeline_config={
                "mode": payload.mode,
                "max_cases": payload.max_cases,
                "eval_single_version": CASELIB_EVAL_SINGLE_VERSION,
                "eval_skip_scoring": CASELIB_EVAL_SKIP_SCORING,
                "scripts": ["backend/main.py", "backend/intent_engine.py", "backend/_case_lib_import.py"],
            },
            status="queued",
            triggered_by=payload.triggered_by or "frontend",
            triggered_at=datetime.utcnow(),
        )
        db.add(run)
        db.commit()
        db.refresh(run)

        t = threading.Thread(
            target=_caselib_run_iteration_background,
            args=(str(run.run_id), payload.mode, payload.max_cases),
            daemon=True,
        )
        CASELIB_BACKGROUND_THREAD[str(run.run_id)] = t
        t.start()

        return {"status": "success", "iteration": _caselib_serialize_run(run)}
    finally:
        db.close()


@app.post("/api/case_lib/reimport")
async def caselib_reimport():
    repo_root = os.path.dirname(os.path.dirname(os.path.abspath(__file__)))
    script = os.path.join(repo_root, "backend", "_case_lib_import.py")
    try:
        proc = subprocess.run(["python", script], cwd=repo_root,
                              capture_output=True, text=True, timeout=120)
        return {
            "status": "success" if proc.returncode == 0 else "failed",
            "stdout": proc.stdout[-4000:],
            "stderr": proc.stderr[-2000:],
        }
    except Exception as e:
        return {"status": "failed", "error": str(e)}


def _heuristic_score_sales_text(sales_text: str, customer_text: str = "") -> dict:
    """对销售回复做规则启发式打分（不调用LLM），返回 7 维度分 + overall。
    维度权重与 AI 质量分完全一致：
      overall = conciseness*0.18 + low_barrier*0.24 + non_repetition*0.22
              + safety*0.22 + style_match*0.08 + context_alignment*0.06
    """
    import re as _re
    text = (sales_text or "").strip()
    char_count = len(_re.sub(r'\s+', '', text))  # 不含空白的字符数

    # 1. conciseness（微信感）：纯字数规则
    if char_count == 0:
        conciseness = 0
    elif char_count <= 50:
        conciseness = 87   # 80-95 区间取中偏上
    elif char_count <= 80:
        conciseness = 55   # 40-70 区间取中
    else:
        conciseness = 20   # 0-30 区间取中偏上

    # 2. low_barrier（易回复）：问号数量 + 内容丰富度
    q_count = text.count('？') + text.count('?')
    if char_count == 0:
        low_barrier = 20
    elif q_count == 0:
        low_barrier = 55 if char_count <= 3 else 82   # 极短语气词扣分
    elif q_count == 1:
        low_barrier = 68
    elif q_count == 2:
        low_barrier = 50
    else:
        low_barrier = 38

    # 3. non_repetition（差异化）：避免客套套话
    cliche_matches = sum(
        1 for pat in ['您好', '感谢关注', '非常抱歉', '亲爱的', '如有疑问', '欢迎光临', '很高兴为您', '随时为您服务']
        if pat in text
    )
    non_repetition = max(0, 80 - cliche_matches * 20)

    # 4. safety（稳妥度）：规避风险承诺；普通跟进基准 72
    safety = 72
    for w in ['一定', '保证', '承诺', '绝对', '肯定没问题', '100%', '无条件', '全额退款', '赔偿']:
        if w in text:
            safety = max(0, safety - 15)
    if _re.search(r'[¥￥]\s*\d+|报价\s*\d+|总价\s*\d+|单价\s*\d+', text):
        safety = max(0, safety - 8)

    # 5. style_match（风格匹配）：微信口语化，避免过度书面
    style_match = 75
    for w in ['敬请', '谨此', '特此告知', '烦请', '恳请', '兹', '顺此']:
        if w in text:
            style_match = max(0, style_match - 20)

    # 6. context_alignment（上下文贴合）：无 LLM 时只做基础判断
    context_alignment = 20 if char_count == 0 else 72

    # 加权总分（与 AI 评分公式完全一致）
    overall_float = (
        conciseness * 0.18 +
        low_barrier * 0.24 +
        non_repetition * 0.22 +
        safety * 0.22 +
        style_match * 0.08 +
        context_alignment * 0.06
    )
    # 硬约束（与 LLM 评分一致）
    if conciseness < 75:
        overall_float = min(overall_float, 84)
    if low_barrier < 75:
        overall_float = min(overall_float, 84)

    return {
        "conciseness": conciseness,
        "low_barrier": low_barrier,
        "non_repetition": non_repetition,
        "safety": safety,
        "style_match": style_match,
        "context_alignment": context_alignment,
        "overall": round(overall_float),
        "score_method": "heuristic",
    }


@app.post("/api/case_lib/score_original_replies")
async def caselib_score_original_replies(case_id: str | None = Query(default=None)):
    """对所有（或指定案例的）对话轮次原销售回复做启发式规则打分（不调用LLM）。
    完成后 actual_sales_score / actual_sales_scores / score_status 被写入 DB，
    案例列表的人工原始分会自动取各轮平均值。"""
    db = SessionLocal()
    try:
        q = db.query(CaseLibraryDialogueTurn)
        if case_id:
            q = q.filter(CaseLibraryDialogueTurn.case_id == case_id)
        turns = q.order_by(CaseLibraryDialogueTurn.case_id, CaseLibraryDialogueTurn.turn_no).all()
        scored = 0
        skipped = 0
        for t in turns:
            sales = (t.sales_text or "").strip()
            if not sales:
                t.score_status = "missing_sales_text"
                skipped += 1
                continue
            scores = _heuristic_score_sales_text(sales, t.customer_text or "")
            t.actual_sales_score = scores["overall"]
            t.actual_sales_scores = scores
            t.score_status = "heuristic_scored"
            scored += 1
        db.commit()
        return {"status": "success", "scored": scored, "skipped": skipped, "total": len(turns)}
    except Exception as e:
        logger.exception("score_original_replies 失败")
        return {"status": "failed", "error": str(e)}
    finally:
        db.close()


def _caselib_rescore_one_result(rr: CaseIterationResult) -> dict:
    """对单个 case_iteration_result 重新打分：基于已存的 step7_reply_styles + step4_knowledge + step1_summary
    重新调用 IntentEngine.score_reply_candidates，把 7 维评分（含 reason）写回 step7_reply_scores，
    并刷新 quality_score / kb1_eval_score / kb2_eval_score。返回 {scored:bool, reason}。"""
    styles = rr.step7_reply_styles if isinstance(rr.step7_reply_styles, list) else (_caselib_load_json(rr.step7_reply_styles) or [])
    if not styles:
        return {"scored": False, "reason": "no_styles"}
    summary_json = _caselib_load_json(rr.step1_summary) or {}
    knowledge = _caselib_load_json(rr.step4_knowledge) or {}
    crm = _caselib_load_json(rr.step2_crm_info) or {}
    tbf = _caselib_load_json(rr.step3_thread_business_fact) or {}
    knowledge_payload = {
        "knowledge_v2": knowledge.get("knowledge_v2") or {},
        "knowledge_external_api": knowledge.get("knowledge_external_api") or {},
        "thread_business_fact": tbf,
    }
    candidates = []
    for s in styles:
        if not isinstance(s, dict):
            continue
        candidates.append({
            "candidate_id": s.get("candidate_id"),
            "model_slot": s.get("model_slot"),
            "model_label": s.get("model_label"),
            "model_display_name": s.get("model_display_name"),
            "knowledge_source": s.get("knowledge_source"),
            "knowledge_source_label": s.get("knowledge_source_label"),
            "style_id": s.get("style_id"),
            "style_title": s.get("style_title"),
            "reply_style": s.get("reply_style"),
            "content": s.get("reply_reference") or s.get("text") or s.get("content") or "",
            "status": s.get("status") or "done",
            "validation": s.get("validation"),
        })
    if not candidates:
        return {"scored": False, "reason": "no_candidates"}
    try:
        scores = IntentEngine.score_reply_candidates(
            summary_json=summary_json,
            knowledge_payload=knowledge_payload,
            crm_context=crm,
            candidates=candidates,
            actual_sales_replies=None,
        )
    except Exception as exc:
        return {"scored": False, "reason": f"score_err:{str(exc)[:100]}"}
    rr.step7_reply_scores = scores
    ac = scores.get("ai_candidates") or []
    scored_ok = False
    if ac:
        best = next((c for c in ac if c.get("overall_score") is not None), None)
        if best is not None:
            rr.quality_score = round(float(best["overall_score"]), 2)
            kb1_pool = [float(c.get("overall_score") or 0) for c in ac if c.get("knowledge_source") == "knowledge_v2" and c.get("overall_score") is not None]
            kb2_pool = [float(c.get("overall_score") or 0) for c in ac if c.get("knowledge_source") == "knowledge_external_api" and c.get("overall_score") is not None]
            rr.kb1_eval_score = round(max(kb1_pool), 2) if kb1_pool else rr.kb1_eval_score
            rr.kb2_eval_score = round(max(kb2_pool), 2) if kb2_pool else rr.kb2_eval_score
            # 打分成功：修正单条状态
            if rr.quality_status in ("real_score_missing", "real_partial"):
                rr.quality_status = "real_success"
            if rr.status == "failed" and rr.quality_status == "real_success":
                rr.status = "success"
            scored_ok = True
    return {"scored": scored_ok, "candidates": len(ac), "score_mode": (scores.get("scored_by") or {}).get("score_mode")}


@app.post("/api/case_lib/iterations/{run_id}/rescore")
async def caselib_rescore_iteration(run_id: str):
    """重打两个评分：
    1. AI 质量分：基于已存 step7_reply_styles + step1_summary + step4_knowledge 重新调用 IntentEngine.score_reply_candidates，
       把 7 维评分（含 reason）写回 step7_reply_scores 并刷新 quality_score / kb1 / kb2。
    2. 人工原始分：执行 backend/_case_lib_import.py 从 sales_scenario_cases_v2.md 重新装载 quality_score_md。
    最后刷新 run 的 avg/min/max。
    """
    import asyncio
    loop = asyncio.get_event_loop()

    def _do_rescore():
        db = SessionLocal()
        try:
            run = db.query(CaseIterationRun).filter(CaseIterationRun.run_id == run_id).first()
            if not run:
                return {"status": "failed", "error": f"run_id 不存在: {run_id}"}
            results = db.query(CaseIterationResult).filter(CaseIterationResult.run_id == run_id).all()
            scored_n = 0; skipped_n = 0; reasons: dict = {}
            for rr in results:
                ret = _caselib_rescore_one_result(rr)
                if ret.get("scored"):
                    scored_n += 1
                else:
                    skipped_n += 1
                    tag = ret.get("reason") or "unknown"
                    reasons[tag] = reasons.get(tag, 0) + 1
            # 刷新 run 汇总（重查最新状态避免缓存）
            db.expire_all()
            results_fresh = db.query(CaseIterationResult).filter(CaseIterationResult.run_id == run_id).all()
            valid_scores = [float(r.quality_score) for r in results_fresh if r.quality_score is not None]
            if valid_scores:
                run.avg_quality_score = round(sum(valid_scores) / len(valid_scores), 2)
                run.min_quality_score = round(min(valid_scores), 2)
                run.max_quality_score = round(max(valid_scores), 2)
            success_n = sum(1 for r in results_fresh if r.status == "success")
            failed_n = sum(1 for r in results_fresh if r.status != "success")
            run.success_cases = success_n
            run.failed_cases = failed_n
            run.status = "success" if failed_n == 0 else ("partial" if success_n > 0 else "failed")
            if valid_scores:
                run.improvement_analysis = _caselib_compose_improvement_analysis(db, run, valid_scores)
            run.updated_at = datetime.utcnow()
            db.commit()

            # 重新装载 quality_score_md
            repo_root = os.path.dirname(os.path.dirname(os.path.abspath(__file__)))
            script = os.path.join(repo_root, "backend", "_case_lib_import.py")
            md_status = "skipped"
            md_stderr = ""
            try:
                proc = subprocess.run(["python", script], cwd=repo_root,
                                      capture_output=True, text=True, timeout=120)
                md_status = "success" if proc.returncode == 0 else f"failed_rc{proc.returncode}"
                md_stderr = proc.stderr[-500:] if proc.stderr else ""
            except Exception as e:
                md_status = f"err:{str(e)[:120]}"

            return {
                "status": "success",
                "run_id": run_id,
                "version_no": run.version_no,
                "ai_rescore": {
                    "scored": scored_n,
                    "skipped": skipped_n,
                    "skip_reasons": reasons,
                },
                "md_reimport": {
                    "status": md_status,
                    "stderr_tail": md_stderr,
                },
                "iteration": _caselib_serialize_run(run),
            }
        finally:
            db.close()

    return await loop.run_in_executor(None, _do_rescore)


# ============== 三 AI 分析与下一步建议：人工填 + LLM-1 汇总 ==============

CASELIB_ANALYSIS_FIELDS = {
    "codex": "analysis_codex",
    "antigravity": "analysis_antigravity",
    "claude_code": "analysis_claude_code",
}


class CaseLibAnalysisUpsertRequest(BaseModel):
    source: str            # codex / antigravity / claude_code
    content: str            # 该 AI 给出的"分析与下一步建议"全文（markdown 可）


def _caselib_compose_three_ai_summary(run: CaseIterationRun) -> tuple[str, str]:
    """三个 AI 字段都非空时调用：交给 LLM-1 生成"分析与下一步建议(汇总)"，返回 (summary_text, status)。
    LLM-1 未配置或调用失败时回退为带 ## 分段标题的纯拼接，并在状态里说明。"""
    codex = (run.analysis_codex or "").strip()
    anti = (run.analysis_antigravity or "").strip()
    cc = (run.analysis_claude_code or "").strip()
    fallback = (
        f"# v{run.version_no} 三 AI 分析与下一步建议汇总（拼接版）\n\n"
        f"## Codex\n{codex or '_未填写_'}\n\n"
        f"## Antigravity\n{anti or '_未填写_'}\n\n"
        f"## Claude Code\n{cc or '_未填写_'}\n"
    )
    llm1_cfg = _runtime_llm_values("LLM1")
    if not _runtime_llm_configured(llm1_cfg):
        return fallback + "\n> LLM-1 未配置，本汇总仅做拼接，无 AI 综合。", "fallback_concat_no_llm1"
    if not (codex and anti and cc):
        return fallback + "\n> 三个 AI 内容未齐，本汇总仅做拼接。", "fallback_concat_incomplete"
    prompt = (
        "你是迭代评测复盘助手。下面是同一轮案例库迭代评测后，三个独立 AI 编码工具各自给出的"
        "「分析与下一步建议」。请仔细对比并产出一份综合复盘，**严格按以下 4 个段落输出 markdown，每段都要有内容**：\n"
        "## 1. 三方共识点（多个 AI 都明确指出的同类问题/方向）\n"
        "## 2. 三方分歧点（结论不同甚至冲突的地方，列出每个 AI 的观点）\n"
        "## 3. 优先级排序（按重要度从高到低，列 3~5 个最该先做的事项；每条注明源自哪个/哪些 AI）\n"
        "## 4. 下一轮具体执行清单（可直接 copy 到 change_summary 的可执行步骤）\n\n"
        "约束：\n"
        "- 不允许编造未在原文出现的事项；\n"
        "- 引用 AI 观点时用「Codex:」「Antigravity:」「Claude Code:」开头；\n"
        "- 用词精简，避免空话。\n\n"
        f"=== Codex ===\n{codex}\n\n=== Antigravity ===\n{anti}\n\n=== Claude Code ===\n{cc}\n"
    )
    try:
        request_spec = IntentEngine.build_llm1_request(
            [{"content": prompt, "sender_type": "system"}],
            user_id=f"caselib_run_{run.run_id}",
            api_url=llm1_cfg["api_url"],
            api_key=llm1_cfg["api_key"],
            model=llm1_cfg["model"],
            timeout_seconds=llm1_cfg["timeout_seconds"],
            label="LLM1_CASELIB_SUMMARY",
        )
        bundle = IntentEngine.run_llm1_request(request_spec)
        summary_payload = bundle.get("summary") or {}
        # 优先取裸文本字段；若 LLM 返回结构化 dict 则 json 序列化兜底
        text_out = ""
        for key in ("text", "content", "summary", "answer"):
            v = summary_payload.get(key) if isinstance(summary_payload, dict) else None
            if isinstance(v, str) and v.strip():
                text_out = v.strip()
                break
        if not text_out and isinstance(summary_payload, dict):
            text_out = json.dumps(summary_payload, ensure_ascii=False, indent=2)
        if not text_out:
            return fallback + "\n> LLM-1 调用成功但返回空文本，回退拼接。", "fallback_llm1_empty"
        header = f"# v{run.version_no} 三 AI 分析与下一步建议汇总（LLM-1 综合）\n\n"
        return header + text_out, "llm1_summarized"
    except Exception as exc:
        logger.error("LLM-1 汇总三AI分析失败: %s", exc)
        return fallback + f"\n> LLM-1 调用失败：{str(exc)[:200]}", "fallback_llm1_error"


@app.put("/api/case_lib/iterations/{run_id}/analysis")
async def caselib_upsert_iteration_analysis(run_id: str, body: CaseLibAnalysisUpsertRequest):
    """提交某个 AI 工具对本轮迭代的分析。3 个都填完后自动触发 LLM-1 汇总。"""
    src = (body.source or "").strip().lower()
    col = CASELIB_ANALYSIS_FIELDS.get(src)
    if not col:
        return {"status": "failed", "error": f"unknown source: {src}; 必须是 codex / antigravity / claude_code"}
    db = SessionLocal()
    try:
        run = db.query(CaseIterationRun).filter(CaseIterationRun.run_id == run_id).first()
        if not run:
            return {"status": "failed", "error": f"run_id 不存在: {run_id}"}
        setattr(run, col, (body.content or "").strip())
        # 检查另外两个是否都已填
        filled = [bool((getattr(run, c) or "").strip()) for c in CASELIB_ANALYSIS_FIELDS.values()]
        summary_status = "skipped_incomplete"
        if all(filled):
            run.analysis_summary, summary_status = _caselib_compose_three_ai_summary(run)
        run.updated_at = datetime.utcnow()
        db.commit()
        db.refresh(run)
        return {
            "status": "success",
            "source": src,
            "summary_status": summary_status,
            "filled_sources": [k for k, c in CASELIB_ANALYSIS_FIELDS.items() if (getattr(run, c) or "").strip()],
            "iteration": _caselib_serialize_run(run),
        }
    finally:
        db.close()


@app.post("/api/case_lib/iterations/{run_id}/analysis/regenerate_summary")
async def caselib_regenerate_iteration_summary(run_id: str):
    """手动重新触发"三 AI 分析汇总"——例如某个 AI 内容改过后想重跑。"""
    db = SessionLocal()
    try:
        run = db.query(CaseIterationRun).filter(CaseIterationRun.run_id == run_id).first()
        if not run:
            return {"status": "failed", "error": f"run_id 不存在: {run_id}"}
        run.analysis_summary, summary_status = _caselib_compose_three_ai_summary(run)
        run.updated_at = datetime.utcnow()
        db.commit()
        db.refresh(run)
        return {
            "status": "success",
            "summary_status": summary_status,
            "iteration": _caselib_serialize_run(run),
        }
    finally:
        db.close()
